__register("Core.Accessibility", function(require)
--!strict
--[[
	AetherUI • Core/Accessibility
	Reduced motion detection, font scaling, and focus-visible support.
]]

local GuiService = game:GetService("GuiService")

local Fusion = require("Core.Fusion")
local Value = Fusion.Value

local Accessibility = {}

--- Reactive: true when the platform requests reduced motion.
Accessibility.ReducedMotion = Value(false)

--- Reactive: multiplier applied to all text sizes (1 = default).
Accessibility.FontScale = Value(1)

--- Reactive: when true, focus rings are always rendered (keyboard navigation mode).
Accessibility.FocusVisible = Value(false)

local ok, reduced = pcall(function()
	return (GuiService :: any).ReducedMotionEnabled
end)
if ok and reduced == true then
	Accessibility.ReducedMotion:set(true)
end

function Accessibility.SetFontScale(scale: number)
	Accessibility.FontScale:set(math.clamp(scale, 0.75, 2))
end

function Accessibility.SetReducedMotion(enabled: boolean)
	Accessibility.ReducedMotion:set(enabled)
end

function Accessibility.SetFocusVisible(enabled: boolean)
	Accessibility.FocusVisible:set(enabled)
end

--- Scales a base text size by the current font scale (non-reactive read).
function Accessibility.ScaleText(size: number): number
	return math.round(size * Accessibility.FontScale:get())
end

return Accessibility

end)

__register("Core.Animation", function(require)
--!strict
--[[
	AetherUI • Core/Animation
	Motion design tokens + helpers.

	• `Presets`  — TweenInfo presets for Fusion.Tween wrapping
	• `Springs`  — { Speed, Damping } configs for Fusion.Spring
	• `Stagger`  — run a callback across a list with per-item delay
	• `Enter/Exit` — imperative transitions for overlays (toasts, modals)

	All imperative helpers respect Accessibility.ReducedMotion.
]]

local TweenService = game:GetService("TweenService")
local GuiService = game:GetService("GuiService")

local Animation = {}

-- // TweenInfo presets ------------------------------------------------------

Animation.Presets = {
	Instant = TweenInfo.new(0.05, Enum.EasingStyle.Linear),
	Fast = TweenInfo.new(0.12, Enum.EasingStyle.Quad, Enum.EasingDirection.Out),
	Normal = TweenInfo.new(0.2, Enum.EasingStyle.Quart, Enum.EasingDirection.Out),
	Smooth = TweenInfo.new(0.32, Enum.EasingStyle.Quint, Enum.EasingDirection.Out),
	Slow = TweenInfo.new(0.5, Enum.EasingStyle.Quint, Enum.EasingDirection.Out),
	Bounce = TweenInfo.new(0.45, Enum.EasingStyle.Back, Enum.EasingDirection.Out),
	Expressive = TweenInfo.new(0.6, Enum.EasingStyle.Exponential, Enum.EasingDirection.Out),
}

-- // Spring configs (for Fusion.Spring(state, speed, damping)) ---------------

Animation.Springs = {
	Stiff = { Speed = 40, Damping = 1 },
	Snappy = { Speed = 28, Damping = 0.95 },
	Gentle = { Speed = 18, Damping = 1 },
	Wobbly = { Speed = 20, Damping = 0.55 },
	Slow = { Speed = 10, Damping = 1 },
}

-- // Reduced motion -----------------------------------------------------------

function Animation.ReducedMotion(): boolean
	local ok, reduced = pcall(function()
		return (GuiService :: any).ReducedMotionEnabled
	end)
	return ok and reduced == true
end

local function info(preset: TweenInfo): TweenInfo
	if Animation.ReducedMotion() then
		return TweenInfo.new(0.01, Enum.EasingStyle.Linear)
	end
	return preset
end

-- // Imperative helpers -------------------------------------------------------

--- Tweens properties on an instance and returns the Tween (already playing).
function Animation.Tween(instance: Instance, properties: { [string]: any }, preset: TweenInfo?): Tween
	local tween = TweenService:Create(instance, info(preset or Animation.Presets.Normal), properties)
	tween:Play()
	return tween
end

--- Fades a GuiObject (and its descendants' transparency-ish props) in from offset.
function Animation.Enter(gui: GuiObject, options: { Offset: UDim2?, From: number?, Preset: TweenInfo? }?)
	local opts = options or {}
	local targetPosition = gui.Position
	local offset = opts.Offset or UDim2.fromOffset(0, 8)

	gui.Position = targetPosition - offset
	if gui:IsA("Frame") or gui:IsA("TextButton") or gui:IsA("ImageButton") or gui:IsA("TextLabel") then
		local target = (gui :: any).BackgroundTransparency
		;(gui :: any).BackgroundTransparency = opts.From or 1
		Animation.Tween(gui, { Position = targetPosition, BackgroundTransparency = target }, opts.Preset or Animation.Presets.Smooth)
	else
		Animation.Tween(gui, { Position = targetPosition }, opts.Preset or Animation.Presets.Smooth)
	end
end

--- Fades a GuiObject out, then destroys (or calls onDone).
function Animation.Exit(gui: GuiObject, options: { Offset: UDim2?, Preset: TweenInfo?, OnDone: (() -> ())? }?)
	local opts = options or {}
	local offset = opts.Offset or UDim2.fromOffset(0, 8)
	local tween = Animation.Tween(gui, {
		Position = gui.Position + offset,
		BackgroundTransparency = 1,
	}, opts.Preset or Animation.Presets.Fast)
	tween.Completed:Once(function()
		if opts.OnDone then
			opts.OnDone()
		else
			gui:Destroy()
		end
	end)
end

--- Runs `fn(item, index)` for each item, spaced by `delay` seconds (default 0.04).
function Animation.Stagger<T>(items: { T }, fn: (T, number) -> (), delayPerItem: number?)
	local step = if Animation.ReducedMotion() then 0 else (delayPerItem or 0.04)
	for index, item in items do
		task.delay(step * (index - 1), fn, item, index)
	end
end

--- Pulse scale effect (micro-interaction for presses).
function Animation.Pulse(gui: GuiObject, scaleTo: number?)
	local uiScale = gui:FindFirstChildOfClass("UIScale")
	if not uiScale then
		uiScale = Instance.new("UIScale")
		assert(uiScale)
		uiScale.Parent = gui
	end
	assert(uiScale)
	uiScale.Scale = scaleTo or 0.965
	Animation.Tween(uiScale, { Scale = 1 }, Animation.Presets.Bounce)
end

return Animation

end)

__register("Core.Fusion", function(require)
-- Vendored Fusion 0.2 (github.com/dphfox/Fusion, MIT) — bundled below.
local Fusion = require("Fusion")

local hasPeek = pcall(function()
	return Fusion.peek
end)
if hasPeek then
	return Fusion
end

local function peek(target)
	if typeof(target) == "table" and typeof(target.get) == "function" then
		return target:get(false)
	end
	return target
end

-- rawget finds `peek` on the proxy first; everything else falls through
-- to the real Fusion exports (whose own strict guard still applies).
return setmetatable({ peek = peek }, { __index = Fusion })

end)

__register("Core.Icons", function(require)
--!strict
--[[
	AetherUI • Core/Icons
	Lucide icon integration with caching + pluggable icon packs.

	AetherUI ships with support for the community `lucide-roblox` spritesheet
	format (https://github.com/latte-soft/lucide-roblox). Load the generated
	icon data module and register it once:

		local lucideData = loadstring(game:HttpGet("<lucide-pack-url>"))()
		AetherUI.Icons.LoadPack(lucideData)

	After that, every component accepts icons by name:

		AetherUI.Button({ Text = "Save", Icon = "save" })

	You can also register single icons (your own uploads):

		AetherUI.Icons.Register("brand-logo", { Id = "rbxassetid://123456" })

	If an icon is missing, components render a subtle placeholder glyph
	instead of a broken image — the UI never looks broken.
]]

type IconData = {
	Id: string,
	ImageRectOffset: Vector2?,
	ImageRectSize: Vector2?,
}

local Icons = {}

local registry: { [string]: IconData } = {}
local resolveCache: { [string]: IconData | false } = {}
local aliases: { [string]: string } = {
	["x"] = "x",
	["close"] = "x",
	["chevron-down"] = "chevron-down",
	["chevron-up"] = "chevron-up",
	["chevron-left"] = "chevron-left",
	["chevron-right"] = "chevron-right",
	["check"] = "check",
	["search"] = "search",
	["settings"] = "settings",
}

--- Registers a single icon by name.
function Icons.Register(name: string, data: IconData)
	registry[name:lower()] = data
	resolveCache[name:lower()] = nil
end

--- Adds an alias (e.g. Icons.Alias("cog", "settings")).
function Icons.Alias(alias: string, target: string)
	aliases[alias:lower()] = target:lower()
end

--[[
	Loads a lucide-roblox style pack. Supported shapes:

	1. { IconData = { [name] = { Url|Id, ImageRectOffset, ImageRectSize } } }
	2. { [name] = { Id = ..., ImageRectOffset = ..., ImageRectSize = ... } }
	3. { GetAsset = function(name, size?) -> { Url, ImageRectOffset, ImageRectSize } }
]]
function Icons.LoadPack(pack: any)
	if type(pack) ~= "table" then
		warn("[AetherUI] Icons.LoadPack expects a table")
		return
	end
	if type(pack.GetAsset) == "function" then
		Icons._provider = pack
		table.clear(resolveCache)
		return
	end
	local source = pack.IconData or pack
	for name, data in source :: { [string]: any } do
		if type(data) == "table" then
			Icons.Register(name, {
				Id = data.Id or data.Url or data.Image or "",
				ImageRectOffset = data.ImageRectOffset,
				ImageRectSize = data.ImageRectSize,
			})
		end
	end
end

Icons._provider = nil :: any

--- Resolves an icon by name. Returns nil when unknown (components then show a fallback).
function Icons.Get(name: string?): IconData?
	if name == nil or name == "" then
		return nil
	end
	local key = name:lower()
	key = aliases[key] or key

	local cached = resolveCache[key]
	if cached ~= nil then
		return if cached == false then nil else cached :: IconData
	end

	local data: IconData? = registry[key]

	if data == nil and Icons._provider then
		local ok, asset = pcall(function()
			return Icons._provider.GetAsset(key, 48)
		end)
		if ok and type(asset) == "table" then
			data = {
				Id = asset.Url or asset.Id or "",
				ImageRectOffset = asset.ImageRectOffset,
				ImageRectSize = asset.ImageRectSize,
			}
		end
	end

	resolveCache[key] = data or false
	return data
end

--- True when the icon can be rendered as an image.
function Icons.Has(name: string?): boolean
	return Icons.Get(name) ~= nil
end

--- Lists all directly registered icon names (excludes provider-backed icons).
function Icons.List(): { string }
	local names = {}
	for name in registry do
		table.insert(names, name)
	end
	table.sort(names)
	return names
end

--[[
	Renders an icon as an ImageLabel. Used by every component that accepts
	an `Icon` prop.

	`name` may be a plain string OR a Fusion state object (Value/Computed)
	for reactive icon swapping. `props` supports: Name, Size, Position,
	AnchorPoint, LayoutOrder, ZIndex, Rotation, Visible, Color (-> ImageColor3),
	Transparency (-> ImageTransparency) — each either static or reactive.

	Unknown icons render an empty (invisible) label so the UI never breaks.
]]
function Icons.render(name: any, props: any): Instance
	local Fusion = require("Core.Fusion") :: any
	local New = Fusion.New
	local Computed = Fusion.Computed

	props = props or {}

	local isReactive = typeof(name) == "table" and typeof(name.get) == "function"

	local image: any
	local rectOffset: any
	local rectSize: any

	if isReactive then
		image = Computed(function()
			local data = Icons.Get(name:get())
			return if data then data.Id else ""
		end)
		rectOffset = Computed(function()
			local data = Icons.Get(name:get())
			return if data and data.ImageRectOffset then data.ImageRectOffset else Vector2.zero
		end)
		rectSize = Computed(function()
			local data = Icons.Get(name:get())
			return if data and data.ImageRectSize then data.ImageRectSize else Vector2.zero
		end)
	else
		local data = Icons.Get(name)
		image = if data then data.Id else ""
		rectOffset = if data and data.ImageRectOffset then data.ImageRectOffset else Vector2.zero
		rectSize = if data and data.ImageRectSize then data.ImageRectSize else Vector2.zero
	end

	return New("ImageLabel")({
		Name = props.Name or "Icon",
		Size = props.Size or UDim2.fromOffset(16, 16),
		Position = props.Position,
		AnchorPoint = props.AnchorPoint,
		LayoutOrder = props.LayoutOrder,
		ZIndex = props.ZIndex,
		Rotation = props.Rotation,
		Visible = props.Visible,
		BackgroundTransparency = 1,
		Image = image,
		ImageRectOffset = rectOffset,
		ImageRectSize = rectSize,
		ImageColor3 = props.Color,
		ImageTransparency = props.Transparency,
		ScaleType = Enum.ScaleType.Fit,
	})
end

return Icons

end)

__register("Core.Keybinds", function(require)
--!strict
--[[
	AetherUI • Core/Keybinds
	Global + per-component hotkey registry.

		local bind = Keybinds.Register("toggle-menu", {
			Key = Enum.KeyCode.K,
			Modifiers = { "Ctrl" },
			Description = "Toggle the menu",
			Callback = function() window:Toggle() end,
		})
		bind:Disconnect()

	Capture mode (used by the KeybindInput component):

		Keybinds.BeginCapture(function(keyCode, modifiers) ... end)
]]

local UserInputService = game:GetService("UserInputService")

local Signal = require("Core.Signal")
local Types = require("Types")

type KeybindSpec = Types.KeybindSpec

type KeybindHandle = {
	Id: string,
	Spec: KeybindSpec,
	SetEnabled: (self: KeybindHandle, enabled: boolean) -> (),
	Disconnect: (self: KeybindHandle) -> (),
}

--- Lightweight bind descriptor used by KeybindInput and transient binds.
type Bind = {
	Key: Enum.KeyCode,
	Ctrl: boolean?,
	Shift: boolean?,
	Alt: boolean?,
}

local Keybinds = {}

Keybinds.Enabled = true
Keybinds.Triggered = Signal.new() :: any

local registry: { [string]: KeybindHandle } = {}
local captureCallback: ((Enum.KeyCode, { string }) -> ())? = nil

local MODIFIER_KEYS = {
	[Enum.KeyCode.LeftControl] = "Ctrl",
	[Enum.KeyCode.RightControl] = "Ctrl",
	[Enum.KeyCode.LeftShift] = "Shift",
	[Enum.KeyCode.RightShift] = "Shift",
	[Enum.KeyCode.LeftAlt] = "Alt",
	[Enum.KeyCode.RightAlt] = "Alt",
}

local function activeModifiers(): { [string]: boolean }
	return {
		Ctrl = UserInputService:IsKeyDown(Enum.KeyCode.LeftControl)
			or UserInputService:IsKeyDown(Enum.KeyCode.RightControl),
		Shift = UserInputService:IsKeyDown(Enum.KeyCode.LeftShift)
			or UserInputService:IsKeyDown(Enum.KeyCode.RightShift),
		Alt = UserInputService:IsKeyDown(Enum.KeyCode.LeftAlt)
			or UserInputService:IsKeyDown(Enum.KeyCode.RightAlt),
	}
end

local function modifiersMatch(required: { string }?, active: { [string]: boolean }): boolean
	local requiredSet = { Ctrl = false, Shift = false, Alt = false }
	for _, mod in required or {} do
		requiredSet[mod] = true
	end
	return requiredSet.Ctrl == active.Ctrl
		and requiredSet.Shift == active.Shift
		and requiredSet.Alt == active.Alt
end

--- Registers a keybind. Returns a handle with :Disconnect() and :SetEnabled().
function Keybinds.Register(id: string, spec: KeybindSpec): KeybindHandle
	local handle = {} :: KeybindHandle
	handle.Id = id
	handle.Spec = spec
	if spec.Enabled == nil then
		spec.Enabled = true
	end

	function handle.SetEnabled(_, enabled: boolean)
		spec.Enabled = enabled
	end

	function handle.Disconnect()
		registry[id] = nil
	end

	registry[id] = handle
	return handle
end

function Keybinds.Unregister(id: string)
	registry[id] = nil
end

--- Changes the key (and optionally modifiers) of an existing bind in place.
function Keybinds.Rebind(id: string, key: Enum.KeyCode, modifiers: { string }?)
	local handle = registry[id]
	if handle then
		handle.Spec.Key = key
		if modifiers ~= nil then
			handle.Spec.Modifiers = modifiers
		end
	end
end

function Keybinds.GetAll(): { [string]: KeybindSpec }
	local out = {}
	for id, handle in registry do
		out[id] = handle.Spec
	end
	return out
end

function Keybinds.SetEnabled(enabled: boolean)
	Keybinds.Enabled = enabled
end

--- Enters capture mode: the next key press is reported and swallowed. Escape cancels.
function Keybinds.BeginCapture(callback: (Enum.KeyCode?, { string }) -> ())
	captureCallback = callback :: any
end

function Keybinds.CancelCapture()
	captureCallback = nil
end

--- Formats a keybind for display, e.g. "Ctrl + Shift + K".
function Keybinds.Format(key: Enum.KeyCode?, modifiers: { string }?): string
	local parts = {}
	for _, mod in modifiers or {} do
		table.insert(parts, mod)
	end
	if key then
		table.insert(parts, key.Name)
	end
	return if #parts > 0 then table.concat(parts, " + ") else "None"
end

--- Formats a Bind descriptor for display, e.g. "Ctrl + K".
function Keybinds.format(bind: Bind): string
	local mods = {}
	if bind.Ctrl then
		table.insert(mods, "Ctrl")
	end
	if bind.Shift then
		table.insert(mods, "Shift")
	end
	if bind.Alt then
		table.insert(mods, "Alt")
	end
	return Keybinds.Format(bind.Key, mods)
end

--- Binds a single key until unbound. Returns an unbind function.
--- Used internally for transient bindings like Escape-to-close.
local transientCounter = 0
function Keybinds.bindTransient(key: Enum.KeyCode, callback: () -> ()): () -> ()
	transientCounter += 1
	local id = "__transient_" .. transientCounter
	Keybinds.Register(id, {
		Key = key,
		Callback = callback,
	})
	return function()
		Keybinds.Unregister(id)
	end
end

-- Input handling ------------------------------------------------------------

UserInputService.InputBegan:Connect(function(input, gameProcessed)
	if input.UserInputType ~= Enum.UserInputType.Keyboard then
		return
	end

	-- Capture mode takes priority over everything
	if captureCallback then
		if MODIFIER_KEYS[input.KeyCode] then
			return -- wait for a non-modifier key
		end
		local callback = captureCallback
		captureCallback = nil
		local mods = {}
		local active = activeModifiers()
		for _, name in { "Ctrl", "Shift", "Alt" } do
			if active[name] then
				table.insert(mods, name)
			end
		end
		if input.KeyCode == Enum.KeyCode.Escape then
			callback(nil, {})
		else
			callback(input.KeyCode, mods)
		end
		return
	end

	if not Keybinds.Enabled or gameProcessed then
		return
	end

	local active = activeModifiers()
	for id, handle in registry do
		local spec = handle.Spec
		if spec.Enabled ~= false and spec.Key == input.KeyCode and modifiersMatch(spec.Modifiers, active) then
			Keybinds.Triggered:Fire(id)
			task.spawn(spec.Callback)
		end
	end
end)

--- Removes every registered keybind. Used by AetherUI.Destroy() on teardown.
function Keybinds.DisconnectAll()
	captureCallback = nil
	table.clear(registry)
end

return Keybinds

end)

__register("Core.Maid", function(require)
--!strict
--[[
	AetherUI • Core/Maid
	Tracks connections, instances, threads and callbacks for deterministic cleanup.
]]

type Task = RBXScriptConnection | Instance | thread | () -> () | { Disconnect: (any) -> () } | { Destroy: (any) -> () }

type Maid = {
	Add: <T>(self: Maid, task: T & Task) -> T,
	Remove: (self: Maid, task: Task) -> (),
	Clean: (self: Maid) -> (),
	Destroy: (self: Maid) -> (),
}

local Maid = {}
Maid.__index = Maid

function Maid.new(): Maid
	return (setmetatable({ _tasks = {} :: { Task } }, Maid) :: any) :: Maid
end

local function cleanTask(item: Task)
	local itemType = typeof(item)
	if itemType == "RBXScriptConnection" then
		(item :: RBXScriptConnection):Disconnect()
	elseif itemType == "Instance" then
		(item :: Instance):Destroy()
	elseif itemType == "thread" then
		pcall(task.cancel, item :: thread)
	elseif itemType == "function" then
		(item :: () -> ())()
	elseif itemType == "table" then
		local tbl = item :: any
		if type(tbl.Disconnect) == "function" then
			tbl:Disconnect()
		elseif type(tbl.Destroy) == "function" then
			tbl:Destroy()
		elseif type(tbl.Clean) == "function" then
			tbl:Clean()
		end
	end
end

function Maid:Add(item)
	table.insert(self._tasks, item)
	return item
end

function Maid:Remove(item)
	local index = table.find(self._tasks, item)
	if index then
		table.remove(self._tasks, index)
	end
end

function Maid:Clean()
	local tasks = self._tasks
	self._tasks = {}
	for i = #tasks, 1, -1 do
		cleanTask(tasks[i])
	end
end

function Maid:Destroy()
	self:Clean()
end

return Maid

end)

__register("Core.Overlay", function(require)
--!strict
--[=[
	AetherUI · Overlay
	Shared ScreenGui layer for modals, toasts, tooltips, menus and palettes.
	Guarantees a single top-most root with sensible DisplayOrder.
]=]

local Overlay = {}

local root: ScreenGui? = nil

--- Standalone runtime: the UI always lives in CoreGui so it persists across
--- character respawns and is fully independent of the LocalPlayer's PlayerGui.
--- Prefers the executor-provided hidden UI container (gethui) when available.
local function getParent(): Instance
	local getHui = (getfenv() :: any).gethui
	if typeof(getHui) == "function" then
		local ok, hui = pcall(getHui)
		if ok and typeof(hui) == "Instance" then
			return hui
		end
	end
	return game:GetService("CoreGui")
end

function Overlay.getRoot(): ScreenGui
	if root and root.Parent then
		return root
	end
	local gui = Instance.new("ScreenGui")
	gui.Name = "AetherUI_Overlay"
	gui.ResetOnSpawn = false
	gui.IgnoreGuiInset = true
	gui.DisplayOrder = 1000
	gui.ZIndexBehavior = Enum.ZIndexBehavior.Sibling
	gui.Parent = getParent()
	root = gui
	return gui
end

--[=[ Layer helpers — each subsystem gets its own folder-frame ]=]
function Overlay.getLayer(name: string, zIndex: number): Frame
	local gui = Overlay.getRoot()
	local existing = gui:FindFirstChild(name)
	if existing and existing:IsA("Frame") then
		return existing
	end
	local layer = Instance.new("Frame")
	layer.Name = name
	layer.Size = UDim2.fromScale(1, 1)
	layer.BackgroundTransparency = 1
	layer.ZIndex = zIndex
	layer.Parent = gui
	return layer
end

function Overlay.destroy()
	if root then
		root:Destroy()
		root = nil
	end
end

return Overlay

end)

__register("Core.Responsive", function(require)
--!strict
--[[
	AetherUI • Core/Responsive
	Viewport-aware scaling. Attach a managed UIScale to any root gui:

		Responsive.Attach(myScreenGuiRootFrame)          -- auto scale
		Responsive.SetUserScale(1.15)                    -- user preference on top
]]

local Fusion = require("Core.Fusion")
local Maid = require("Core.Maid")

local Value = Fusion.Value

local Responsive = {}

--- Reference resolution the UI was designed against.
Responsive.BaseResolution = Vector2.new(1920, 1080)

--- Reactive user scale preference multiplied on top of auto scale.
Responsive.UserScale = Value(1)

--- Reactive auto scale derived from viewport size.
Responsive.AutoScale = Value(1)

Responsive.MinScale = 0.65
Responsive.MaxScale = 1.5

local function computeScale(viewport: Vector2): number
	if viewport.X <= 0 or viewport.Y <= 0 then
		return 1
	end
	local scale = math.min(viewport.X / Responsive.BaseResolution.X, viewport.Y / Responsive.BaseResolution.Y)
	-- Never scale up past 1 automatically; blend towards 1 to avoid tiny UI on small screens
	scale = 0.5 + scale * 0.5
	return math.clamp(scale, Responsive.MinScale, Responsive.MaxScale)
end

function Responsive.SetUserScale(scale: number)
	Responsive.UserScale:set(math.clamp(scale, 0.5, 2))
end

--- Attaches a managed UIScale to `gui` that tracks viewport size and user scale.
--- Returns a cleanup function.
function Responsive.Attach(gui: GuiObject): () -> ()
	local maid = Maid.new()
	local uiScale = Instance.new("UIScale")
	uiScale.Parent = gui
	maid:Add(uiScale)

	local camera = workspace.CurrentCamera

	local function update()
		if camera then
			Responsive.AutoScale:set(computeScale(camera.ViewportSize))
		end
		uiScale.Scale = Responsive.AutoScale:get() * Responsive.UserScale:get()
	end

	if camera then
		maid:Add(camera:GetPropertyChangedSignal("ViewportSize"):Connect(update))
	end
	maid:Add(Fusion.Observer(Responsive.UserScale):onChange(update))
	maid:Add(Fusion.Observer(Responsive.AutoScale):onChange(update))
	update()

	return function()
		maid:Clean()
	end
end

return Responsive

end)

__register("Core.Signal", function(require)
--!strict
--[[
	AetherUI • Core/Signal
	Lightweight, allocation-friendly signal implementation.
]]

type Connection = {
	Disconnect: (self: Connection) -> (),
	Connected: boolean,
}

type Signal<T...> = {
	Connect: (self: Signal<T...>, fn: (T...) -> ()) -> Connection,
	Once: (self: Signal<T...>, fn: (T...) -> ()) -> Connection,
	Fire: (self: Signal<T...>, T...) -> (),
	Wait: (self: Signal<T...>) -> T...,
	Destroy: (self: Signal<T...>) -> (),
}

local Signal = {}
Signal.__index = Signal

function Signal.new<T...>(): Signal<T...>
	local self = setmetatable({
		_handlers = {} :: { [number]: (T...) -> () },
	}, Signal)
	return (self :: any) :: Signal<T...>
end

function Signal:Connect(fn)
	local handlers = self._handlers
	table.insert(handlers, fn)

	local connection = {
		Connected = true,
	}
	function connection.Disconnect(conn)
		if not conn.Connected then
			return
		end
		conn.Connected = false
		local index = table.find(handlers, fn)
		if index then
			table.remove(handlers, index)
		end
	end
	return connection
end

function Signal:Once(fn)
	local connection
	connection = self:Connect(function(...)
		connection:Disconnect()
		fn(...)
	end)
	return connection
end

function Signal:Fire(...)
	for _, fn in table.clone(self._handlers) do
		task.spawn(fn, ...)
	end
end

function Signal:Wait()
	local thread = coroutine.running()
	local connection
	connection = self:Connect(function(...)
		connection:Disconnect()
		task.spawn(thread, ...)
	end)
	return coroutine.yield()
end

function Signal:Destroy()
	table.clear(self._handlers)
end

return Signal

end)

__register("Core.Sound", function(require)
--!strict
--[[
	AetherUI • Core/Sound
	Optional audio feedback layer. Disabled by default — call Sound.SetEnabled(true).

	The default asset ids are intentionally generic placeholders; override them
	with your own uploads via Sound.Configure for a fully branded feel:

		Sound.Configure("Click", { Id = "rbxassetid://YOUR_ID", Volume = 0.35 })
]]

local SoundService = game:GetService("SoundService")

local Sound = {}

Sound.Enabled = false
Sound.MasterVolume = 0.5

type SoundDef = { Id: string, Volume: number, PlaybackSpeed: number? }

local registry: { [string]: SoundDef } = {
	Hover = { Id = "rbxassetid://10066936758", Volume = 0.12, PlaybackSpeed = 1.15 },
	Click = { Id = "rbxassetid://10066931761", Volume = 0.3 },
	Toggle = { Id = "rbxassetid://10066931761", Volume = 0.25, PlaybackSpeed = 1.2 },
	Success = { Id = "rbxassetid://10066947742", Volume = 0.35 },
	Error = { Id = "rbxassetid://10066947742", Volume = 0.35, PlaybackSpeed = 0.7 },
	Open = { Id = "rbxassetid://10066936758", Volume = 0.2 },
	Close = { Id = "rbxassetid://10066936758", Volume = 0.2, PlaybackSpeed = 0.85 },
}

local cache: { [string]: Sound } = {}

local function getInstance(name: string): Sound?
	local def = registry[name]
	if not def then
		return nil
	end
	local cached = cache[name]
	if cached then
		return cached
	end
	local sound = Instance.new("Sound")
	sound.Name = "AetherUI_" .. name
	sound.SoundId = def.Id
	sound.Volume = def.Volume
	sound.PlaybackSpeed = def.PlaybackSpeed or 1
	sound.Parent = SoundService
	cache[name] = sound
	return sound
end

function Sound.SetEnabled(enabled: boolean)
	Sound.Enabled = enabled
end

function Sound.SetMasterVolume(volume: number)
	Sound.MasterVolume = math.clamp(volume, 0, 1)
end

--- Registers or overrides a sound (name: Hover | Click | Toggle | Success | Error | Open | Close | custom).
function Sound.Configure(name: string, def: SoundDef)
	registry[name] = def
	local cached = cache[name]
	if cached then
		cached:Destroy()
		cache[name] = nil
	end
end

--- Plays a named sound if the sound system is enabled.
function Sound.Play(name: string)
	if not Sound.Enabled then
		return
	end
	local sound = getInstance(name)
	if sound then
		local def = registry[name]
		sound.Volume = def.Volume * Sound.MasterVolume
		sound:Play()
	end
end

function Sound.Destroy()
	for _, sound in cache do
		sound:Destroy()
	end
	table.clear(cache)
end

-- Lowercase alias used internally by components.
Sound.play = Sound.Play

return Sound

end)

__register("Core.Theme", function(require)
--!strict
--[[
	AetherUI • Core/Theme
	Reactive theme manager built on Fusion Values.

	Every token is a Fusion Value, so switching themes live-updates the whole
	UI (and animates anywhere a token is wrapped in Tween/Spring).

	Usage:
		Theme.Apply("Light")
		Theme.Register("Dracula", { Colors = { Primary = Color3.fromRGB(...) } }, "Dark")
		local json = Theme.Save()      -- serialize custom themes
		Theme.Load(json)               -- restore them later
]]

local HttpService = game:GetService("HttpService")

local Fusion = require("Core.Fusion")
local Themes = require("Core.Themes")
local Types = require("Types")
local Utils = require("Core.Utils")
local Signal = require("Core.Signal")

local Value = Fusion.Value

type ThemeSpec = Types.ThemeSpec

local Theme = {}

Theme.Registered = {} :: { [string]: ThemeSpec }
for name, spec in Themes :: { [string]: ThemeSpec } do
	Theme.Registered[name] = spec
end

--- Flattens a theme spec into a single token table:
--- all Colors at the top level, plus RadiusSm/RadiusMd/... numbers.
local function flatten(spec: ThemeSpec): { [string]: any }
	local flat: { [string]: any } = {}
	for key, color in spec.Colors :: any do
		flat[key] = color
	end
	for key, value in spec.Radius :: any do
		flat["Radius" .. key] = value
	end
	flat.StrokeTransparency = spec.StrokeTransparency
	flat.GlassTransparency = spec.GlassTransparency
	flat.ShadowTransparency = spec.ShadowTransparency
	flat.Mode = spec.Mode or "Dark"
	return flat
end

--- Name of the active theme ("Dark" by default).
Theme.ActiveName = Value("Dark")
--- Reactive flat token table of the active theme. Components read
--- `theme:get().Primary`, `theme:get().RadiusMd`, etc. inside Computeds so
--- switching themes live-updates everything.
Theme.Current = Value(flatten(Theme.Registered.Dark))
Theme.Changed = Signal.new() :: any

-- Reactive token stores ---------------------------------------------------

local default = Theme.Registered.Dark

Theme.Colors = {} :: { [string]: any }
for key, color in default.Colors :: any do
	Theme.Colors[key] = Value(color)
end

Theme.Radius = {} :: { [string]: any }
for key, value in default.Radius :: any do
	Theme.Radius[key] = Value(value)
end

Theme.Spacing = table.clone(default.Spacing)
Theme.TextSizes = table.clone(default.TextSizes)

Theme.Fonts = {
	Body = Value(default.Fonts.Body),
	Heading = Value(default.Fonts.Heading),
	Mono = Value(default.Fonts.Mono),
}

Theme.StrokeTransparency = Value(default.StrokeTransparency)
Theme.GlassTransparency = Value(default.GlassTransparency)
Theme.ShadowTransparency = Value(default.ShadowTransparency)
Theme.Mode = Value(default.Mode or "Dark")

-- API ----------------------------------------------------------------------

--- Applies a registered theme by name. Live-updates every mounted component.
function Theme.Apply(name: string)
	local spec = Theme.Registered[name]
	assert(spec ~= nil, `[AetherUI] Unknown theme "{name}". Register it first with Theme.Register.`)

	for key, color in spec.Colors :: any do
		if Theme.Colors[key] then
			Theme.Colors[key]:set(color)
		end
	end
	for key, value in spec.Radius :: any do
		if Theme.Radius[key] then
			Theme.Radius[key]:set(value)
		end
	end
	Theme.Fonts.Body:set(spec.Fonts.Body)
	Theme.Fonts.Heading:set(spec.Fonts.Heading)
	Theme.Fonts.Mono:set(spec.Fonts.Mono)
	Theme.StrokeTransparency:set(spec.StrokeTransparency)
	Theme.GlassTransparency:set(spec.GlassTransparency)
	Theme.ShadowTransparency:set(spec.ShadowTransparency)
	Theme.Mode:set(spec.Mode or "Dark")
	Theme.Spacing = table.clone(spec.Spacing)
	Theme.TextSizes = table.clone(spec.TextSizes)

	Theme.ActiveName:set(name)
	Theme.Current:set(flatten(spec))
	Theme.Changed:Fire(name)
end

--- Registers a new theme. `overrides` is deep-merged on top of `base` (default "Dark").
function Theme.Register(name: string, overrides: { [string]: any }, base: string?): ThemeSpec
	local parent = Theme.Registered[base or "Dark"]
	assert(parent ~= nil, `[AetherUI] Unknown base theme "{tostring(base)}".`)
	local spec = Utils.DeepMerge(parent :: any, overrides) :: any
	spec.Name = name
	Theme.Registered[name] = spec
	return spec
end

--- Returns the raw spec of the current theme.
function Theme.GetSpec(): ThemeSpec
	return Theme.Registered[Theme.ActiveName:get()]
end

--- Sets a single color token on the fly (e.g. Theme.SetColor("Primary", myColor)).
function Theme.SetColor(token: string, color: Color3)
	local state = Theme.Colors[token]
	assert(state ~= nil, `[AetherUI] Unknown color token "{token}".`)
	state:set(color)
	-- Propagate into the flat reactive token table so all components update.
	local flat = table.clone(Theme.Current:get())
	flat[token] = color
	Theme.Current:set(flat)
end

-- Persistence ----------------------------------------------------------------

local function serializeColor(c: Color3): { number }
	return { math.round(c.R * 255), math.round(c.G * 255), math.round(c.B * 255) }
end

--- Serializes all custom (non-builtin) themes + the active theme name to JSON.
function Theme.Save(): string
	local custom = {}
	for name, spec in Theme.Registered do
		if Themes[name] == nil then
			local colors = {}
			for key, color in spec.Colors :: any do
				colors[key] = serializeColor(color)
			end
			custom[name] = { Colors = colors, Mode = spec.Mode, Base = "Dark" }
		end
	end
	return HttpService:JSONEncode({
		Active = Theme.ActiveName:get(),
		Custom = custom,
	})
end

--- Restores themes serialized with Theme.Save() and re-applies the active theme.
function Theme.Load(json: string)
	local ok, data = pcall(HttpService.JSONDecode, HttpService, json)
	if not ok or type(data) ~= "table" then
		warn("[AetherUI] Theme.Load received invalid JSON")
		return
	end
	for name, entry in (data.Custom or {}) :: { [string]: any } do
		local colors = {}
		for key, rgb in (entry.Colors or {}) :: { [string]: { number } } do
			colors[key] = Color3.fromRGB(rgb[1], rgb[2], rgb[3])
		end
		Theme.Register(name, { Colors = colors, Mode = entry.Mode }, entry.Base or "Dark")
	end
	if data.Active and Theme.Registered[data.Active] then
		Theme.Apply(data.Active)
	end
end

return Theme

end)

