__register("Components.Accordion", function(require)
--!strict
--[=[
	AetherUI · Accordion / Collapsible
	Smooth height animation, rotating chevron, single or multiple open.
]=]

local Fusion = require("Core.Fusion")
local Theme = require("Core.Theme")
local Icons = require("Core.Icons")
local Sound = require("Core.Sound")
local Primitives = require("Components.Primitives")

local New = Fusion.New
local Children = Fusion.Children
local Value = Fusion.Value
local Computed = Fusion.Computed
local OnEvent = Fusion.OnEvent
local Spring = Fusion.Spring

type AccordionItem = {
	Id: string,
	Title: string,
	Icon: string?,
	Content: () -> Instance,
	DefaultOpen: boolean?,
}

type AccordionProps = {
	Items: { AccordionItem },
	Multiple: boolean?,
	Size: UDim2?,
	LayoutOrder: number?,
	Parent: Instance?,
}

local function Accordion(props: AccordionProps): Frame
	local theme = Theme.Current

	local openSet: Fusion.Value<{ [string]: boolean }> = Value({})
	do
		local initial: { [string]: boolean } = {}
		for _, item in ipairs(props.Items) do
			if item.DefaultOpen then
				initial[item.Id] = true
			end
		end
		openSet:set(initial)
	end

	local function toggle(id: string)
		local current = table.clone(Fusion.peek(openSet))
		if current[id] then
			current[id] = nil
		else
			if not props.Multiple then
				table.clear(current)
			end
			current[id] = true
		end
		openSet:set(current)
		Sound.play("Click")
	end

	local itemFrames: { Instance } = {
		New("UIListLayout")({
			FillDirection = Enum.FillDirection.Vertical,
			Padding = UDim.new(0, 8),
			SortOrder = Enum.SortOrder.LayoutOrder,
		}),
	}

	for i, item in ipairs(props.Items) do
		local isOpen = Computed(function()
			return Fusion.peek(openSet)[item.Id] == true
		end)
		local hovered = Value(false)

		-- content is mounted once, revealed via ClipsDescendants + size spring
		local contentInstance = item.Content()
		local contentHeight = Value(0)
		if contentInstance:IsA("GuiObject") then
			local function measure()
				contentHeight:set((contentInstance :: GuiObject).AbsoluteSize.Y + 12)
			end
			(contentInstance :: GuiObject):GetPropertyChangedSignal("AbsoluteSize"):Connect(measure)
			task.defer(measure)
		end

		local headerChildren: { Instance } = {
			New("UIListLayout")({
				FillDirection = Enum.FillDirection.Horizontal,
				Padding = UDim.new(0, 8),
				VerticalAlignment = Enum.VerticalAlignment.Center,
			}),
			New("UIPadding")({ PaddingLeft = UDim.new(0, 12), PaddingRight = UDim.new(0, 12) }),
		}

		if item.Icon then
			table.insert(headerChildren, Icons.render(item.Icon, {
				Size = UDim2.fromOffset(15, 15),
				LayoutOrder = 1,
				Color = Computed(function()
					return theme:get().TextMuted
				end),
			}))
		end

		table.insert(headerChildren, New("TextLabel")({
			Size = UDim2.new(1, item.Icon and -60 or -40, 1, 0),
			BackgroundTransparency = 1,
			Text = item.Title,
			Font = Enum.Font.GothamMedium,
			TextSize = 13,
			TextColor3 = Computed(function()
				return theme:get().Text
			end),
			TextXAlignment = Enum.TextXAlignment.Left,
			LayoutOrder = 2,
		}))

		table.insert(headerChildren, Icons.render("chevron-down", {
			Size = UDim2.fromOffset(14, 14),
			LayoutOrder = 3,
			Rotation = Spring(Computed(function()
				return Fusion.peek(isOpen) and 180 or 0
			end), 25, 1),
			Color = Computed(function()
				return theme:get().TextMuted
			end),
		}))

		table.insert(itemFrames, Primitives.Surface({
			Name = "AccordionItem_" .. item.Id,
			Size = UDim2.new(1, 0, 0, 0),
			AutomaticSize = Enum.AutomaticSize.Y,
			LayoutOrder = i,
			Padding = 0,
			[Children] = {
				New("UIListLayout")({
					FillDirection = Enum.FillDirection.Vertical,
					SortOrder = Enum.SortOrder.LayoutOrder,
				}),
				New("TextButton")({
					Name = "Header",
					Size = UDim2.new(1, 0, 0, 40),
					Text = "",
					AutoButtonColor = false,
					LayoutOrder = 1,
					BackgroundColor3 = Computed(function()
						return theme:get().SurfaceHigh
					end),
					BackgroundTransparency = Spring(Computed(function()
						return Fusion.peek(hovered) and 0.5 or 1
					end), 30, 1),
					[OnEvent("Activated")] = function()
						toggle(item.Id)
					end,
					[OnEvent("MouseEnter")] = function()
						hovered:set(true)
						Sound.play("Hover")
					end,
					[OnEvent("MouseLeave")] = function()
						hovered:set(false)
					end,
					[Children] = {
						New("UICorner")({ CornerRadius = Computed(function()
							return UDim.new(0, theme:get().RadiusSm)
						end) }),
						New("Frame")({
							Size = UDim2.fromScale(1, 1),
							BackgroundTransparency = 1,
							[Children] = headerChildren,
						}),
					},
				}),
				New("Frame")({
					Name = "ContentClip",
					Size = Spring(Computed(function()
						return UDim2.new(1, 0, 0, Fusion.peek(isOpen) and Fusion.peek(contentHeight) or 0)
					end), 28, 1),
					BackgroundTransparency = 1,
					ClipsDescendants = true,
					LayoutOrder = 2,
					[Children] = {
						New("Frame")({
							Size = UDim2.new(1, 0, 0, 0),
							AutomaticSize = Enum.AutomaticSize.Y,
							BackgroundTransparency = 1,
							[Children] = {
								New("UIPadding")({
									PaddingLeft = UDim.new(0, 12),
									PaddingRight = UDim.new(0, 12),
									PaddingBottom = UDim.new(0, 12),
								}),
								contentInstance,
							},
						}),
					},
				}),
			},
		}))
	end

	return New("Frame")({
		Name = "AetherAccordion",
		Size = props.Size or UDim2.new(1, 0, 0, 0),
		AutomaticSize = Enum.AutomaticSize.Y,
		BackgroundTransparency = 1,
		LayoutOrder = props.LayoutOrder,
		Parent = props.Parent,
		[Children] = itemFrames,
	}) :: Frame
end

return Accordion

end)

__register("Components.Badge", function(require)
--!strict
--[[
	AetherUI • Components/Badge

	Badge(props)          pill label with semantic variants + optional icon/dot
	Badge.Avatar(props)   image or initials avatar with ring + status dot
	Badge.Status(props)   pulsing status indicator with optional label

	Badge props:
		Text: string          Variant: "Default"|"Primary"|"Success"|"Warning"|"Danger"|"Info"|"Outline"
		Icon: string?         Dot: boolean?      Size: "Sm"|"Md"?
	Avatar props:
		Image: string?        Name: string?      Size: number? (px)
		Status: "Online"|"Idle"|"Busy"|"Offline"?   Ring: boolean?
	Status props:
		Status: same as above    Label: string?    Pulse: boolean?
]]

local Fusion = require("Core.Fusion")
local Theme = require("Core.Theme")
local Utils = require("Core.Utils")
local Primitives = require("Components.Primitives")

local New = Fusion.New
local Children = Fusion.Children
local Computed = Fusion.Computed
local Value = Fusion.Value
local Spring = Fusion.Spring

local Badge = {}

-- Variant -> { fg token, mix ratio for bg } -----------------------------------

local VARIANT_TOKENS: { [string]: string } = {
	Default = "TextMuted",
	Primary = "Primary",
	Success = "Success",
	Warning = "Warning",
	Danger = "Danger",
	Info = "Info",
	Outline = "TextMuted",
}

local function fgColor(variant: string)
	local token = VARIANT_TOKENS[variant] or "TextMuted"
	return Computed(function()
		return Theme.Colors[token]:get()
	end)
end

local function bgColor(variant: string)
	local token = VARIANT_TOKENS[variant] or "TextMuted"
	return Computed(function()
		if variant == "Default" then
			return Theme.Colors.SurfaceHigh:get()
		end
		-- Tint: 15% accent over surface.
		local accent: Color3 = Theme.Colors[token]:get()
		local surface: Color3 = Theme.Colors.Surface:get()
		return surface:Lerp(accent, 0.15)
	end)
end

-- Badge ------------------------------------------------------------------------

function Badge.new(props: { [string]: any }): Frame
	local variant: string = props.Variant or "Default"
	local size: string = props.Size or "Md"
	local height = if size == "Sm" then 18 else 22
	local textSize = if size == "Sm" then 10 else 11
	local fg = fgColor(variant)

	local content: { any } = {
		Primitives.Corner("Full"),
		Primitives.Stroke({
			Color = if variant == "Outline" then nil else fg,
			Transparency = if variant == "Outline" then nil else 0.75,
		}),
		Primitives.Padding({ Left = if props.Dot or props.Icon then 8 else 10, Right = 10 }),
		Primitives.List({ Direction = "Horizontal", Padding = 5, VerticalAlignment = Enum.VerticalAlignment.Center }),
	}

	if props.Dot then
		table.insert(content, New("Frame")({
			Name = "Dot",
			Size = UDim2.fromOffset(6, 6),
			BackgroundColor3 = fg,
			LayoutOrder = 1,
			[Children] = { Primitives.Corner("Full") },
		}))
	elseif props.Icon then
		table.insert(content, Primitives.Icon({
			Name = props.Icon,
			Size = 12,
			Color = fg,
			LayoutOrder = 1,
		}))
	end

	table.insert(content, Primitives.Text({
		Text = props.Text or "",
		Size = textSize,
		Color = fg,
		Bold = true,
		LayoutOrder = 2,
	}))

	return New("Frame")({
		Name = "AetherBadge",
		AutomaticSize = Enum.AutomaticSize.X,
		Size = UDim2.fromOffset(0, height),
		BackgroundColor3 = bgColor(variant),
		BackgroundTransparency = if variant == "Outline" then 1 else 0,
		LayoutOrder = props.LayoutOrder,
		Position = props.Position,
		AnchorPoint = props.AnchorPoint,
		Parent = props.Parent,
		[Children] = content,
	})
end

-- Status color helper ------------------------------------------------------------

local STATUS_TOKENS: { [string]: string } = {
	Online = "Success",
	Idle = "Warning",
	Busy = "Danger",
	Offline = "TextDim",
}

local function statusColor(status: string)
	local token = STATUS_TOKENS[status] or "TextDim"
	return Computed(function()
		return Theme.Colors[token]:get()
	end)
end

-- Avatar ------------------------------------------------------------------------

local function initialsOf(name: string): string
	local parts = string.split(name, " ")
	local first = string.sub(parts[1] or "?", 1, 1)
	local second = if #parts > 1 then string.sub(parts[#parts], 1, 1) else ""
	return string.upper(first .. second)
end

function Badge.Avatar(props: { [string]: any }): Frame
	local px: number = props.Size or 36

	local inner: Instance
	if props.Image then
		inner = New("ImageLabel")({
			Name = "Image",
			Size = UDim2.fromScale(1, 1),
			BackgroundColor3 = Computed(function()
				return Theme.Colors.SurfaceHigh:get()
			end),
			Image = props.Image,
			ScaleType = Enum.ScaleType.Crop,
			[Children] = { Primitives.Corner("Full") },
		})
	else
		inner = New("TextLabel")({
			Name = "Initials",
			Size = UDim2.fromScale(1, 1),
			BackgroundColor3 = Computed(function()
				return Theme.Colors.Surface:get():Lerp(Theme.Colors.Primary:get(), 0.2)
			end),
			Text = initialsOf(props.Name or "?"),
			TextSize = math.max(10, math.floor(px * 0.36)),
			FontFace = Computed(function()
				return Theme.Fonts.Heading:get()
			end),
			TextColor3 = Computed(function()
				return Theme.Colors.Primary:get()
			end),
			[Children] = { Primitives.Corner("Full") },
		})
	end

	local content: { any } = { inner }

	if props.Ring then
		table.insert(content, New("UIStroke")({
			Color = Computed(function()
				return Theme.Colors.Primary:get()
			end),
			Thickness = 2,
			Transparency = 0.25,
			ApplyStrokeMode = Enum.ApplyStrokeMode.Border,
		}))
	end

	if props.Status then
		local dotPx = math.max(8, math.floor(px * 0.28))
		table.insert(content, New("Frame")({
			Name = "StatusDot",
			Size = UDim2.fromOffset(dotPx, dotPx),
			Position = UDim2.new(1, -dotPx + 1, 1, -dotPx + 1),
			BackgroundColor3 = statusColor(props.Status),
			ZIndex = 2,
			[Children] = {
				Primitives.Corner("Full"),
				New("UIStroke")({
					Color = Computed(function()
						return Theme.Colors.Surface:get()
					end),
					Thickness = 2,
					ApplyStrokeMode = Enum.ApplyStrokeMode.Border,
				}),
			},
		}))
	end

	return New("Frame")({
		Name = "AetherAvatar",
		Size = UDim2.fromOffset(px, px),
		BackgroundTransparency = 1,
		LayoutOrder = props.LayoutOrder,
		Position = props.Position,
		AnchorPoint = props.AnchorPoint,
		Parent = props.Parent,
		[Children] = content,
	})
end

-- StatusIndicator ------------------------------------------------------------------

function Badge.Status(props: { [string]: any }): Frame
	local pulseScale = Value(1)

	local dot = New("Frame")({
		Name = "Dot",
		Size = UDim2.fromOffset(8, 8),
		BackgroundColor3 = statusColor(props.Status or "Offline"),
		LayoutOrder = 1,
		[Children] = {
			Primitives.Corner("Full"),
			New("UIScale")({
				Scale = Spring(pulseScale, 8, 0.6),
			}),
		},
	})

	if props.Pulse and props.Status ~= "Offline" then
		task.spawn(function()
			task.wait() -- allow one frame for mounting
			while dot:IsDescendantOf(game) do
				pulseScale:set(1.25)
				task.wait(0.9)
				pulseScale:set(1)
				task.wait(0.9)
			end
		end)
	end

	local content: { any } = {
		Primitives.List({ Direction = "Horizontal", Padding = 6, VerticalAlignment = Enum.VerticalAlignment.Center }),
		dot,
	}

	if props.Label then
		table.insert(content, Primitives.Text({
			Text = props.Label,
			Size = 12,
			Muted = true,
			LayoutOrder = 2,
		}))
	end

	return New("Frame")({
		Name = "AetherStatus",
		AutomaticSize = Enum.AutomaticSize.XY,
		BackgroundTransparency = 1,
		LayoutOrder = props.LayoutOrder,
		Position = props.Position,
		AnchorPoint = props.AnchorPoint,
		Parent = props.Parent,
		[Children] = content,
	})
end

local _ = Utils -- reserved for future color utilities

setmetatable(Badge, {
	__call = function(_, props)
		return Badge.new(props)
	end,
})

return Badge

end)

__register("Components.Breadcrumbs", function(require)
--!strict
--[=[
	AetherUI · Breadcrumbs
	Path navigation with chevron separators; last crumb is emphasized.
]=]

local Fusion = require("Core.Fusion")
local Theme = require("Core.Theme")
local Icons = require("Core.Icons")
local Sound = require("Core.Sound")

local New = Fusion.New
local Children = Fusion.Children
local Value = Fusion.Value
local Computed = Fusion.Computed
local OnEvent = Fusion.OnEvent
local Spring = Fusion.Spring

type Crumb = {
	Label: string,
	Icon: string?,
	OnClick: (() -> ())?,
}

type BreadcrumbsProps = {
	Items: { Crumb },
	LayoutOrder: number?,
	Parent: Instance?,
}

local function Breadcrumbs(props: BreadcrumbsProps): Frame
	local theme = Theme.Current

	local children: { Instance } = {
		New("UIListLayout")({
			FillDirection = Enum.FillDirection.Horizontal,
			Padding = UDim.new(0, 6),
			VerticalAlignment = Enum.VerticalAlignment.Center,
			SortOrder = Enum.SortOrder.LayoutOrder,
		}),
	}

	local order = 0
	for i, crumb in ipairs(props.Items) do
		local isLast = i == #props.Items
		local hovered = Value(false)

		order += 1
		local crumbChildren: { Instance } = {
			New("UIListLayout")({
				FillDirection = Enum.FillDirection.Horizontal,
				Padding = UDim.new(0, 4),
				VerticalAlignment = Enum.VerticalAlignment.Center,
			}),
		}
		if crumb.Icon then
			table.insert(crumbChildren, Icons.render(crumb.Icon, {
				Size = UDim2.fromOffset(13, 13),
				LayoutOrder = 1,
				Color = Computed(function()
					local t = theme:get()
					return isLast and t.Text or t.TextMuted
				end),
			}))
		end
		table.insert(crumbChildren, New("TextLabel")({
			AutomaticSize = Enum.AutomaticSize.XY,
			BackgroundTransparency = 1,
			Text = crumb.Label,
			Font = isLast and Enum.Font.GothamBold or Enum.Font.GothamMedium,
			TextSize = 12,
			LayoutOrder = 2,
			TextColor3 = Spring(Computed(function()
				local t = theme:get()
				if isLast then
					return t.Text
				end
				return Fusion.peek(hovered) and t.Text or t.TextMuted
			end), 30, 1),
		}))

		table.insert(children, New("TextButton")({
			Name = "Crumb_" .. i,
			AutomaticSize = Enum.AutomaticSize.XY,
			BackgroundTransparency = 1,
			Text = "",
			LayoutOrder = order,
			[OnEvent("Activated")] = function()
				if not isLast and crumb.OnClick then
					Sound.play("Click")
					crumb.OnClick()
				end
			end,
			[OnEvent("MouseEnter")] = function()
				if not isLast then
					hovered:set(true)
				end
			end,
			[OnEvent("MouseLeave")] = function()
				hovered:set(false)
			end,
			[Children] = crumbChildren,
		}))

		if not isLast then
			order += 1
			table.insert(children, Icons.render("chevron-right", {
				Size = UDim2.fromOffset(12, 12),
				LayoutOrder = order,
				Color = Computed(function()
					return theme:get().TextDisabled
				end),
			}))
		end
	end

	return New("Frame")({
		Name = "AetherBreadcrumbs",
		Size = UDim2.new(1, 0, 0, 24),
		BackgroundTransparency = 1,
		LayoutOrder = props.LayoutOrder,
		Parent = props.Parent,
		[Children] = children,
	}) :: Frame
end

return Breadcrumbs

end)

__register("Components.Button", function(require)
--!strict
--[[
	AetherUI • Components/Button

	Variants: Primary | Secondary | Outline | Ghost | Destructive
	Sizes:    Sm | Md | Lg | Icon

	props:
		Text: string?               Icon: string?          IconRight: string?
		Variant: string?            Size: string?          Disabled: boolean | Value?
		Loading: boolean | Value?   OnClick: () -> ()?     FullWidth: boolean?
		LayoutOrder, Position, AnchorPoint, ZIndex
]]

local Fusion = require("Core.Fusion")
local Theme = require("Core.Theme")
local Animation = require("Core.Animation")
local Primitives = require("Components.Primitives")
local UseHover = require("Hooks.UseHover")
local UsePress = require("Hooks.UsePress")

local New = Fusion.New
local Children = Fusion.Children
local OnEvent = Fusion.OnEvent
local Computed = Fusion.Computed
local Tween = Fusion.Tween
local Value = Fusion.Value

local SIZES = {
	Sm = { Height = 30, Text = "Sm", PadX = 12, Icon = 14 },
	Md = { Height = 36, Text = "Md", PadX = 16, Icon = 16 },
	Lg = { Height = 42, Text = "Lg", PadX = 20, Icon = 18 },
	Icon = { Height = 36, Text = "Md", PadX = 0, Icon = 16 },
}

local function asState(value: any): any
	if type(value) == "table" and type(value.get) == "function" then
		return value
	end
	return Value(value or false)
end

return function(props: { [string]: any }): TextButton
	local variant: string = props.Variant or "Primary"
	local size = SIZES[props.Size or "Md"] or SIZES.Md
	local disabled = asState(props.Disabled)
	local loading = asState(props.Loading)

	local hover = UseHover()
	local press = UsePress()

	local interactive = Computed(function()
		return not disabled:get() and not loading:get()
	end)

	local background = Computed(function()
		local c = Theme.Colors
		local hovering = hover.Hovering:get() and interactive:get()
		if variant == "Primary" then
			return if hovering then c.PrimaryHover:get() else c.Primary:get()
		elseif variant == "Destructive" then
			return if hovering then c.DangerHover:get() else c.Danger:get()
		elseif variant == "Secondary" then
			return if hovering then c.SecondaryHover:get() else c.Secondary:get()
		else -- Outline / Ghost
			return if hovering then c.SurfaceHover:get() else c.Surface:get()
		end
	end)

	local backgroundTransparency = Computed(function()
		if variant == "Ghost" and not (hover.Hovering:get() and interactive:get()) then
			return 1
		end
		if variant == "Outline" and not (hover.Hovering:get() and interactive:get()) then
			return 1
		end
		return if disabled:get() then 0.45 else 0
	end)

	local textColor = Computed(function()
		local c = Theme.Colors
		if disabled:get() then
			return c.TextDisabled:get()
		end
		if variant == "Primary" then
			return c.PrimaryText:get()
		elseif variant == "Destructive" then
			return Color3.new(1, 1, 1)
		end
		return c.Text:get()
	end)

	local spinnerRotation = Value(0)
	task.spawn(function()
		-- lightweight spinner driver; stops itself when button is gone
		while task.wait(1 / 60) do
			if loading:get() then
				spinnerRotation:set((spinnerRotation:get() + 7) % 360)
			end
		end
	end)

	local isIconOnly = props.Size == "Icon"

	local content: { any } = {
		Primitives.Corner("Md"),
		Primitives.List({
			Direction = Enum.FillDirection.Horizontal,
			Gap = 8,
			HorizontalAlignment = Enum.HorizontalAlignment.Center,
			VerticalAlignment = Enum.VerticalAlignment.Center,
		}),
	}

	if variant == "Outline" then
		table.insert(content, Primitives.Stroke({ Color = Theme.Colors.BorderStrong, Transparency = 0.4 }))
	end

	if not isIconOnly then
		table.insert(content, Primitives.Padding({ X = size.PadX }))
	end

	-- Loading spinner replaces the left icon
	table.insert(
		content,
		New("ImageLabel")({
			Name = "Spinner",
			BackgroundTransparency = 1,
			Image = "rbxassetid://11304130802",
			ImageColor3 = textColor,
			Size = UDim2.fromOffset(size.Icon, size.Icon),
			Rotation = Computed(function()
				return spinnerRotation:get()
			end),
			Visible = Computed(function()
				return loading:get()
			end),
			LayoutOrder = 0,
		})
	)

	if props.Icon then
		table.insert(
			content,
			New("Frame")({
				Name = "IconSlot",
				BackgroundTransparency = 1,
				Size = UDim2.fromOffset(size.Icon, size.Icon),
				LayoutOrder = 1,
				Visible = Computed(function()
					return not loading:get()
				end),
				[Children] = { Primitives.Icon({ Name = props.Icon, Size = size.Icon, Color = textColor }) },
			})
		)
	end

	if props.Text and not isIconOnly then
		table.insert(
			content,
			Primitives.Text({
				Text = props.Text,
				Size = size.Text,
				Color = textColor,
				LayoutOrder = 2,
			})
		)
	end

	if props.IconRight then
		table.insert(
			content,
			Primitives.Icon({ Name = props.IconRight, Size = size.Icon, Color = textColor, LayoutOrder = 3 })
		)
	end

	local button: TextButton

	button = New("TextButton")({
		Name = "AetherButton",
		Text = "",
		AutoButtonColor = false,
		BackgroundColor3 = Tween(background, Animation.Presets.Fast),
		BackgroundTransparency = Tween(backgroundTransparency, Animation.Presets.Fast),
		Size = if props.FullWidth
			then UDim2.new(1, 0, 0, size.Height)
			elseif isIconOnly then UDim2.fromOffset(size.Height, size.Height)
			else UDim2.fromOffset(0, size.Height),
		AutomaticSize = if props.FullWidth or isIconOnly then Enum.AutomaticSize.None else Enum.AutomaticSize.X,
		LayoutOrder = props.LayoutOrder or 0,
		Position = props.Position,
		AnchorPoint = props.AnchorPoint,
		ZIndex = props.ZIndex or 1,
		Active = interactive,

		[OnEvent("MouseEnter")] = hover.Enter,
		[OnEvent("MouseLeave")] = function()
			hover.Leave()
			press.Up()
		end,
		[OnEvent("MouseButton1Down")] = function()
			if interactive:get() then
				press.Down()
			end
		end,
		[OnEvent("MouseButton1Up")] = press.Up,
		[OnEvent("Activated")] = function()
			if interactive:get() then
				Animation.Pulse(button)
				press.Activate(props.OnClick)
			end
		end,

		[Children] = content,
	}) :: TextButton

	return button
end

end)

__register("Components.Card", function(require)
--!strict
--[=[
	AetherUI · Card / Section / GroupBox
	Elevated surfaces with optional header (title, description, icon, actions).
]=]

local Fusion = require("Core.Fusion")
local Theme = require("Core.Theme")
local Icons = require("Core.Icons")
local Primitives = require("Components.Primitives")

local New = Fusion.New
local Children = Fusion.Children
local Computed = Fusion.Computed

local Card = {}

type CardProps = {
	Title: string?,
	Description: string?,
	Icon: string?,
	Glass: boolean?,
	Padding: number?,
	Size: UDim2?,
	AutomaticSize: Enum.AutomaticSize?,
	LayoutOrder: number?,
	Parent: Instance?,
	Children: { Instance }?,
	HeaderActions: { Instance }?,
}

function Card.Card(props: CardProps): Frame
	local theme = Theme.Current
	local body: { Instance } = {
		New("UIListLayout")({
			FillDirection = Enum.FillDirection.Vertical,
			Padding = UDim.new(0, 12),
			SortOrder = Enum.SortOrder.LayoutOrder,
		}),
	}

	if props.Title then
		local headerRow: { Instance } = {
			New("UIListLayout")({
				FillDirection = Enum.FillDirection.Horizontal,
				Padding = UDim.new(0, 8),
				VerticalAlignment = Enum.VerticalAlignment.Center,
			}),
		}

		if props.Icon then
			table.insert(headerRow, Icons.render(props.Icon, {
				Size = UDim2.fromOffset(16, 16),
				LayoutOrder = 1,
				Color = Computed(function()
					return theme:get().Primary
				end),
			}))
		end

		table.insert(headerRow, New("Frame")({
			Name = "Titles",
			AutomaticSize = Enum.AutomaticSize.XY,
			BackgroundTransparency = 1,
			LayoutOrder = 2,
			[Children] = {
				New("UIListLayout")({
					FillDirection = Enum.FillDirection.Vertical,
					Padding = UDim.new(0, 2),
				}),
				New("TextLabel")({
					AutomaticSize = Enum.AutomaticSize.XY,
					BackgroundTransparency = 1,
					Text = props.Title,
					Font = Enum.Font.GothamBold,
					TextSize = 14,
					TextColor3 = Computed(function()
						return theme:get().Text
					end),
					TextXAlignment = Enum.TextXAlignment.Left,
				}),
				props.Description and New("TextLabel")({
					AutomaticSize = Enum.AutomaticSize.XY,
					BackgroundTransparency = 1,
					Text = props.Description,
					Font = Enum.Font.Gotham,
					TextSize = 12,
					TextColor3 = Computed(function()
						return theme:get().TextMuted
					end),
					TextXAlignment = Enum.TextXAlignment.Left,
					TextWrapped = true,
				}) or nil,
			},
		}))

		if props.HeaderActions then
			table.insert(headerRow, New("Frame")({
				Name = "Actions",
				AutomaticSize = Enum.AutomaticSize.XY,
				BackgroundTransparency = 1,
				LayoutOrder = 99,
				[Children] = {
					New("UIListLayout")({
						FillDirection = Enum.FillDirection.Horizontal,
						Padding = UDim.new(0, 6),
					}),
					props.HeaderActions :: any,
				},
			}))
		end

		table.insert(body, New("Frame")({
			Name = "Header",
			Size = UDim2.new(1, 0, 0, 0),
			AutomaticSize = Enum.AutomaticSize.Y,
			BackgroundTransparency = 1,
			LayoutOrder = 0,
			[Children] = headerRow,
		}))
	end

	if props.Children then
		for i, child in ipairs(props.Children) do
			if child:IsA("GuiObject") then
				child.LayoutOrder = i
			end
			table.insert(body, child)
		end
	end

	return Primitives.Surface({
		Name = "AetherCard",
		Size = props.Size or UDim2.new(1, 0, 0, 0),
		AutomaticSize = props.AutomaticSize or Enum.AutomaticSize.Y,
		Padding = props.Padding or 16,
		Glass = props.Glass,
		Shadow = true,
		LayoutOrder = props.LayoutOrder,
		Parent = props.Parent,
		[Children] = body,
	}) :: Frame
end

type SectionProps = {
	Title: string,
	LayoutOrder: number?,
	Parent: Instance?,
	Children: { Instance }?,
}

function Card.Section(props: SectionProps): Frame
	local theme = Theme.Current
	local body: { Instance } = {
		New("UIListLayout")({
			FillDirection = Enum.FillDirection.Vertical,
			Padding = UDim.new(0, 10),
			SortOrder = Enum.SortOrder.LayoutOrder,
		}),
		New("TextLabel")({
			Size = UDim2.new(1, 0, 0, 14),
			BackgroundTransparency = 1,
			Text = string.upper(props.Title),
			Font = Enum.Font.GothamBold,
			TextSize = 11,
			TextColor3 = Computed(function()
				return theme:get().TextMuted
			end),
			TextXAlignment = Enum.TextXAlignment.Left,
			LayoutOrder = 0,
		}),
	}

	if props.Children then
		for i, child in ipairs(props.Children) do
			if child:IsA("GuiObject") then
				child.LayoutOrder = i
			end
			table.insert(body, child)
		end
	end

	return New("Frame")({
		Name = "AetherSection",
		Size = UDim2.new(1, 0, 0, 0),
		AutomaticSize = Enum.AutomaticSize.Y,
		BackgroundTransparency = 1,
		LayoutOrder = props.LayoutOrder,
		Parent = props.Parent,
		[Children] = body,
	}) :: Frame
end

return Card

end)

__register("Components.Checkbox", function(require)
--!strict
--[[
	AetherUI • Components/Checkbox
	props: Label?, Description?, Value: Fusion.Value<boolean>?, Disabled?, OnChanged?, LayoutOrder
]]

local Fusion = require("Core.Fusion")
local Theme = require("Core.Theme")
local Animation = require("Core.Animation")
local Sound = require("Core.Sound")
local Primitives = require("Components.Primitives")

local New = Fusion.New
local Children = Fusion.Children
local OnEvent = Fusion.OnEvent
local Computed = Fusion.Computed
local Tween = Fusion.Tween
local Spring = Fusion.Spring
local Value = Fusion.Value

return function(props: { [string]: any }): TextButton
	local checked = props.Value or Value(false)
	local hovering = Value(false)

	local checkScale = Spring(
		Computed(function()
			return if checked:get() then 1 else 0
		end),
		Animation.Springs.Wobbly.Speed,
		Animation.Springs.Wobbly.Damping
	)

	local function toggle()
		if props.Disabled then
			return
		end
		checked:set(not checked:get())
		Sound.Play("Toggle")
		if props.OnChanged then
			props.OnChanged(checked:get())
		end
	end

	return New("TextButton")({
		Name = "AetherCheckbox",
		Parent = props.Parent,
		Text = "",
		AutoButtonColor = false,
		BackgroundTransparency = 1,
		AutomaticSize = Enum.AutomaticSize.XY,
		LayoutOrder = props.LayoutOrder or 0,
		[OnEvent("MouseEnter")] = function()
			hovering:set(true)
		end,
		[OnEvent("MouseLeave")] = function()
			hovering:set(false)
		end,
		[OnEvent("Activated")] = toggle,
		[Children] = {
			Primitives.List({
				Direction = Enum.FillDirection.Horizontal,
				Gap = 10,
				VerticalAlignment = Enum.VerticalAlignment.Top,
			}),

			New("Frame")({
				Name = "Box",
				BackgroundColor3 = Tween(
					Computed(function()
						return if checked:get() then Theme.Colors.Primary:get() else Theme.Colors.Surface:get()
					end),
					Animation.Presets.Fast
				),
				Size = UDim2.fromOffset(18, 18),
				LayoutOrder = 0,
				[Children] = {
					Primitives.Corner(5),
					Primitives.Stroke({
						Color = Tween(
							Computed(function()
								if checked:get() then
									return Theme.Colors.Primary:get()
								end
								return if hovering:get() then Theme.Colors.BorderStrong:get() else Theme.Colors.Border:get()
							end),
							Animation.Presets.Fast
						),
						Transparency = 0,
					}),
					New("Frame")({
						BackgroundTransparency = 1,
						Size = UDim2.fromScale(1, 1),
						[Children] = {
							New("UIScale")({ Scale = checkScale }),
							Primitives.Icon({
								Name = "check",
								Size = 12,
								Color = Theme.Colors.PrimaryText,
								Position = UDim2.fromScale(0.5, 0.5),
								AnchorPoint = Vector2.new(0.5, 0.5),
							}),
						},
					}),
				},
			}),

			if props.Label
				then New("Frame")({
					Name = "Copy",
					BackgroundTransparency = 1,
					AutomaticSize = Enum.AutomaticSize.XY,
					LayoutOrder = 1,
					[Children] = {
						Primitives.List({ Gap = 2 }),
						Primitives.Text({
							Text = props.Label,
							Size = "Sm",
							Color = if props.Disabled then Theme.Colors.TextDisabled else Theme.Colors.Text,
						}),
						if props.Description
							then Primitives.Text({ Text = props.Description, Size = "Xs", Muted = true, Wrapped = true })
							else nil,
					},
				})
				else nil,
		},
	}) :: TextButton
end

end)

__register("Components.ColorPicker", function(require)
--!strict
--[=[
	AetherUI · ColorPicker
	Advanced color picker: SV square + Hue bar, RGB/HEX inputs,
	preset swatches, copy-to-clipboard button, live preview.
]=]

local Fusion = require("Core.Fusion")
local Theme = require("Core.Theme")
local Icons = require("Core.Icons")
local Sound = require("Core.Sound")
local Utils = require("Core.Utils")
local Primitives = require("Components.Primitives")

local New = Fusion.New
local Children = Fusion.Children
local Value = Fusion.Value
local Computed = Fusion.Computed
local OnEvent = Fusion.OnEvent
local Spring = Fusion.Spring

local UserInputService = game:GetService("UserInputService")

type ColorPickerProps = {
	Value: Color3?,
	Presets: { Color3 }?,
	ShowHex: boolean?,
	ShowRGB: boolean?,
	OnChanged: ((color: Color3) -> ())?,
	Size: UDim2?,
	LayoutOrder: number?,
	Parent: Instance?,
}

local DEFAULT_PRESETS: { Color3 } = {
	Color3.fromRGB(99, 102, 241),
	Color3.fromRGB(59, 130, 246),
	Color3.fromRGB(16, 185, 129),
	Color3.fromRGB(245, 158, 11),
	Color3.fromRGB(239, 68, 68),
	Color3.fromRGB(236, 72, 153),
	Color3.fromRGB(255, 255, 255),
	Color3.fromRGB(23, 23, 23),
}

local function ColorPicker(props: ColorPickerProps): Frame
	local theme = Theme.Current

	local initH, initS, initV = (props.Value or Color3.fromRGB(99, 102, 241)):ToHSV()
	local hue = Value(initH)
	local sat = Value(initS)
	local val = Value(initV)

	local draggingSV = Value(false)
	local draggingHue = Value(false)
	local copied = Value(false)

	local color = Computed(function()
		return Color3.fromHSV(Fusion.peek(hue), Fusion.peek(sat), Fusion.peek(val))
	end)

	local function emit()
		if props.OnChanged then
			props.OnChanged(Fusion.peek(color))
		end
	end

	local function setFromColor(c: Color3)
		local h, s, v = c:ToHSV()
		hue:set(h)
		sat:set(s)
		val:set(v)
		emit()
	end

	local hexText = Computed(function()
		return Utils.ToHex(Fusion.peek(color))
	end)

	-- SV square ---------------------------------------------------------
	local svSquare = New("ImageButton")({
		Name = "SVSquare",
		Size = UDim2.new(1, 0, 0, 140),
		BackgroundColor3 = Computed(function()
			return Color3.fromHSV(Fusion.peek(hue), 1, 1)
		end),
		AutoButtonColor = false,
		[Children] = {
			New("UICorner")({ CornerRadius = Computed(function()
				return UDim.new(0, theme:get().RadiusSm)
			end) }),
			-- white → transparent horizontal
			New("Frame")({
				Size = UDim2.fromScale(1, 1),
				BackgroundColor3 = Color3.new(1, 1, 1),
				[Children] = {
					New("UIGradient")({
						Transparency = NumberSequence.new({
							NumberSequenceKeypoint.new(0, 0),
							NumberSequenceKeypoint.new(1, 1),
						}),
					}),
					New("UICorner")({ CornerRadius = UDim.new(0, 8) }),
				},
			}),
			-- transparent → black vertical
			New("Frame")({
				Size = UDim2.fromScale(1, 1),
				BackgroundColor3 = Color3.new(0, 0, 0),
				[Children] = {
					New("UIGradient")({
						Rotation = 90,
						Transparency = NumberSequence.new({
							NumberSequenceKeypoint.new(0, 1),
							NumberSequenceKeypoint.new(1, 0),
						}),
					}),
					New("UICorner")({ CornerRadius = UDim.new(0, 8) }),
				},
			}),
			-- Thumb
			New("Frame")({
				Name = "Thumb",
				AnchorPoint = Vector2.new(0.5, 0.5),
				Position = Spring(Computed(function()
					return UDim2.fromScale(Fusion.peek(sat), 1 - Fusion.peek(val))
				end), 40, 1),
				Size = Computed(function()
					return Fusion.peek(draggingSV) and UDim2.fromOffset(18, 18) or UDim2.fromOffset(14, 14)
				end),
				BackgroundColor3 = color,
				ZIndex = 3,
				[Children] = {
					New("UICorner")({ CornerRadius = UDim.new(1, 0) }),
					New("UIStroke")({ Color = Color3.new(1, 1, 1), Thickness = 2 }),
				},
			}),
		},
	}) :: ImageButton

	local function updateSV(input: InputObject)
		local pos = svSquare.AbsolutePosition
		local size = svSquare.AbsoluteSize
		local x = math.clamp((input.Position.X - pos.X) / size.X, 0, 1)
		local y = math.clamp((input.Position.Y - pos.Y) / size.Y, 0, 1)
		sat:set(x)
		val:set(1 - y)
		emit()
	end

	svSquare.InputBegan:Connect(function(input)
		if input.UserInputType == Enum.UserInputType.MouseButton1 or input.UserInputType == Enum.UserInputType.Touch then
			draggingSV:set(true)
			updateSV(input)
		end
	end)

	UserInputService.InputChanged:Connect(function(input)
		if Fusion.peek(draggingSV) and (input.UserInputType == Enum.UserInputType.MouseMovement or input.UserInputType == Enum.UserInputType.Touch) then
			updateSV(input)
		end
	end)
	UserInputService.InputEnded:Connect(function(input)
		if input.UserInputType == Enum.UserInputType.MouseButton1 or input.UserInputType == Enum.UserInputType.Touch then
			draggingSV:set(false)
			draggingHue:set(false)
		end
	end)

	-- Hue bar -----------------------------------------------------------
	local hueKeypoints = {}
	for i = 0, 6 do
		table.insert(hueKeypoints, ColorSequenceKeypoint.new(i / 6, Color3.fromHSV(i / 6, 1, 1)))
	end

	local hueBar = New("ImageButton")({
		Name = "HueBar",
		Size = UDim2.new(1, 0, 0, 14),
		BackgroundColor3 = Color3.new(1, 1, 1),
		AutoButtonColor = false,
		[Children] = {
			New("UIGradient")({ Color = ColorSequence.new(hueKeypoints) }),
			New("UICorner")({ CornerRadius = UDim.new(1, 0) }),
			New("Frame")({
				Name = "Thumb",
				AnchorPoint = Vector2.new(0.5, 0.5),
				Position = Spring(Computed(function()
					return UDim2.fromScale(Fusion.peek(hue), 0.5)
				end), 40, 1),
				Size = UDim2.fromOffset(18, 18),
				BackgroundColor3 = Computed(function()
					return Color3.fromHSV(Fusion.peek(hue), 1, 1)
				end),
				ZIndex = 3,
				[Children] = {
					New("UICorner")({ CornerRadius = UDim.new(1, 0) }),
					New("UIStroke")({ Color = Color3.new(1, 1, 1), Thickness = 2 }),
				},
			}),
		},
	}) :: ImageButton

	local function updateHue(input: InputObject)
		local pos = hueBar.AbsolutePosition
		local size = hueBar.AbsoluteSize
		local x = math.clamp((input.Position.X - pos.X) / size.X, 0, 1)
		hue:set(x)
		emit()
	end

	hueBar.InputBegan:Connect(function(input)
		if input.UserInputType == Enum.UserInputType.MouseButton1 or input.UserInputType == Enum.UserInputType.Touch then
			draggingHue:set(true)
			updateHue(input)
		end
	end)
	UserInputService.InputChanged:Connect(function(input)
		if Fusion.peek(draggingHue) and (input.UserInputType == Enum.UserInputType.MouseMovement or input.UserInputType == Enum.UserInputType.Touch) then
			updateHue(input)
		end
	end)

	-- HEX row -----------------------------------------------------------
	local hexBox = New("TextBox")({
		Name = "HexInput",
		Size = UDim2.new(1, -76, 1, 0),
		BackgroundColor3 = Computed(function()
			return theme:get().SurfaceHigh
		end),
		Text = hexText,
		TextColor3 = Computed(function()
			return theme:get().Text
		end),
		Font = Enum.Font.RobotoMono,
		TextSize = 13,
		ClearTextOnFocus = false,
		[Children] = {
			New("UICorner")({ CornerRadius = UDim.new(0, 8) }),
			New("UIStroke")({
				Color = Computed(function()
					return theme:get().Border
				end),
				Thickness = 1,
			}),
		},
	}) :: TextBox

	hexBox.FocusLost:Connect(function(enterPressed)
		if enterPressed then
			local parsed = Utils.FromHex(hexBox.Text)
			if parsed then
				setFromColor(parsed)
				Sound.play("Success")
			else
				hexBox.Text = Fusion.peek(hexText)
			end
		end
	end)

	local copyButton = New("TextButton")({
		Name = "CopyButton",
		Size = UDim2.fromOffset(32, 32),
		BackgroundColor3 = Computed(function()
			return theme:get().SurfaceHigh
		end),
		Text = "",
		AutoButtonColor = false,
		[OnEvent("Activated")] = function()
			-- setclipboard is exploit-env only; fall back to selecting text
			local ok = pcall(function()
				(getfenv() :: any).setclipboard(Fusion.peek(hexText))
			end)
			if not ok then
				hexBox:CaptureFocus()
			end
			copied:set(true)
			Sound.play("Click")
			task.delay(1.2, function()
				copied:set(false)
			end)
		end,
		[Children] = {
			New("UICorner")({ CornerRadius = UDim.new(0, 8) }),
			New("UIStroke")({
				Color = Computed(function()
					return theme:get().Border
				end),
				Thickness = 1,
			}),
			Icons.render(Computed(function()
				return Fusion.peek(copied) and "check" or "copy"
			end), {
				Size = UDim2.fromOffset(14, 14),
				Position = UDim2.fromScale(0.5, 0.5),
				AnchorPoint = Vector2.new(0.5, 0.5),
				Color = Computed(function()
					local t = theme:get()
					return Fusion.peek(copied) and t.Success or t.TextMuted
				end),
			}),
		},
	})

	-- Preview swatch
	local preview = New("Frame")({
		Name = "Preview",
		Size = UDim2.fromOffset(32, 32),
		BackgroundColor3 = Spring(color, 30, 1),
		[Children] = {
			New("UICorner")({ CornerRadius = UDim.new(0, 8) }),
			New("UIStroke")({
				Color = Computed(function()
					return theme:get().Border
				end),
				Thickness = 1,
			}),
		},
	})

	-- Presets row -------------------------------------------------------
	local presetChildren: { Instance } = {
		New("UIListLayout")({
			FillDirection = Enum.FillDirection.Horizontal,
			Padding = UDim.new(0, 6),
			VerticalAlignment = Enum.VerticalAlignment.Center,
		}),
	}
	for i, presetColor in ipairs(props.Presets or DEFAULT_PRESETS) do
		table.insert(presetChildren, New("TextButton")({
			Name = "Preset" .. i,
			Size = UDim2.fromOffset(22, 22),
			BackgroundColor3 = presetColor,
			Text = "",
			AutoButtonColor = false,
			LayoutOrder = i,
			[OnEvent("Activated")] = function()
				setFromColor(presetColor)
				Sound.play("Click")
			end,
			[Children] = {
				New("UICorner")({ CornerRadius = UDim.new(1, 0) }),
				New("UIStroke")({
					Color = Computed(function()
						return theme:get().Border
					end),
					Thickness = 1,
					Transparency = 0.4,
				}),
			},
		}))
	end

	return Primitives.Surface({
		Name = "AetherColorPicker",
		Size = props.Size or UDim2.new(1, 0, 0, 0),
		AutomaticSize = Enum.AutomaticSize.Y,
		LayoutOrder = props.LayoutOrder,
		Parent = props.Parent,
		Padding = 12,
		[Children] = {
			New("UIListLayout")({
				FillDirection = Enum.FillDirection.Vertical,
				Padding = UDim.new(0, 10),
				SortOrder = Enum.SortOrder.LayoutOrder,
			}),
			svSquare,
			hueBar,
			New("Frame")({
				Name = "HexRow",
				Size = UDim2.new(1, 0, 0, 32),
				BackgroundTransparency = 1,
				LayoutOrder = 3,
				[Children] = {
					New("UIListLayout")({
						FillDirection = Enum.FillDirection.Horizontal,
						Padding = UDim.new(0, 6),
						VerticalAlignment = Enum.VerticalAlignment.Center,
					}),
					preview,
					hexBox,
					copyButton,
				},
			}),
			New("Frame")({
				Name = "Presets",
				Size = UDim2.new(1, 0, 0, 24),
				BackgroundTransparency = 1,
				LayoutOrder = 4,
				[Children] = presetChildren,
			}),
		},
	}) :: Frame
end

return ColorPicker

end)

__register("Components.CommandPalette", function(require)
--!strict
--[[
	AetherUI • Components/CommandPalette

	Linear/Raycast-style command palette. Fuzzy search, keyboard navigation,
	grouped commands, shortcut hints. Opens as a centered overlay.

	Usage:
		local palette = CommandPalette({
			Commands = {
				{ Id = "theme", Label = "Toggle theme", Icon = "moon", Group = "General",
				  Shortcut = "Ctrl T", Run = function() ... end },
			},
		})
		palette.Open()          -- or bind to a keybind (Ctrl+K is registered by default)
		palette.Close()
		palette.Destroy()
]]

local UserInputService = game:GetService("UserInputService")

local Fusion = require("Core.Fusion")
local Theme = require("Core.Theme")
local Overlay = require("Core.Overlay")
local Keybinds = require("Core.Keybinds")
local Sound = require("Core.Sound")
local Primitives = require("Components.Primitives")

local New = Fusion.New
local Children = Fusion.Children
local Computed = Fusion.Computed
local Value = Fusion.Value
local ForValues = Fusion.ForValues
local OnEvent = Fusion.OnEvent
local Tween = Fusion.Tween
local Spring = Fusion.Spring

local WIDTH = 560
local ROW = 44
local MAX_VISIBLE = 8

-- Simple subsequence fuzzy match with scoring (lower = better).
local function fuzzyScore(query: string, target: string): number?
	query = string.lower(query)
	target = string.lower(target)
	if query == "" then
		return 0
	end
	local qi = 1
	local score = 0
	local lastMatch = 0
	for ti = 1, #target do
		if qi > #query then
			break
		end
		if string.sub(target, ti, ti) == string.sub(query, qi, qi) then
			score += if lastMatch > 0 then (ti - lastMatch - 1) else ti - 1
			lastMatch = ti
			qi += 1
		end
	end
	if qi <= #query then
		return nil -- not all query chars matched
	end
	return score
end

return function(props: { [string]: any })
	local commands: { { [string]: any } } = props.Commands or {}

	local open = Value(false)
	local query = Value("")
	local highlighted = Value(1)

	local results = Computed(function()
		local q = query:get()
		local scored = {}
		for _, cmd in commands do
			local score = fuzzyScore(q, cmd.Label .. " " .. (cmd.Group or ""))
			if score ~= nil then
				table.insert(scored, { Score = score, Cmd = cmd })
			end
		end
		table.sort(scored, function(a, b)
			return a.Score < b.Score
		end)
		local out = {}
		for i, entry in scored do
			entry.Cmd.__order = i
			table.insert(out, entry.Cmd)
		end
		return out
	end)

	local function close()
		open:set(false)
		query:set("")
		highlighted:set(1)
	end

	local function runHighlighted()
		local list = results:get()
		local cmd = list[highlighted:get()]
		if cmd then
			close()
			Sound.Play("Success")
			if cmd.Run then
				cmd.Run()
			end
		end
	end

	-- Input box ------------------------------------------------------------------

	local inputBox: TextBox

	inputBox = New("TextBox")({
		Name = "Query",
		Size = UDim2.new(1, -44, 1, 0),
		Position = UDim2.fromOffset(40, 0),
		BackgroundTransparency = 1,
		PlaceholderText = props.Placeholder or "Type a command or search...",
		PlaceholderColor3 = Computed(function()
			return Theme.Colors.TextDim:get()
		end),
		Text = "",
		TextSize = 15,
		FontFace = Computed(function()
			return Theme.Fonts.Body:get()
		end),
		TextColor3 = Computed(function()
			return Theme.Colors.Text:get()
		end),
		TextXAlignment = Enum.TextXAlignment.Left,
		ClearTextOnFocus = false,
	}) :: TextBox

	inputBox:GetPropertyChangedSignal("Text"):Connect(function()
		query:set(inputBox.Text)
		highlighted:set(1)
	end)

	-- Rows -----------------------------------------------------------------------------

	local listFrame = New("ScrollingFrame")({
		Name = "Results",
		Size = Computed(function()
			local count = math.min(#results:get(), MAX_VISIBLE)
			return UDim2.new(1, 0, 0, math.max(count, 1) * ROW)
		end),
		CanvasSize = Computed(function()
			return UDim2.new(0, 0, 0, #results:get() * ROW)
		end),
		BackgroundTransparency = 1,
		ScrollBarThickness = 3,
		ScrollBarImageColor3 = Computed(function()
			return Theme.Colors.Border:get()
		end),
		BorderSizePixel = 0,
		LayoutOrder = 3,
		[Children] = {
			New("UIListLayout")({ SortOrder = Enum.SortOrder.LayoutOrder }),
			ForValues(results, function(cmd: { [string]: any })
				local index = cmd.__order :: number
				local isHighlighted = Computed(function()
					return highlighted:get() == index
				end)

				local rowContent: { any } = {
					Primitives.Padding({ Left = 14, Right = 14 }),
					Primitives.List({ Direction = "Horizontal", Padding = 10, VerticalAlignment = Enum.VerticalAlignment.Center }),
				}

				if cmd.Icon then
					table.insert(rowContent, Primitives.Icon({
						Name = cmd.Icon,
						Size = 16,
						Color = Computed(function()
							return if isHighlighted:get()
								then Theme.Colors.Primary:get()
								else Theme.Colors.TextMuted:get()
						end),
						LayoutOrder = 1,
					}))
				end

				table.insert(rowContent, Primitives.Text({
					Text = cmd.Label,
					Size = 13,
					Color = Computed(function()
						return if isHighlighted:get()
							then Theme.Colors.Text:get()
							else Theme.Colors.TextMuted:get()
					end),
					LayoutOrder = 2,
				}))

				if cmd.Group then
					table.insert(rowContent, Primitives.Text({
						Text = cmd.Group,
						Size = 11,
						Muted = true,
						LayoutOrder = 3,
					}))
				end

				if cmd.Shortcut then
					table.insert(rowContent, New("Frame")({
						Name = "Shortcut",
						AutomaticSize = Enum.AutomaticSize.XY,
						BackgroundColor3 = Computed(function()
							return Theme.Colors.SurfaceHigh:get()
						end),
						LayoutOrder = 4,
						[Children] = {
							Primitives.Corner("Sm"),
							Primitives.Padding({ X = 6, Y = 3 }),
							Primitives.Text({
								Text = cmd.Shortcut,
								Size = 10,
								Font = "Mono",
								Muted = true,
							}),
						},
					}))
				end

				return New("TextButton")({
					Name = "Cmd_" .. (cmd.Id or index),
					Size = UDim2.new(1, 0, 0, ROW),
					BackgroundColor3 = Computed(function()
						return Theme.Colors.SurfaceHover:get()
					end),
					BackgroundTransparency = Computed(function()
						return if isHighlighted:get() then 0.3 else 1
					end),
					Text = "",
					AutoButtonColor = false,
					LayoutOrder = index,
					[OnEvent("MouseEnter")] = function()
						highlighted:set(index)
					end,
					[OnEvent("Activated")] = function()
						highlighted:set(index)
						runHighlighted()
					end,
					[Children] = rowContent,
				})
			end, Fusion.cleanup),
		},
	})

	-- Panel ----------------------------------------------------------------------------------

	local panelScale = Computed(function()
		return if open:get() then 1 else 0.96
	end)

	local panel = New("Frame")({
		Name = "Panel",
		AnchorPoint = Vector2.new(0.5, 0),
		Position = UDim2.new(0.5, 0, 0.22, 0),
		AutomaticSize = Enum.AutomaticSize.Y,
		Size = UDim2.fromOffset(WIDTH, 0),
		BackgroundColor3 = Computed(function()
			return Theme.Colors.Surface:get()
		end),
		ZIndex = 100,
		[Children] = {
			Primitives.Corner("Xl"),
			Primitives.Stroke(),
			Primitives.Shadow({ Size = 40 }),
			New("UIScale")({ Scale = Spring(panelScale, 30, 0.9) }),
			New("UIListLayout")({ SortOrder = Enum.SortOrder.LayoutOrder }),
			-- Search row
			New("Frame")({
				Name = "SearchRow",
				Size = UDim2.new(1, 0, 0, 52),
				BackgroundTransparency = 1,
				LayoutOrder = 1,
				[Children] = {
					Primitives.Padding({ Left = 16, Right = 16 }),
					Primitives.Icon({
						Name = "search",
						Size = 16,
						Color = Computed(function()
							return Theme.Colors.TextMuted:get()
						end),
						Position = UDim2.new(0, 0, 0.5, 0),
						AnchorPoint = Vector2.new(0, 0.5),
					}),
					inputBox,
				},
			}),
			New("Frame")({
				Name = "Divider",
				Size = UDim2.new(1, 0, 0, 1),
				BackgroundColor3 = Computed(function()
					return Theme.Colors.Border:get()
				end),
				BorderSizePixel = 0,
				LayoutOrder = 2,
			}),
			listFrame,
			-- Footer hints
			New("Frame")({
				Name = "Hints",
				Size = UDim2.new(1, 0, 0, 34),
				BackgroundTransparency = 1,
				LayoutOrder = 4,
				[Children] = {
					Primitives.Padding({ X = 14 }),
					Primitives.List({ Direction = "Horizontal", Padding = 14, VerticalAlignment = Enum.VerticalAlignment.Center }),
					Primitives.Text({ Text = "↑↓ Navigate", Size = 10, Muted = true, LayoutOrder = 1 }),
					Primitives.Text({ Text = "↵ Run", Size = 10, Muted = true, LayoutOrder = 2 }),
					Primitives.Text({ Text = "Esc Close", Size = 10, Muted = true, LayoutOrder = 3 }),
				},
			}),
		},
	})

	-- Backdrop + mount -----------------------------------------------------------------------

	local backdrop = New("TextButton")({
		Name = "AetherCommandPalette",
		Size = UDim2.fromScale(1, 1),
		BackgroundColor3 = Color3.new(0, 0, 0),
		BackgroundTransparency = Tween(
			Computed(function()
				return if open:get() then 0.45 else 1
			end),
			TweenInfo.new(0.18, Enum.EasingStyle.Quad, Enum.EasingDirection.Out)
		),
		Text = "",
		AutoButtonColor = false,
		Visible = open,
		ZIndex = 99,
		[OnEvent("Activated")] = function()
			close()
		end,
		[Children] = { panel },
	})

	backdrop.Parent = Overlay.getLayer("Palette", 400)

	-- Keyboard navigation ---------------------------------------------------------------------

	local navConnection = UserInputService.InputBegan:Connect(function(input, _processed)
		if not open:get() then
			return
		end
		if input.KeyCode == Enum.KeyCode.Down then
			highlighted:set(math.min(highlighted:get() + 1, #results:get()))
		elseif input.KeyCode == Enum.KeyCode.Up then
			highlighted:set(math.max(highlighted:get() - 1, 1))
		elseif input.KeyCode == Enum.KeyCode.Return then
			runHighlighted()
		elseif input.KeyCode == Enum.KeyCode.Escape then
			close()
		end
	end)

	-- Default hotkey: Ctrl+K
	local hotkeyId = "AetherUI_CommandPalette_" .. tostring(math.random(1, 1e9))
	if props.Hotkey ~= false then
		Keybinds.Register(hotkeyId, {
			Key = props.Hotkey or Enum.KeyCode.K,
			Modifiers = { "Ctrl" },
			Callback = function()
				open:set(not open:get())
				if open:get() then
					task.defer(function()
						inputBox:CaptureFocus()
					end)
				end
			end,
		})
	end

	-- Public API --------------------------------------------------------------------------------

	local api = {}

	function api.Open()
		open:set(true)
		Sound.Play("Open")
		task.defer(function()
			inputBox:CaptureFocus()
		end)
	end

	function api.Close()
		close()
	end

	api.IsOpen = open

	function api.Destroy()
		navConnection:Disconnect()
		if props.Hotkey ~= false then
			Keybinds.Unregister(hotkeyId)
		end
		backdrop:Destroy()
	end

	return api
end

end)

__register("Components.ContextMenu", function(require)
--!strict
--[=[
	AetherUI · ContextMenu
	Right-click (or programmatic) menus with icons, shortcuts, separators,
	destructive items and nested submenus.

		ContextMenu.attach(frame, {
			{ Label = "Rename", Icon = "pencil", OnClick = ... },
			{ Separator = true },
			{ Label = "Delete", Icon = "trash-2", Destructive = true, OnClick = ... },
		})
]=]

local Fusion = require("Core.Fusion")
local Theme = require("Core.Theme")
local Icons = require("Core.Icons")
local Sound = require("Core.Sound")
local Overlay = require("Core.Overlay")

local New = Fusion.New
local Children = Fusion.Children
local Value = Fusion.Value
local Computed = Fusion.Computed
local OnEvent = Fusion.OnEvent
local Spring = Fusion.Spring

local UserInputService = game:GetService("UserInputService")
local GuiService = game:GetService("GuiService")

type MenuItem = {
	Label: string?,
	Icon: string?,
	Shortcut: string?,
	Destructive: boolean?,
	Disabled: boolean?,
	Separator: boolean?,
	OnClick: (() -> ())?,
	Items: { MenuItem }?, -- submenu
}

local ContextMenu = {}

local activeMenu: Frame? = nil
local dismissConn: RBXScriptConnection? = nil

local function closeActive()
	if activeMenu then
		activeMenu:Destroy()
		activeMenu = nil
	end
	if dismissConn then
		dismissConn:Disconnect()
		dismissConn = nil
	end
end

local MENU_WIDTH = 200

local function buildMenu(items: { MenuItem }, position: Vector2, depth: number): Frame
	local theme = Theme.Current
	local layer = Overlay.getLayer("Menus", 250)
	local visible = Value(false)

	local rows: { Instance } = {
		New("UIListLayout")({
			FillDirection = Enum.FillDirection.Vertical,
			Padding = UDim.new(0, 2),
			SortOrder = Enum.SortOrder.LayoutOrder,
		}),
		New("UIPadding")({
			PaddingLeft = UDim.new(0, 4),
			PaddingRight = UDim.new(0, 4),
			PaddingTop = UDim.new(0, 4),
			PaddingBottom = UDim.new(0, 4),
		}),
	}

	local openSubmenu: Frame? = nil

	for i, item in ipairs(items) do
		if item.Separator then
			table.insert(rows, New("Frame")({
				Size = UDim2.new(1, 0, 0, 1),
				BackgroundColor3 = Computed(function()
					return theme:get().Border
				end),
				BorderSizePixel = 0,
				LayoutOrder = i,
			}))
			continue
		end

		local hovered = Value(false)

		local rowChildren: { Instance } = {
			New("UIListLayout")({
				FillDirection = Enum.FillDirection.Horizontal,
				Padding = UDim.new(0, 8),
				VerticalAlignment = Enum.VerticalAlignment.Center,
			}),
			New("UIPadding")({ PaddingLeft = UDim.new(0, 8), PaddingRight = UDim.new(0, 8) }),
		}

		local itemColor = Computed(function()
			local t = theme:get()
			if item.Disabled then
				return t.TextDisabled
			end
			return item.Destructive and t.Danger or t.Text
		end)

		if item.Icon then
			table.insert(rowChildren, Icons.render(item.Icon, {
				Size = UDim2.fromOffset(14, 14),
				LayoutOrder = 1,
				Color = itemColor,
			}))
		end

		table.insert(rowChildren, New("TextLabel")({
			Size = UDim2.new(1, item.Icon and -70 or -48, 1, 0),
			BackgroundTransparency = 1,
			Text = item.Label or "",
			Font = Enum.Font.GothamMedium,
			TextSize = 12,
			TextColor3 = itemColor,
			TextXAlignment = Enum.TextXAlignment.Left,
			LayoutOrder = 2,
		}))

		if item.Shortcut then
			table.insert(rowChildren, New("TextLabel")({
				AutomaticSize = Enum.AutomaticSize.XY,
				BackgroundTransparency = 1,
				Text = item.Shortcut,
				Font = Enum.Font.RobotoMono,
				TextSize = 10,
				TextColor3 = Computed(function()
					return theme:get().TextMuted
				end),
				LayoutOrder = 3,
			}))
		elseif item.Items then
			table.insert(rowChildren, Icons.render("chevron-right", {
				Size = UDim2.fromOffset(12, 12),
				LayoutOrder = 3,
				Color = Computed(function()
					return theme:get().TextMuted
				end),
			}))
		end

		local row: TextButton
		row = New("TextButton")({
			Name = "Item_" .. i,
			Size = UDim2.new(1, 0, 0, 30),
			Text = "",
			AutoButtonColor = false,
			LayoutOrder = i,
			BackgroundColor3 = Computed(function()
				local t = theme:get()
				return item.Destructive and t.Danger or t.SurfaceHigh
			end),
			BackgroundTransparency = Spring(Computed(function()
				if item.Disabled then
					return 1
				end
				return Fusion.peek(hovered) and (item.Destructive and 0.85 or 0.4) or 1
			end), 40, 1),
			[OnEvent("MouseEnter")] = function()
				if item.Disabled then
					return
				end
				hovered:set(true)
				Sound.play("Hover")
				if openSubmenu then
					openSubmenu:Destroy()
					openSubmenu = nil
				end
				if item.Items then
					local abs = row.AbsolutePosition
					openSubmenu = buildMenu(item.Items, Vector2.new(abs.X + MENU_WIDTH, abs.Y), depth + 1)
				end
			end,
			[OnEvent("MouseLeave")] = function()
				hovered:set(false)
			end,
			[OnEvent("Activated")] = function()
				if item.Disabled or item.Items then
					return
				end
				Sound.play("Click")
				closeActive()
				if item.OnClick then
					item.OnClick()
				end
			end,
			[Children] = {
				New("UICorner")({ CornerRadius = UDim.new(0, 6) }),
				New("Frame")({
					Size = UDim2.fromScale(1, 1),
					BackgroundTransparency = 1,
					[Children] = rowChildren,
				}),
			},
		}) :: TextButton

		table.insert(rows, row)
	end

	-- clamp to screen
	local camera = workspace.CurrentCamera
	local vp = camera and camera.ViewportSize or Vector2.new(1920, 1080)
	local x = math.min(position.X, vp.X - MENU_WIDTH - 8)
	local estHeight = #items * 32 + 8
	local y = math.min(position.Y, vp.Y - estHeight - 8)

	local menu = New("Frame")({
		Name = "AetherContextMenu_" .. depth,
		Position = UDim2.fromOffset(x, y),
		Size = UDim2.fromOffset(MENU_WIDTH, 0),
		AutomaticSize = Enum.AutomaticSize.Y,
		BackgroundColor3 = Computed(function()
			return theme:get().Surface
		end),
		BackgroundTransparency = Spring(Computed(function()
			return Fusion.peek(visible) and 0 or 1
		end), 45, 1),
		ZIndex = 251 + depth,
		Parent = layer,
		[Children] = {
			New("UICorner")({ CornerRadius = Computed(function()
				return UDim.new(0, theme:get().RadiusMd)
			end) }),
			New("UIStroke")({
				Color = Computed(function()
					return theme:get().Border
				end),
				Thickness = 1,
			}),
			New("Frame")({
				Size = UDim2.new(1, 0, 0, 0),
				AutomaticSize = Enum.AutomaticSize.Y,
				BackgroundTransparency = 1,
				[Children] = rows,
			}),
		},
	}) :: Frame

	task.defer(function()
		visible:set(true)
	end)
	return menu
end

--- Opens a menu at a screen position (programmatic use).
function ContextMenu.open(items: { MenuItem }, position: Vector2?)
	closeActive()
	local pos = position
	if not pos then
		local mouse = UserInputService:GetMouseLocation()
		local inset = GuiService:GetGuiInset()
		pos = Vector2.new(mouse.X, mouse.Y - inset.Y)
	end
	Sound.play("Open")
	activeMenu = buildMenu(items, pos :: Vector2, 0)

	-- Dismiss on any click outside
	task.defer(function()
		dismissConn = UserInputService.InputBegan:Connect(function(input)
			if input.UserInputType == Enum.UserInputType.MouseButton1
				or input.UserInputType == Enum.UserInputType.MouseButton2
				or input.UserInputType == Enum.UserInputType.Touch then
				local menu = activeMenu
				if menu then
					local mouse = UserInputService:GetMouseLocation()
					local inset = GuiService:GetGuiInset()
					local mx, my = mouse.X, mouse.Y - inset.Y
					local pos2 = menu.AbsolutePosition
					local size = menu.AbsoluteSize
					if mx < pos2.X or mx > pos2.X + size.X or my < pos2.Y or my > pos2.Y + size.Y then
						closeActive()
					end
				end
			end
		end)
	end)
end

--- Attaches a right-click menu to a GuiObject. Returns a detach function.
function ContextMenu.attach(target: GuiObject, items: { MenuItem }): () -> ()
	local conn = target.InputBegan:Connect(function(input)
		if input.UserInputType == Enum.UserInputType.MouseButton2 then
			ContextMenu.open(items)
		end
	end)
	return function()
		conn:Disconnect()
		closeActive()
	end
end

function ContextMenu.close()
	closeActive()
end

--- PascalCase alias. Accepts either an items array or `{ Items = { ... } }`.
function ContextMenu.Attach(target: GuiObject, itemsOrOptions: { MenuItem } | { Items: { MenuItem } }): () -> ()
	local items = (itemsOrOptions :: any).Items or itemsOrOptions
	return ContextMenu.attach(target, items :: { MenuItem })
end

ContextMenu.Open = ContextMenu.open
ContextMenu.Close = ContextMenu.close

return ContextMenu

end)

__register("Components.DataTable", function(require)
--!strict
--[[
	AetherUI • Components/DataTable

	Sortable, filterable, paginated data table with row actions.

	props:
		Columns: { { Key: string, Label: string, Width: number?, Sortable: boolean?, Format: ((any) -> string)? } }
		Rows: { { [string]: any } } | Fusion Value
		PageSize: number?           (default 10)
		Searchable: boolean?        (adds a search input, filters all columns)
		Actions: { { Icon: string, Tooltip: string?, OnClick: (row) -> () } }?
		OnRowClick: ((row: { [string]: any }) -> ())?
		Size: UDim2?                LayoutOrder: number?    Parent: Instance?
]]

local Fusion = require("Core.Fusion")
local Theme = require("Core.Theme")
local Utils = require("Core.Utils")
local Primitives = require("Components.Primitives")
local Button = require("Components.Button")
local TextInput = require("Components.TextInput")

local New = Fusion.New
local Children = Fusion.Children
local Computed = Fusion.Computed
local Value = Fusion.Value
local ForValues = Fusion.ForValues
local OnEvent = Fusion.OnEvent

local ROW_HEIGHT = 40
local HEADER_HEIGHT = 38

local function asState(value: any): any
	if type(value) == "table" and type(value.get) == "function" then
		return value
	end
	return Value(value or {})
end

return function(props: { [string]: any }): Frame
	local columns: { { [string]: any } } = props.Columns or {}
	local rows = asState(props.Rows)
	local pageSize: number = props.PageSize or 10

	local sortKey = Value(nil :: string?)
	local sortAsc = Value(true)
	local page = Value(1)
	local search = Value("")

	-- Derived pipeline: filter -> sort -> paginate --------------------------------

	local filtered = Computed(function()
		local all: { { [string]: any } } = rows:get()
		local query = string.lower(search:get())
		if query == "" then
			return all
		end
		return Utils.Filter(all, function(row)
			for _, col in columns do
				local cell = row[col.Key]
				if cell ~= nil and string.find(string.lower(tostring(cell)), query, 1, true) then
					return true
				end
			end
			return false
		end)
	end)

	local sorted = Computed(function()
		local list = table.clone(filtered:get())
		local key = sortKey:get()
		if key ~= nil then
			local asc = sortAsc:get()
			table.sort(list, function(a, b)
				local av, bv = a[key], b[key]
				if type(av) == "number" and type(bv) == "number" then
					return if asc then av < bv else av > bv
				end
				return if asc
					then tostring(av) < tostring(bv)
					else tostring(av) > tostring(bv)
			end)
		end
		return list
	end)

	local pageCount = Computed(function()
		return math.max(1, math.ceil(#sorted:get() / pageSize))
	end)

	local pageRows = Computed(function()
		local list = sorted:get()
		local p = math.clamp(page:get(), 1, math.max(1, math.ceil(#list / pageSize)))
		local out = {}
		for i = (p - 1) * pageSize + 1, math.min(p * pageSize, #list) do
			table.insert(out, { Index = i, Row = list[i] })
		end
		return out
	end)

	-- Column width resolution ------------------------------------------------------

	local flexCount = 0
	local fixedTotal = 0
	for _, col in columns do
		if col.Width then
			fixedTotal += col.Width
		else
			flexCount += 1
		end
	end
	local actionsWidth = if props.Actions and #props.Actions > 0 then #props.Actions * 32 + 8 else 0

	local function columnSize(col: { [string]: any }): UDim2
		if col.Width then
			return UDim2.new(0, col.Width, 1, 0)
		end
		return UDim2.new(1 / math.max(flexCount, 1), -math.floor((fixedTotal + actionsWidth) / math.max(flexCount, 1)), 1, 0)
	end

	-- Header ------------------------------------------------------------------------

	local headerCells: { any } = {
		Primitives.List({ Direction = "Horizontal", Padding = 0, VerticalAlignment = Enum.VerticalAlignment.Center }),
		Primitives.Padding({ Left = 12, Right = 12 }),
	}

	for order, col in columns do
		local isSorted = Computed(function()
			return sortKey:get() == col.Key
		end)
		table.insert(headerCells, New("TextButton")({
			Name = "Head_" .. col.Key,
			Size = columnSize(col),
			BackgroundTransparency = 1,
			Text = "",
			AutoButtonColor = false,
			LayoutOrder = order,
			[OnEvent("Activated")] = function()
				if col.Sortable == false then
					return
				end
				if sortKey:get() == col.Key then
					sortAsc:set(not sortAsc:get())
				else
					sortKey:set(col.Key)
					sortAsc:set(true)
				end
			end,
			[Children] = {
				Primitives.List({ Direction = "Horizontal", Padding = 4, VerticalAlignment = Enum.VerticalAlignment.Center }),
				Primitives.Text({
					Text = col.Label or col.Key,
					Size = 11,
					Bold = true,
					Color = Computed(function()
						return if isSorted:get() then Theme.Colors.Text:get() else Theme.Colors.TextMuted:get()
					end),
					LayoutOrder = 1,
				}),
				Primitives.Icon({
					Name = "chevron-up",
					Size = 12,
					Color = Computed(function()
						return Theme.Colors.TextMuted:get()
					end),
					Transparency = Computed(function()
						return if isSorted:get() then 0 else 1
					end),
					Rotation = Computed(function()
						return if sortAsc:get() then 0 else 180
					end),
					LayoutOrder = 2,
				}),
			},
		}))
	end

	if actionsWidth > 0 then
		table.insert(headerCells, New("Frame")({
			Name = "Head_Actions",
			Size = UDim2.new(0, actionsWidth, 1, 0),
			BackgroundTransparency = 1,
			LayoutOrder = #columns + 1,
		}))
	end

	local header = New("Frame")({
		Name = "Header",
		Size = UDim2.new(1, 0, 0, HEADER_HEIGHT),
		BackgroundColor3 = Computed(function()
			return Theme.Colors.SurfaceHigh:get()
		end),
		LayoutOrder = 2,
		[Children] = headerCells,
	})

	-- Rows ----------------------------------------------------------------------------

	local body = New("Frame")({
		Name = "Body",
		AutomaticSize = Enum.AutomaticSize.Y,
		Size = UDim2.new(1, 0, 0, 0),
		BackgroundTransparency = 1,
		LayoutOrder = 3,
		[Children] = {
			Primitives.List({ Padding = 0 }),
			ForValues(pageRows, function(entry: { [string]: any })
				local row = entry.Row
				local hovering = Value(false)

				local cells: { any } = {
					Primitives.List({ Direction = "Horizontal", Padding = 0, VerticalAlignment = Enum.VerticalAlignment.Center }),
					Primitives.Padding({ Left = 12, Right = 12 }),
					New("Frame")({
						Name = "Divider",
						Size = UDim2.new(1, 0, 0, 1),
						Position = UDim2.new(0, 0, 1, -1),
						BackgroundColor3 = Computed(function()
							return Theme.Colors.Border:get()
						end),
						BackgroundTransparency = 0.5,
						BorderSizePixel = 0,
					}),
				}

				for order, col in columns do
					local cell = row[col.Key]
					local text = if col.Format then col.Format(cell) else tostring(cell == nil and "—" or cell)
					table.insert(cells, New("Frame")({
						Name = "Cell_" .. col.Key,
						Size = columnSize(col),
						BackgroundTransparency = 1,
						LayoutOrder = order,
						[Children] = {
							Primitives.Text({
								Text = text,
								Size = 12,
								Props = {
									Size = UDim2.fromScale(1, 1),
									TextTruncate = Enum.TextTruncate.AtEnd,
									TextXAlignment = Enum.TextXAlignment.Left,
								},
							}),
						},
					}))
				end

				if props.Actions and #props.Actions > 0 then
					local actionButtons: { any } = {
						Primitives.List({ Direction = "Horizontal", Padding = 4, VerticalAlignment = Enum.VerticalAlignment.Center, HorizontalAlignment = Enum.HorizontalAlignment.Right }),
					}
					for aOrder, action in props.Actions :: { { [string]: any } } do
						table.insert(actionButtons, Button({
							Icon = action.Icon,
							Variant = "Ghost",
							Size = "Sm",
							LayoutOrder = aOrder,
							OnClick = function()
								action.OnClick(row)
							end,
						}))
					end
					table.insert(cells, New("Frame")({
						Name = "Cell_Actions",
						Size = UDim2.new(0, actionsWidth, 1, 0),
						BackgroundTransparency = 1,
						LayoutOrder = #columns + 1,
						[Children] = actionButtons,
					}))
				end

				return New("TextButton")({
					Name = "Row_" .. entry.Index,
					Size = UDim2.new(1, 0, 0, ROW_HEIGHT),
					BackgroundColor3 = Computed(function()
						return Theme.Colors.SurfaceHover:get()
					end),
					BackgroundTransparency = Computed(function()
						return if hovering:get() and props.OnRowClick then 0.5 else 1
					end),
					Text = "",
					AutoButtonColor = false,
					LayoutOrder = entry.Index,
					[OnEvent("MouseEnter")] = function()
						hovering:set(true)
					end,
					[OnEvent("MouseLeave")] = function()
						hovering:set(false)
					end,
					[OnEvent("Activated")] = function()
						if props.OnRowClick then
							props.OnRowClick(row)
						end
					end,
					[Children] = cells,
				})
			end, Fusion.cleanup),
		},
	})

	-- Toolbar (search) ------------------------------------------------------------------

	local toolbar: Instance? = nil
	if props.Searchable then
		toolbar = New("Frame")({
			Name = "Toolbar",
			Size = UDim2.new(1, 0, 0, 48),
			BackgroundTransparency = 1,
			LayoutOrder = 1,
			[Children] = {
				Primitives.Padding({ X = 12, Y = 8 }),
				TextInput({
					Placeholder = "Search...",
					Icon = "search",
					Clearable = true,
					Value = search,
					OnChanged = function(text: string)
						search:set(text)
						page:set(1)
					end,
					Props = { Size = UDim2.new(0, 240, 0, 32) },
				}),
			},
		})
	end

	-- Pagination footer --------------------------------------------------------------------

	local footer = New("Frame")({
		Name = "Footer",
		Size = UDim2.new(1, 0, 0, 48),
		BackgroundTransparency = 1,
		LayoutOrder = 4,
		[Children] = {
			Primitives.Padding({ X = 12 }),
			Primitives.Text({
				Text = Computed(function()
					local total = #sorted:get()
					local p = page:get()
					local from = math.min((p - 1) * pageSize + 1, total)
					local to = math.min(p * pageSize, total)
					return if total == 0 then "No results" else `{from}–{to} of {total}`
				end),
				Size = 12,
				Muted = true,
				Props = {
					Size = UDim2.new(0.5, 0, 1, 0),
					TextXAlignment = Enum.TextXAlignment.Left,
				},
			}),
			New("Frame")({
				Name = "Pager",
				AnchorPoint = Vector2.new(1, 0.5),
				Position = UDim2.new(1, -12, 0.5, 0),
				AutomaticSize = Enum.AutomaticSize.XY,
				BackgroundTransparency = 1,
				[Children] = {
					Primitives.List({ Direction = "Horizontal", Padding = 6, VerticalAlignment = Enum.VerticalAlignment.Center }),
					Button({
						Icon = "chevron-left",
						Variant = "Outline",
						Size = "Sm",
						LayoutOrder = 1,
						OnClick = function()
							page:set(math.max(1, page:get() - 1))
						end,
					}),
					Primitives.Text({
						Text = Computed(function()
							return `{page:get()} / {pageCount:get()}`
						end),
						Size = 12,
						Muted = true,
						LayoutOrder = 2,
					}),
					Button({
						Icon = "chevron-right",
						Variant = "Outline",
						Size = "Sm",
						LayoutOrder = 3,
						OnClick = function()
							page:set(math.min(pageCount:get(), page:get() + 1))
						end,
					}),
				},
			}),
		},
	})

	-- Container --------------------------------------------------------------------------------

	local content: { any } = {
		Primitives.Corner("Lg"),
		Primitives.Stroke(),
		New("UIListLayout")({
			SortOrder = Enum.SortOrder.LayoutOrder,
		}),
		header,
		body,
		footer,
	}
	if toolbar then
		table.insert(content, toolbar)
	end

	return New("Frame")({
		Name = "AetherDataTable",
		AutomaticSize = Enum.AutomaticSize.Y,
		Size = props.Size or UDim2.new(1, 0, 0, 0),
		BackgroundColor3 = Computed(function()
			return Theme.Colors.Surface:get()
		end),
		ClipsDescendants = true,
		LayoutOrder = props.LayoutOrder,
		Parent = props.Parent,
		[Children] = content,
	})
end

end)

__register("Components.DatePicker", function(require)
--!strict
--[[
	AetherUI • Components/DatePicker

	Calendar month grid with year/month navigation.

	props:
		Value: { Year: number, Month: number, Day: number }?   (defaults to today)
		OnChanged: ((date: { Year: number, Month: number, Day: number }) -> ())?
		LayoutOrder: number?    Parent: Instance?
]]

local Fusion = require("Core.Fusion")
local Theme = require("Core.Theme")
local Primitives = require("Components.Primitives")
local Button = require("Components.Button")

local New = Fusion.New
local Children = Fusion.Children
local Computed = Fusion.Computed
local Value = Fusion.Value
local ForValues = Fusion.ForValues
local OnEvent = Fusion.OnEvent

local MONTHS = {
	"January", "February", "March", "April", "May", "June",
	"July", "August", "September", "October", "November", "December",
}
local WEEKDAYS = { "Su", "Mo", "Tu", "We", "Th", "Fr", "Sa" }

local CELL = 34
local GRID_PAD = 12

local function daysInMonth(year: number, month: number): number
	local next = os.time({ year = if month == 12 then year + 1 else year, month = if month == 12 then 1 else month + 1, day = 1 }) - 86400
	return tonumber(os.date("%d", next)) :: number
end

local function firstWeekday(year: number, month: number): number
	-- 1 = Sunday
	return tonumber(os.date("%w", os.time({ year = year, month = month, day = 1 }))) :: number + 1
end

return function(props: { [string]: any }): Frame
	local today = os.date("*t")
	local initial = props.Value or { Year = today.year, Month = today.month, Day = today.day }

	local viewYear = Value(initial.Year)
	local viewMonth = Value(initial.Month)
	local selected = Value(initial)

	local function shiftMonth(delta: number)
		local m = viewMonth:get() + delta
		local y = viewYear:get()
		if m < 1 then
			m, y = 12, y - 1
		elseif m > 12 then
			m, y = 1, y + 1
		end
		viewMonth:set(m)
		viewYear:set(y)
	end

	-- Day cells for the visible month --------------------------------------------

	local cells = Computed(function()
		local year = viewYear:get()
		local month = viewMonth:get()
		local offset = firstWeekday(year, month) - 1
		local total = daysInMonth(year, month)
		local out = {}
		for day = 1, total do
			local slot = offset + day - 1
			table.insert(out, {
				Day = day,
				Column = slot % 7,
				Row = math.floor(slot / 7),
			})
		end
		return out
	end)

	local rowCount = Computed(function()
		local list = cells:get()
		local last = list[#list]
		return if last then last.Row + 1 else 5
	end)

	-- Header ------------------------------------------------------------------------

	local header = New("Frame")({
		Name = "Header",
		Size = UDim2.new(1, 0, 0, 44),
		BackgroundTransparency = 1,
		LayoutOrder = 1,
		[Children] = {
			Primitives.Padding({ X = 8 }),
			Button({
				Icon = "chevron-left",
				Variant = "Ghost",
				Size = "Sm",
				Props = { AnchorPoint = Vector2.new(0, 0.5), Position = UDim2.new(0, 0, 0.5, 0) },
				OnClick = function()
					shiftMonth(-1)
				end,
			}),
			Primitives.Text({
				Text = Computed(function()
					return `{MONTHS[viewMonth:get()]} {viewYear:get()}`
				end),
				Size = 14,
				Bold = true,
				Props = {
					AnchorPoint = Vector2.new(0.5, 0.5),
					Position = UDim2.fromScale(0.5, 0.5),
				},
			}),
			Button({
				Icon = "chevron-right",
				Variant = "Ghost",
				Size = "Sm",
				Props = { AnchorPoint = Vector2.new(1, 0.5), Position = UDim2.new(1, 0, 0.5, 0) },
				OnClick = function()
					shiftMonth(1)
				end,
			}),
		},
	})

	-- Weekday labels -------------------------------------------------------------------

	local weekdayLabels: { any } = {}
	for i, wd in WEEKDAYS do
		table.insert(weekdayLabels, Primitives.Text({
			Text = wd,
			Size = 10,
			Muted = true,
			Props = {
				Size = UDim2.fromOffset(CELL, 16),
				Position = UDim2.fromOffset(GRID_PAD + (i - 1) * CELL, 0),
				TextXAlignment = Enum.TextXAlignment.Center,
			},
		}))
	end

	local weekdayRow = New("Frame")({
		Name = "Weekdays",
		Size = UDim2.new(1, 0, 0, 20),
		BackgroundTransparency = 1,
		LayoutOrder = 2,
		[Children] = weekdayLabels,
	})

	-- Day grid ----------------------------------------------------------------------------

	local grid = New("Frame")({
		Name = "Grid",
		Size = Computed(function()
			return UDim2.new(1, 0, 0, rowCount:get() * CELL + 8)
		end),
		BackgroundTransparency = 1,
		LayoutOrder = 3,
		[Children] = {
			ForValues(cells, function(cell: { [string]: any })
				local isSelected = Computed(function()
					local sel = selected:get()
					return sel.Day == cell.Day
						and sel.Month == viewMonth:get()
						and sel.Year == viewYear:get()
				end)
				local isToday = cell.Day == today.day
					and viewMonth:get() == today.month
					and viewYear:get() == today.year
				local hovering = Value(false)

				return New("TextButton")({
					Name = "Day_" .. cell.Day,
					Size = UDim2.fromOffset(CELL - 4, CELL - 4),
					Position = UDim2.fromOffset(GRID_PAD + cell.Column * CELL + 2, cell.Row * CELL + 2),
					BackgroundColor3 = Computed(function()
						if isSelected:get() then
							return Theme.Colors.Primary:get()
						end
						return Theme.Colors.SurfaceHover:get()
					end),
					BackgroundTransparency = Computed(function()
						if isSelected:get() then
							return 0
						end
						return if hovering:get() then 0.4 else 1
					end),
					Text = tostring(cell.Day),
					TextSize = 12,
					FontFace = Computed(function()
						return Theme.Fonts.Body:get()
					end),
					TextColor3 = Computed(function()
						if isSelected:get() then
							return Theme.Colors.PrimaryText:get()
						end
						if isToday then
							return Theme.Colors.Primary:get()
						end
						return Theme.Colors.Text:get()
					end),
					AutoButtonColor = false,
					[OnEvent("MouseEnter")] = function()
						hovering:set(true)
					end,
					[OnEvent("MouseLeave")] = function()
						hovering:set(false)
					end,
					[OnEvent("Activated")] = function()
						local date = { Year = viewYear:get(), Month = viewMonth:get(), Day = cell.Day }
						selected:set(date)
						if props.OnChanged then
							props.OnChanged(date)
						end
					end,
					[Children] = { Primitives.Corner("Sm") },
				})
			end, Fusion.cleanup),
		},
	})

	return New("Frame")({
		Name = "AetherDatePicker",
		AutomaticSize = Enum.AutomaticSize.Y,
		Size = UDim2.fromOffset(CELL * 7 + GRID_PAD * 2, 0),
		BackgroundColor3 = Computed(function()
			return Theme.Colors.Surface:get()
		end),
		LayoutOrder = props.LayoutOrder,
		Parent = props.Parent,
		[Children] = {
			Primitives.Corner("Lg"),
			Primitives.Stroke(),
			New("UIListLayout")({ SortOrder = Enum.SortOrder.LayoutOrder }),
			header,
			weekdayRow,
			grid,
		},
	})
end

end)

__register("Components.Dropdown", function(require)
--!strict
--[[
	AetherUI • Components/Dropdown
	Single-select dropdown with search, icons, keyboard-friendly close and smooth reveal.

	props:
		Items: { { Label, Value, Icon?, Disabled? } }
		Value: Fusion.Value<any>?      Placeholder: string?
		Searchable: boolean?           OnChanged: (value: any) -> ()?
		FullWidth: boolean?            LayoutOrder
]]

local Fusion = require("Core.Fusion")
local Theme = require("Core.Theme")
local Animation = require("Core.Animation")
local Sound = require("Core.Sound")
local Primitives = require("Components.Primitives")
local UseHover = require("Hooks.UseHover")

local New = Fusion.New
local Children = Fusion.Children
local OnEvent = Fusion.OnEvent
local OnChange = Fusion.OnChange
local Computed = Fusion.Computed
local ForValues = Fusion.ForValues
local Tween = Fusion.Tween
local Value = Fusion.Value

local ROW = 32

return function(props: { [string]: any }): Frame
	local items = props.Items or {}
	local selected = props.Value or Value(nil)
	local open = Value(false)
	local query = Value("")
	local hover = UseHover({ Sound = false })

	local filtered = Computed(function()
		local q = query:get():lower()
		if q == "" then
			return items
		end
		local out = {}
		for _, item in items :: { any } do
			if item.Label:lower():find(q, 1, true) then
				table.insert(out, item)
			end
		end
		return out
	end)

	local selectedLabel = Computed(function()
		local current = selected:get()
		for _, item in items :: { any } do
			if item.Value == current then
				return item.Label
			end
		end
		return props.Placeholder or "Select…"
	end)

	local hasSelection = Computed(function()
		return selected:get() ~= nil
	end)

	local function choose(item: any)
		if item.Disabled then
			return
		end
		selected:set(item.Value)
		open:set(false)
		query:set("")
		Sound.Play("Click")
		if props.OnChanged then
			props.OnChanged(item.Value)
		end
	end

	local listHeight = Computed(function()
		local count = math.min(#filtered:get(), 6)
		local search = if props.Searchable then ROW + 6 else 0
		return if open:get() then count * ROW + 8 + search else 0
	end)

	return New("Frame")({
		Name = "AetherDropdown",
		Parent = props.Parent,
		BackgroundTransparency = 1,
		AutomaticSize = Enum.AutomaticSize.Y,
		Size = if props.FullWidth ~= false then UDim2.new(1, 0, 0, 0) else UDim2.fromOffset(240, 0),
		LayoutOrder = props.LayoutOrder or 0,
		ZIndex = 10,
		[Children] = {
			Primitives.List({ Gap = 4 }),

			-- Trigger
			New("TextButton")({
				Name = "Trigger",
				Text = "",
				AutoButtonColor = false,
				BackgroundColor3 = Tween(
					Computed(function()
						return if hover.Hovering:get() then Theme.Colors.SurfaceHover:get() else Theme.Colors.Surface:get()
					end),
					Animation.Presets.Fast
				),
				Size = UDim2.new(1, 0, 0, 36),
				LayoutOrder = 0,
				[OnEvent("MouseEnter")] = hover.Enter,
				[OnEvent("MouseLeave")] = hover.Leave,
				[OnEvent("Activated")] = function()
					open:set(not open:get())
					Sound.Play(if open:get() then "Open" else "Close")
				end,
				[Children] = {
					Primitives.Corner("Md"),
					Primitives.Stroke({
						Color = Tween(
							Computed(function()
								return if open:get() then Theme.Colors.Primary:get() else Theme.Colors.Border:get()
							end),
							Animation.Presets.Fast
						),
						Transparency = Computed(function()
							return if open:get() then 0 else 0.35
						end),
					}),
					Primitives.Padding({ X = 12 }),
					Primitives.Text({
						Text = selectedLabel,
						Size = "Md",
						Color = Computed(function()
							return if hasSelection:get() then Theme.Colors.Text:get() else Theme.Colors.TextDisabled:get()
						end),
						Props = { Position = UDim2.fromScale(0, 0.5), AnchorPoint = Vector2.new(0, 0.5) },
					}),
					New("Frame")({
						Name = "Chevron",
						BackgroundTransparency = 1,
						Size = UDim2.fromOffset(16, 16),
						Position = UDim2.new(1, 0, 0.5, 0),
						AnchorPoint = Vector2.new(1, 0.5),
						Rotation = Tween(
							Computed(function()
								return if open:get() then 180 else 0
							end),
							Animation.Presets.Normal
						),
						[Children] = {
							Primitives.Icon({ Name = "chevron-down", Size = 16, Color = Theme.Colors.TextMuted }),
						},
					}),
				},
			}),

			-- Menu
			New("Frame")({
				Name = "Menu",
				BackgroundColor3 = Theme.Colors.Elevated,
				ClipsDescendants = true,
				Size = Tween(
					Computed(function()
						return UDim2.new(1, 0, 0, listHeight:get())
					end),
					Animation.Presets.Normal
				),
				LayoutOrder = 1,
				ZIndex = 20,
				Visible = Computed(function()
					return listHeight:get() > 0 or open:get()
				end),
				[Children] = {
					Primitives.Corner("Md"),
					Primitives.Stroke(),
					Primitives.Padding(4),
					Primitives.List({ Gap = 2 }),
					Primitives.Shadow({ Size = 32 }),

					if props.Searchable
						then New("Frame")({
							Name = "Search",
							BackgroundColor3 = Theme.Colors.Surface,
							Size = UDim2.new(1, 0, 0, ROW),
							LayoutOrder = -1,
							[Children] = {
								Primitives.Corner("Sm"),
								Primitives.Padding({ X = 10 }),
								New("TextBox")({
									BackgroundTransparency = 1,
									PlaceholderText = "Search…",
									PlaceholderColor3 = Theme.Colors.TextDisabled,
									Text = "",
									TextColor3 = Theme.Colors.Text,
									FontFace = Theme.Fonts.Body,
									TextSize = Theme.TextSizes.Sm,
									TextXAlignment = Enum.TextXAlignment.Left,
									ClearTextOnFocus = false,
									Size = UDim2.fromScale(1, 1),
									[OnChange("Text")] = function(t: string)
										query:set(t)
									end,
								}),
							},
						})
						else nil,

					ForValues(filtered, function(item: any)
						local rowHover = Value(false)
						local isSelected = Computed(function()
							return selected:get() == item.Value
						end)
						return New("TextButton")({
							Name = "Item",
							Text = "",
							AutoButtonColor = false,
							BackgroundColor3 = Tween(
									Computed(function()
										return if rowHover:get() or isSelected:get()
											then Theme.Colors.SurfaceHover:get()
											else Theme.Colors.Elevated:get()
									end),
								Animation.Presets.Fast
							),
							BackgroundTransparency = Computed(function()
								return if rowHover:get() or isSelected:get() then 0 else 1
							end),
							Size = UDim2.new(1, 0, 0, ROW),
							[OnEvent("MouseEnter")] = function()
								rowHover:set(true)
							end,
							[OnEvent("MouseLeave")] = function()
								rowHover:set(false)
							end,
							[OnEvent("Activated")] = function()
								choose(item)
							end,
							[Children] = {
								Primitives.Corner("Sm"),
								Primitives.Padding({ X = 10 }),
								Primitives.List({
									Direction = Enum.FillDirection.Horizontal,
									Gap = 8,
									VerticalAlignment = Enum.VerticalAlignment.Center,
								}),
								if item.Icon
									then Primitives.Icon({
										Name = item.Icon,
										Size = 14,
										Color = Theme.Colors.TextMuted,
										LayoutOrder = 0,
									})
									else nil,
								Primitives.Text({
									Text = item.Label,
									Size = "Sm",
									Color = if item.Disabled then Theme.Colors.TextDisabled else Theme.Colors.Text,
									LayoutOrder = 1,
								}),
								New("Frame")({
									BackgroundTransparency = 1,
									Size = UDim2.fromOffset(14, 14),
									LayoutOrder = 2,
									Visible = isSelected,
									[Children] = {
										Primitives.Icon({ Name = "check", Size = 14, Color = Theme.Colors.Primary }),
									},
								}),
							},
						})
					end, Fusion.cleanup),
				},
			}),
		},
	}) :: Frame
end

end)

__register("Components.EmptyState", function(require)
--!strict
--[[
	AetherUI • Components/EmptyState

	Centered empty/zero-data state with icon, title, description and optional action.

	props:
		Icon: string?          Title: string
		Description: string?   ActionText: string?    OnAction: (() -> ())?
		Size: UDim2?           LayoutOrder: number?   Parent: Instance?
]]

local Fusion = require("Core.Fusion")
local Theme = require("Core.Theme")
local Primitives = require("Components.Primitives")
local Button = require("Components.Button")

local New = Fusion.New
local Children = Fusion.Children
local Computed = Fusion.Computed

return function(props: { [string]: any }): Frame
	local content: { any } = {
		Primitives.List({
			Padding = 10,
			HorizontalAlignment = Enum.HorizontalAlignment.Center,
			VerticalAlignment = Enum.VerticalAlignment.Center,
		}),
		Primitives.Padding({ Y = 32, X = 24 }),
	}

	if props.Icon then
		table.insert(content, New("Frame")({
			Name = "IconHalo",
			Size = UDim2.fromOffset(56, 56),
			BackgroundColor3 = Computed(function()
				return Theme.Colors.SurfaceHigh:get()
			end),
			LayoutOrder = 1,
			[Children] = {
				Primitives.Corner("Full"),
				Primitives.Icon({
					Name = props.Icon,
					Size = 24,
					Color = Computed(function()
						return Theme.Colors.TextMuted:get()
					end),
					Position = UDim2.fromScale(0.5, 0.5),
					AnchorPoint = Vector2.new(0.5, 0.5),
				}),
			},
		}))
	end

	table.insert(content, Primitives.Text({
		Text = props.Title or "Nothing here yet",
		Size = 15,
		Bold = true,
		LayoutOrder = 2,
	}))

	if props.Description then
		table.insert(content, Primitives.Text({
			Text = props.Description,
			Size = 12,
			Muted = true,
			Wrapped = true,
			LayoutOrder = 3,
			Props = {
				Size = UDim2.new(0, 320, 0, 0),
				AutomaticSize = Enum.AutomaticSize.Y,
				TextXAlignment = Enum.TextXAlignment.Center,
			},
		}))
	end

	if props.ActionText then
		table.insert(content, Button({
			Text = props.ActionText,
			Variant = "Primary",
			Size = "Sm",
			LayoutOrder = 4,
			OnClick = props.OnAction,
		}))
	end

	return New("Frame")({
		Name = "AetherEmptyState",
		AutomaticSize = Enum.AutomaticSize.Y,
		Size = props.Size or UDim2.new(1, 0, 0, 0),
		BackgroundTransparency = 1,
		LayoutOrder = props.LayoutOrder,
		Parent = props.Parent,
		[Children] = content,
	})
end

end)

__register("Components.FormField", function(require)
--!strict
--[=[
	AetherUI · FormField, Label, HelperText
	Wrapper that composes a Label + control + HelperText/error message.
]=]

local Fusion = require("Core.Fusion")
local Theme = require("Core.Theme")

local New = Fusion.New
local Children = Fusion.Children
local Computed = Fusion.Computed

local FormField = {}

type LabelProps = {
	Text: string,
	Required: boolean?,
	LayoutOrder: number?,
	Parent: Instance?,
}

function FormField.Label(props: LabelProps): TextLabel
	local theme = Theme.Current
	return New("TextLabel")({
		Name = "AetherLabel",
		Size = UDim2.new(1, 0, 0, 16),
		BackgroundTransparency = 1,
		Text = props.Required and (props.Text .. ' <font color="#ef4444">*</font>') or props.Text,
		RichText = true,
		Font = Enum.Font.GothamMedium,
		TextSize = 13,
		TextColor3 = Computed(function()
			return theme:get().Text
		end),
		TextXAlignment = Enum.TextXAlignment.Left,
		LayoutOrder = props.LayoutOrder,
		Parent = props.Parent,
	}) :: TextLabel
end

type HelperTextProps = {
	Text: Fusion.CanBeState<string>,
	Variant: ("default" | "error" | "success")?,
	LayoutOrder: number?,
	Parent: Instance?,
}

function FormField.HelperText(props: HelperTextProps): TextLabel
	local theme = Theme.Current
	return New("TextLabel")({
		Name = "AetherHelperText",
		Size = UDim2.new(1, 0, 0, 0),
		AutomaticSize = Enum.AutomaticSize.Y,
		BackgroundTransparency = 1,
		Text = props.Text,
		Font = Enum.Font.Gotham,
		TextSize = 12,
		TextWrapped = true,
		TextColor3 = Computed(function()
			local t = theme:get()
			if props.Variant == "error" then
				return t.Danger
			elseif props.Variant == "success" then
				return t.Success
			end
			return t.TextMuted
		end),
		TextXAlignment = Enum.TextXAlignment.Left,
		LayoutOrder = props.LayoutOrder,
		Parent = props.Parent,
	}) :: TextLabel
end

type FormFieldProps = {
	Label: string?,
	Required: boolean?,
	HelperText: Fusion.CanBeState<string>?,
	Error: Fusion.CanBeState<string>?,
	Content: Instance,
	LayoutOrder: number?,
	Parent: Instance?,
}

function FormField.Field(props: FormFieldProps): Frame
	local children: { Instance } = {
		New("UIListLayout")({
			FillDirection = Enum.FillDirection.Vertical,
			Padding = UDim.new(0, 6),
			SortOrder = Enum.SortOrder.LayoutOrder,
		}),
	}

	if props.Label then
		local label = FormField.Label({ Text = props.Label, Required = props.Required, LayoutOrder = 1 })
		table.insert(children, label)
	end

	props.Content.LayoutOrder = 2
	table.insert(children, props.Content)

	if props.Error then
		table.insert(children, FormField.HelperText({ Text = props.Error, Variant = "error", LayoutOrder = 3 }))
	elseif props.HelperText then
		table.insert(children, FormField.HelperText({ Text = props.HelperText, LayoutOrder = 3 }))
	end

	return New("Frame")({
		Name = "AetherFormField",
		Size = UDim2.new(1, 0, 0, 0),
		AutomaticSize = Enum.AutomaticSize.Y,
		BackgroundTransparency = 1,
		LayoutOrder = props.LayoutOrder,
		Parent = props.Parent,
		[Children] = children,
	}) :: Frame
end

return FormField

end)

__register("Components.KeybindInput", function(require)
--!strict
--[=[
	AetherUI · KeybindInput
	Click to capture a new key combination. Integrates with Core/Keybinds.
]=]

local Fusion = require("Core.Fusion")
local Theme = require("Core.Theme")
local Keybinds = require("Core.Keybinds")
local Sound = require("Core.Sound")

local New = Fusion.New
local Children = Fusion.Children
local Value = Fusion.Value
local Computed = Fusion.Computed
local OnEvent = Fusion.OnEvent

local UserInputService = game:GetService("UserInputService")

type KeybindInputProps = {
	Keybind: Keybinds.Bind?,
	OnChanged: ((bind: Keybinds.Bind) -> ())?,
	AllowModifiers: boolean?,
	Size: UDim2?,
	LayoutOrder: number?,
	Parent: Instance?,
}

local function KeybindInput(props: KeybindInputProps): TextButton
	local theme = Theme.Current
	local capturing = Value(false)
	local bind = Value(props.Keybind)
	local captureConn: RBXScriptConnection? = nil

	local labelText = Computed(function()
		if Fusion.peek(capturing) then
			return "Press a key…"
		end
		local b = Fusion.peek(bind)
		return b and Keybinds.format(b) or "Not set"
	end)

	local function stopCapture()
		capturing:set(false)
		if captureConn then
			captureConn:Disconnect()
			captureConn = nil
		end
	end

	local function startCapture()
		if Fusion.peek(capturing) then
			return
		end
		capturing:set(true)
		Sound.play("Click")

		captureConn = UserInputService.InputBegan:Connect(function(input, gameProcessed)
			if input.UserInputType ~= Enum.UserInputType.Keyboard then
				return
			end
			local key = input.KeyCode
			if key == Enum.KeyCode.Escape then
				stopCapture()
				return
			end
			-- Ignore bare modifier presses so combos can be captured
			if key == Enum.KeyCode.LeftControl or key == Enum.KeyCode.RightControl
				or key == Enum.KeyCode.LeftShift or key == Enum.KeyCode.RightShift
				or key == Enum.KeyCode.LeftAlt or key == Enum.KeyCode.RightAlt then
				return
			end

			local newBind: Keybinds.Bind = {
				Key = key,
				Ctrl = props.AllowModifiers ~= false and (UserInputService:IsKeyDown(Enum.KeyCode.LeftControl) or UserInputService:IsKeyDown(Enum.KeyCode.RightControl)) or false,
				Shift = props.AllowModifiers ~= false and (UserInputService:IsKeyDown(Enum.KeyCode.LeftShift) or UserInputService:IsKeyDown(Enum.KeyCode.RightShift)) or false,
				Alt = props.AllowModifiers ~= false and (UserInputService:IsKeyDown(Enum.KeyCode.LeftAlt) or UserInputService:IsKeyDown(Enum.KeyCode.RightAlt)) or false,
			}
			bind:set(newBind)
			stopCapture()
			Sound.play("Success")
			if props.OnChanged then
				props.OnChanged(newBind)
			end
		end)
	end

	return New("TextButton")({
		Name = "AetherKeybindInput",
		Size = props.Size or UDim2.new(0, 140, 0, 32),
		BackgroundColor3 = Computed(function()
			local t = theme:get()
			return Fusion.peek(capturing) and t.SurfaceHigh or t.Surface
		end),
		Text = "",
		AutoButtonColor = false,
		LayoutOrder = props.LayoutOrder,
		Parent = props.Parent,
		[OnEvent("Activated")] = startCapture,
		[Children] = {
			New("UICorner")({ CornerRadius = Computed(function()
				return UDim.new(0, theme:get().RadiusSm)
			end) }),
			New("UIStroke")({
				Color = Computed(function()
					local t = theme:get()
					return Fusion.peek(capturing) and t.Primary or t.Border
				end),
				Thickness = Computed(function()
					return Fusion.peek(capturing) and 2 or 1
				end),
			}),
			New("TextLabel")({
				Size = UDim2.fromScale(1, 1),
				BackgroundTransparency = 1,
				Text = labelText,
				Font = Enum.Font.RobotoMono,
				TextSize = 12,
				TextColor3 = Computed(function()
					local t = theme:get()
					if Fusion.peek(capturing) then
						return t.Primary
					end
					return Fusion.peek(bind) and t.Text or t.TextMuted
				end),
			}),
		},
	}) :: TextButton
end

return KeybindInput

end)

__register("Components.Modal", function(require)
--!strict
--[=[
	AetherUI · Modal / Dialog
	Backdrop blur + dim, scale/fade entrance, ESC to close, optional
	dragging by header, variants (default, danger, success).
]=]

local Fusion = require("Core.Fusion")
local Theme = require("Core.Theme")
local Icons = require("Core.Icons")
local Sound = require("Core.Sound")
local Overlay = require("Core.Overlay")
local Keybinds = require("Core.Keybinds")
local Button = require("Components.Button")

local New = Fusion.New
local Children = Fusion.Children
local Value = Fusion.Value
local Computed = Fusion.Computed
local OnEvent = Fusion.OnEvent
local Spring = Fusion.Spring

local Lighting = game:GetService("Lighting")
local UserInputService = game:GetService("UserInputService")

type ModalAction = {
	Label: string,
	Variant: string?,
	OnClick: (() -> ())?,
	CloseOnClick: boolean?,
}

type ModalProps = {
	Title: string,
	Description: string?,
	Icon: string?,
	Variant: ("default" | "danger" | "success")?,
	Size: UDim2?,
	Draggable: boolean?,
	CloseOnBackdrop: boolean?,
	BlurBackground: boolean?,
	Content: (() -> Instance)?,
	Actions: { ModalAction }?,
	OnClose: (() -> ())?,
}

type ModalHandle = {
	Close: () -> (),
	Instance: Frame,
}

local activeBlur: BlurEffect? = nil
local openCount = 0

local function Modal(props: ModalProps): ModalHandle
	local theme = Theme.Current
	local layer = Overlay.getLayer("Modals", 100)

	local visible = Value(false)
	local closed = false

	openCount += 1

	-- world blur
	if props.BlurBackground ~= false then
		if not activeBlur then
			local blur = Instance.new("BlurEffect")
			blur.Name = "AetherUI_ModalBlur"
			blur.Size = 0
			blur.Parent = Lighting
			activeBlur = blur
		end
		task.spawn(function()
			local blur = activeBlur
			if blur then
				for i = blur.Size, 12, 2 do
					blur.Size = i
					task.wait()
				end
			end
		end)
	end

	local backdrop: Frame? = nil
	local escUnbind: (() -> ())? = nil
	local dragConn: RBXScriptConnection? = nil

	local function close()
		if closed then
			return
		end
		closed = true
		openCount = math.max(0, openCount - 1)
		visible:set(false)
		Sound.play("Close")
		if escUnbind then
			escUnbind()
		end
		if dragConn then
			dragConn:Disconnect()
		end

		if openCount == 0 and activeBlur then
			local blur = activeBlur
			activeBlur = nil
			task.spawn(function()
				for i = blur.Size, 0, -2 do
					blur.Size = i
					task.wait()
				end
				blur:Destroy()
			end)
		end

		task.delay(0.25, function()
			if backdrop then
				backdrop:Destroy()
			end
		end)
		if props.OnClose then
			props.OnClose()
		end
	end

	-- Header ------------------------------------------------------------
	local headerChildren: { Instance } = {
		New("UIListLayout")({
			FillDirection = Enum.FillDirection.Horizontal,
			Padding = UDim.new(0, 10),
			VerticalAlignment = Enum.VerticalAlignment.Center,
		}),
	}

	if props.Icon then
		table.insert(headerChildren, New("Frame")({
			Size = UDim2.fromOffset(34, 34),
			LayoutOrder = 1,
			BackgroundColor3 = Computed(function()
				local t = theme:get()
				if props.Variant == "danger" then
					return t.Danger
				elseif props.Variant == "success" then
					return t.Success
				end
				return t.Primary
			end),
			BackgroundTransparency = 0.85,
			[Children] = {
				New("UICorner")({ CornerRadius = UDim.new(0, 10) }),
				Icons.render(props.Icon, {
					Size = UDim2.fromOffset(17, 17),
					Position = UDim2.fromScale(0.5, 0.5),
					AnchorPoint = Vector2.new(0.5, 0.5),
					Color = Computed(function()
						local t = theme:get()
						if props.Variant == "danger" then
							return t.Danger
						elseif props.Variant == "success" then
							return t.Success
						end
						return t.Primary
					end),
				}),
			},
		}))
	end

	table.insert(headerChildren, New("Frame")({
		AutomaticSize = Enum.AutomaticSize.XY,
		BackgroundTransparency = 1,
		LayoutOrder = 2,
		[Children] = {
			New("UIListLayout")({ FillDirection = Enum.FillDirection.Vertical, Padding = UDim.new(0, 2) }),
			New("TextLabel")({
				AutomaticSize = Enum.AutomaticSize.XY,
				BackgroundTransparency = 1,
				Text = props.Title,
				Font = Enum.Font.GothamBold,
				TextSize = 15,
				TextColor3 = Computed(function()
					return theme:get().Text
				end),
				TextXAlignment = Enum.TextXAlignment.Left,
			}),
			props.Description and New("TextLabel")({
				AutomaticSize = Enum.AutomaticSize.XY,
				BackgroundTransparency = 1,
				Text = props.Description,
				Font = Enum.Font.Gotham,
				TextSize = 12,
				TextColor3 = Computed(function()
					return theme:get().TextMuted
				end),
				TextXAlignment = Enum.TextXAlignment.Left,
				TextWrapped = true,
			}) or nil,
		},
	}))

	-- Body assembly -------------------------------------------------------
	local bodyChildren: { Instance } = {
		New("UIListLayout")({
			FillDirection = Enum.FillDirection.Vertical,
			Padding = UDim.new(0, 14),
			SortOrder = Enum.SortOrder.LayoutOrder,
		}),
		New("UIPadding")({
			PaddingLeft = UDim.new(0, 20),
			PaddingRight = UDim.new(0, 20),
			PaddingTop = UDim.new(0, 20),
			PaddingBottom = UDim.new(0, 20),
		}),
		New("Frame")({
			Name = "Header",
			Size = UDim2.new(1, 0, 0, 0),
			AutomaticSize = Enum.AutomaticSize.Y,
			BackgroundTransparency = 1,
			LayoutOrder = 1,
			[Children] = headerChildren,
		}),
	}

	if props.Content then
		local content = props.Content()
		if content:IsA("GuiObject") then
			content.LayoutOrder = 2
		end
		table.insert(bodyChildren, content)
	end

	if props.Actions then
		local actionButtons: { Instance } = {
			New("UIListLayout")({
				FillDirection = Enum.FillDirection.Horizontal,
				Padding = UDim.new(0, 8),
				HorizontalAlignment = Enum.HorizontalAlignment.Right,
			}),
		}
		for i, action in ipairs(props.Actions) do
			table.insert(actionButtons, Button({
				Text = action.Label,
				Variant = (action.Variant or "secondary") :: any,
				LayoutOrder = i,
				OnClick = function()
					if action.OnClick then
						action.OnClick()
					end
					if action.CloseOnClick ~= false then
						close()
					end
				end,
			}))
		end
		table.insert(bodyChildren, New("Frame")({
			Name = "Actions",
			Size = UDim2.new(1, 0, 0, 36),
			BackgroundTransparency = 1,
			LayoutOrder = 3,
			[Children] = actionButtons,
		}))
	end

	-- Dialog window -------------------------------------------------------
	local dialogPosition = Value(UDim2.fromScale(0.5, 0.5))

	local dialog = New("Frame")({
		Name = "Dialog",
		AnchorPoint = Vector2.new(0.5, 0.5),
		Position = Spring(Computed(function()
			local base = Fusion.peek(dialogPosition)
			if not Fusion.peek(visible) then
				return base + UDim2.fromOffset(0, 24)
			end
			return base
		end), 26, 0.9),
		Size = props.Size or UDim2.fromOffset(420, 0),
		AutomaticSize = Enum.AutomaticSize.Y,
		BackgroundColor3 = Computed(function()
			return theme:get().Surface
		end),
		BackgroundTransparency = Spring(Computed(function()
			return Fusion.peek(visible) and 0 or 1
		end), 26, 1),
		ZIndex = 102,
		[Children] = {
			New("UICorner")({ CornerRadius = Computed(function()
				return UDim.new(0, theme:get().RadiusLg)
			end) }),
			New("UIStroke")({
				Color = Computed(function()
					return theme:get().Border
				end),
				Thickness = 1,
				Transparency = Spring(Computed(function()
					return Fusion.peek(visible) and 0 or 1
				end), 26, 1),
			}),
			New("Frame")({
				Name = "Body",
				Size = UDim2.new(1, 0, 0, 0),
				AutomaticSize = Enum.AutomaticSize.Y,
				BackgroundTransparency = 1,
				[Children] = bodyChildren,
			}),
		},
	}) :: Frame

	-- Dragging ------------------------------------------------------------
	if props.Draggable then
		local dragging = false
		local dragStart = Vector2.zero
		local startPos = UDim2.new()
		dialog.InputBegan:Connect(function(input)
			if input.UserInputType == Enum.UserInputType.MouseButton1 then
				local rel = input.Position.Y - dialog.AbsolutePosition.Y
				if rel <= 60 then -- header zone
					dragging = true
					dragStart = Vector2.new(input.Position.X, input.Position.Y)
					startPos = Fusion.peek(dialogPosition)
				end
			end
		end)
		dragConn = UserInputService.InputChanged:Connect(function(input)
			if dragging and input.UserInputType == Enum.UserInputType.MouseMovement then
				local delta = Vector2.new(input.Position.X, input.Position.Y) - dragStart
				dialogPosition:set(UDim2.new(
					startPos.X.Scale, startPos.X.Offset + delta.X,
					startPos.Y.Scale, startPos.Y.Offset + delta.Y
				))
			end
		end)
		UserInputService.InputEnded:Connect(function(input)
			if input.UserInputType == Enum.UserInputType.MouseButton1 then
				dragging = false
			end
		end)
	end

	-- Backdrop --------------------------------------------------------------
	backdrop = New("TextButton")({
		Name = "AetherModalBackdrop",
		Size = UDim2.fromScale(1, 1),
		BackgroundColor3 = Color3.new(0, 0, 0),
		BackgroundTransparency = Spring(Computed(function()
			return Fusion.peek(visible) and 0.45 or 1
		end), 26, 1),
		Text = "",
		AutoButtonColor = false,
		ZIndex = 101,
		Parent = layer,
		[OnEvent("Activated")] = function()
			if props.CloseOnBackdrop ~= false then
				close()
			end
		end,
		[Children] = { dialog },
	}) :: Frame

	-- ESC to close
	escUnbind = Keybinds.bindTransient(Enum.KeyCode.Escape, close)

	Sound.play("Open")
	task.defer(function()
		visible:set(true)
	end)

	return {
		Close = close,
		Instance = backdrop :: Frame,
	}
end

return Modal

end)

__register("Components.MultiSelect", function(require)
--!strict
--[[
	AetherUI • Components/MultiSelect
	Multi-select dropdown rendering selections as removable chips/tags.

	props:
		Items: { { Label, Value, Icon? } }
		Values: Fusion.Value<{ any }>?
		Placeholder: string?     MaxVisibleChips: number?
		OnChanged: (values: { any }) -> ()?     LayoutOrder
]]

local Fusion = require("Core.Fusion")
local Theme = require("Core.Theme")
local Animation = require("Core.Animation")
local Sound = require("Core.Sound")
local Primitives = require("Components.Primitives")

local New = Fusion.New
local Children = Fusion.Children
local OnEvent = Fusion.OnEvent
local Computed = Fusion.Computed
local ForValues = Fusion.ForValues
local Tween = Fusion.Tween
local Value = Fusion.Value

local ROW = 32

return function(props: { [string]: any }): Frame
	local items = props.Items or {}
	local values = props.Values or Value({})
	local open = Value(false)

	local function isPicked(v: any): boolean
		return table.find(values:get(), v) ~= nil
	end

	local function toggle(v: any)
		local current = table.clone(values:get())
		local index = table.find(current, v)
		if index then
			table.remove(current, index)
		else
			table.insert(current, v)
		end
		values:set(current)
		Sound.Play("Click")
		if props.OnChanged then
			props.OnChanged(current)
		end
	end

	local function labelOf(v: any): string
		for _, item in items :: { any } do
			if item.Value == v then
				return item.Label
			end
		end
		return tostring(v)
	end

	local chips = Computed(function()
		local out = {}
		local maxChips = props.MaxVisibleChips or 4
		local current = values:get()
		for index, v in current do
			if index > maxChips then
				table.insert(out, { Kind = "overflow", Count = #current - maxChips })
				break
			end
			table.insert(out, { Kind = "chip", Value = v, Label = labelOf(v) })
		end
		return out
	end)

	local menuHeight = Computed(function()
		return if open:get() then math.min(#items, 6) * ROW + 8 else 0
	end)

	return New("Frame")({
		Name = "AetherMultiSelect",
		Parent = props.Parent,
		BackgroundTransparency = 1,
		AutomaticSize = Enum.AutomaticSize.Y,
		Size = UDim2.new(1, 0, 0, 0),
		LayoutOrder = props.LayoutOrder or 0,
		ZIndex = 10,
		[Children] = {
			Primitives.List({ Gap = 4 }),

			-- Trigger with chips
			New("TextButton")({
				Name = "Trigger",
				Text = "",
				AutoButtonColor = false,
				BackgroundColor3 = Theme.Colors.Surface,
				AutomaticSize = Enum.AutomaticSize.Y,
				Size = UDim2.new(1, 0, 0, 36),
				LayoutOrder = 0,
				[OnEvent("Activated")] = function()
					open:set(not open:get())
				end,
				[Children] = {
					Primitives.Corner("Md"),
					Primitives.Stroke({
						Color = Computed(function()
							return if open:get() then Theme.Colors.Primary:get() else Theme.Colors.Border:get()
						end),
						Transparency = Computed(function()
							return if open:get() then 0 else 0.35
						end),
					}),
					Primitives.Padding({ X = 8, Y = 6 }),
					Primitives.List({
						Direction = Enum.FillDirection.Horizontal,
						Gap = 4,
						VerticalAlignment = Enum.VerticalAlignment.Center,
						Wraps = true,
					}),

					Primitives.Text({
						Text = props.Placeholder or "Select…",
						Size = "Md",
						Color = Theme.Colors.TextDisabled,
						LayoutOrder = 0,
						Props = {
							Visible = Computed(function()
								return #values:get() == 0
							end),
						},
					}),

					ForValues(chips, function(chip: any)
						if chip.Kind == "overflow" then
							return New("Frame")({
								BackgroundColor3 = Theme.Colors.Secondary,
								AutomaticSize = Enum.AutomaticSize.XY,
								LayoutOrder = 99,
								[Children] = {
									Primitives.Corner("Full"),
									Primitives.Padding({ X = 8, Y = 3 }),
									Primitives.Text({ Text = `+{chip.Count}`, Size = "Xs", Muted = true }),
								},
							})
						end
						return New("Frame")({
							Name = "Chip",
							BackgroundColor3 = Theme.Colors.Secondary,
							AutomaticSize = Enum.AutomaticSize.XY,
							LayoutOrder = 1,
							[Children] = {
								Primitives.Corner("Full"),
								Primitives.Padding({ Left = 8, Right = 4, Y = 3 }),
								Primitives.List({
									Direction = Enum.FillDirection.Horizontal,
									Gap = 4,
									VerticalAlignment = Enum.VerticalAlignment.Center,
								}),
								Primitives.Text({ Text = chip.Label, Size = "Xs" }),
								New("TextButton")({
									Text = "",
									BackgroundTransparency = 1,
									Size = UDim2.fromOffset(14, 14),
									LayoutOrder = 2,
									[OnEvent("Activated")] = function()
										toggle(chip.Value)
									end,
									[Children] = {
										Primitives.Icon({
											Name = "x",
											Size = 10,
											Color = Theme.Colors.TextMuted,
											Position = UDim2.fromScale(0.5, 0.5),
											AnchorPoint = Vector2.new(0.5, 0.5),
										}),
									},
								}),
							},
						})
					end, Fusion.cleanup),
				},
			}),

			-- Menu
			New("Frame")({
				Name = "Menu",
				BackgroundColor3 = Theme.Colors.Elevated,
				ClipsDescendants = true,
				Size = Tween(
					Computed(function()
						return UDim2.new(1, 0, 0, menuHeight:get())
					end),
					Animation.Presets.Normal
				),
				LayoutOrder = 1,
				ZIndex = 20,
				[Children] = {
					Primitives.Corner("Md"),
					Primitives.Stroke(),
					Primitives.Padding(4),
					Primitives.List({ Gap = 2 }),

					ForValues(items, function(item: any)
						local rowHover = Value(false)
						local picked = Computed(function()
							local _ = values:get()
							return isPicked(item.Value)
						end)
						return New("TextButton")({
							Text = "",
							AutoButtonColor = false,
							BackgroundColor3 = Theme.Colors.SurfaceHover,
							BackgroundTransparency = Computed(function()
								return if rowHover:get() then 0 else 1
							end),
							Size = UDim2.new(1, 0, 0, ROW),
							[OnEvent("MouseEnter")] = function()
								rowHover:set(true)
							end,
							[OnEvent("MouseLeave")] = function()
								rowHover:set(false)
							end,
							[OnEvent("Activated")] = function()
								toggle(item.Value)
							end,
							[Children] = {
								Primitives.Corner("Sm"),
								Primitives.Padding({ X = 10 }),
								Primitives.List({
									Direction = Enum.FillDirection.Horizontal,
									Gap = 8,
									VerticalAlignment = Enum.VerticalAlignment.Center,
								}),
								-- Checkbox indicator
								New("Frame")({
									BackgroundColor3 = Tween(
										Computed(function()
											return if picked:get() then Theme.Colors.Primary:get() else Theme.Colors.Surface:get()
										end),
										Animation.Presets.Fast
									),
									Size = UDim2.fromOffset(16, 16),
									LayoutOrder = 0,
									[Children] = {
										Primitives.Corner(4),
										Primitives.Stroke({
											Color = Computed(function()
												return if picked:get() then Theme.Colors.Primary:get() else Theme.Colors.BorderStrong:get()
											end),
											Transparency = 0,
										}),
										New("Frame")({
											BackgroundTransparency = 1,
											Size = UDim2.fromScale(1, 1),
											Visible = picked,
											[Children] = {
												Primitives.Icon({
													Name = "check",
													Size = 11,
													Color = Theme.Colors.PrimaryText,
													Position = UDim2.fromScale(0.5, 0.5),
													AnchorPoint = Vector2.new(0.5, 0.5),
												}),
											},
										}),
									},
								}),
								Primitives.Text({ Text = item.Label, Size = "Sm", LayoutOrder = 1 }),
							},
						})
					end, Fusion.cleanup),
				},
			}),
		},
	}) :: Frame
end

end)

__register("Components.Primitives", function(require)
--!strict
--[[
	AetherUI • Components/Primitives
	Low-level themed building blocks shared by every component:
	corners, strokes, padding, soft shadows, glass, themed text, icons.
]]

local Fusion = require("Core.Fusion")
local Theme = require("Core.Theme")
local Icons = require("Core.Icons")

local New = Fusion.New
local Children = Fusion.Children
local Computed = Fusion.Computed

local SHADOW_IMAGE = "rbxassetid://6014261993" -- soft radial drop shadow (9-slice)

local Primitives = {}

--- UICorner bound to a theme radius token name ("Sm"|"Md"|"Lg"|"Xl"|"Full") or a number.
function Primitives.Corner(radius: any): Instance
	local value = if type(radius) == "string" then Theme.Radius[radius] else radius
	return New("UICorner")({
		CornerRadius = if type(value) == "number"
			then UDim.new(0, value)
			else Computed(function()
				return UDim.new(0, value:get())
			end),
	})
end

--- Themed hairline border. props: { Color?, Transparency?, Thickness? } (all optional / reactive-friendly).
function Primitives.Stroke(props: { [string]: any }?): Instance
	local p = props or {}
	return New("UIStroke")({
		ApplyStrokeMode = Enum.ApplyStrokeMode.Border,
		Color = p.Color or Theme.Colors.Border,
		Transparency = p.Transparency or Theme.StrokeTransparency,
		Thickness = p.Thickness or 1,
	})
end

--- UIPadding. Accepts a number (all sides) or { Top?, Bottom?, Left?, Right?, X?, Y? }.
function Primitives.Padding(padding: any): Instance
	if type(padding) == "number" then
		local u = UDim.new(0, padding)
		return New("UIPadding")({
			PaddingTop = u,
			PaddingBottom = u,
			PaddingLeft = u,
			PaddingRight = u,
		})
	end
	local p = padding or {}
	return New("UIPadding")({
		PaddingTop = UDim.new(0, p.Top or p.Y or 0),
		PaddingBottom = UDim.new(0, p.Bottom or p.Y or 0),
		PaddingLeft = UDim.new(0, p.Left or p.X or 0),
		PaddingRight = UDim.new(0, p.Right or p.X or 0),
	})
end

--- Soft drop shadow rendered behind the parent. props: { Size?, Transparency?, Offset? }.
function Primitives.Shadow(props: { [string]: any }?): Instance
	local p = props or {}
	local spread = p.Size or 24
	return New("ImageLabel")({
		Name = "Shadow",
		BackgroundTransparency = 1,
		Image = SHADOW_IMAGE,
		ImageColor3 = Color3.new(0, 0, 0),
		ImageTransparency = p.Transparency or Theme.ShadowTransparency,
		ScaleType = Enum.ScaleType.Slice,
		SliceCenter = Rect.new(49, 49, 450, 450),
		Size = UDim2.new(1, spread, 1, spread),
		Position = UDim2.new(0.5, 0, 0.5, p.Offset or 4),
		AnchorPoint = Vector2.new(0.5, 0.5),
		ZIndex = -1,
	})
end

--- Vertical or horizontal UIListLayout with sensible defaults.
function Primitives.List(props: { [string]: any }?): Instance
	local p = props or {}
	return New("UIListLayout")({
		FillDirection = p.Direction or Enum.FillDirection.Vertical,
		Padding = UDim.new(0, p.Gap or Theme.Spacing.Sm),
		SortOrder = Enum.SortOrder.LayoutOrder,
		HorizontalAlignment = p.HorizontalAlignment or Enum.HorizontalAlignment.Left,
		VerticalAlignment = p.VerticalAlignment or Enum.VerticalAlignment.Top,
		HorizontalFlex = p.HorizontalFlex,
		VerticalFlex = p.VerticalFlex,
		Wraps = p.Wraps,
	})
end

--- Themed text label. props: Text, Size ("Xs".."Xxl" or number), Color, Font ("Body"|"Heading"|"Mono"),
--- Muted, Bold, Wrapped, XAlignment, plus any TextLabel overrides in Props.
function Primitives.Text(props: { [string]: any }): Instance
	local sizeToken = props.Size or "Md"
	local textSize = if type(sizeToken) == "number" then sizeToken else Theme.TextSizes[sizeToken] or 14
	local fontToken = props.Font or (if props.Bold then "Heading" else "Body")

	local label: { [any]: any } = {
		Name = props.Name or "Text",
		BackgroundTransparency = 1,
		Text = props.Text or "",
		FontFace = Theme.Fonts[fontToken],
		TextSize = textSize,
		TextColor3 = props.Color or (if props.Muted then Theme.Colors.TextMuted else Theme.Colors.Text),
		TextXAlignment = props.XAlignment or Enum.TextXAlignment.Left,
		TextYAlignment = props.YAlignment or Enum.TextYAlignment.Center,
		TextWrapped = props.Wrapped or false,
		TextTruncate = props.Truncate or Enum.TextTruncate.None,
		AutomaticSize = props.AutomaticSize or Enum.AutomaticSize.XY,
		Size = props.SizeUDim2 or UDim2.fromOffset(0, 0),
		Position = props.Position,
		AnchorPoint = props.AnchorPoint,
		LayoutOrder = props.LayoutOrder or 0,
		TextTransparency = props.Transparency or 0,
		RichText = props.RichText or false,
		ZIndex = props.ZIndex or 1,
	}
	for key, value in (props.Props or {}) :: { [string]: any } do
		label[key] = value
	end
	return New("TextLabel")(label)
end

--- Lucide icon. Renders an ImageLabel when the icon resolves, otherwise a subtle dot glyph.
--- props: { Name, Size?, Color?, Transparency?, LayoutOrder?, Position?, AnchorPoint?, Rotation? }
function Primitives.Icon(props: { [string]: any }): Instance
	local size = props.Size or 16
	local data = Icons.Get(props.Name)

	if data then
		return New("ImageLabel")({
			Name = "Icon",
			BackgroundTransparency = 1,
			Image = data.Id,
			ImageRectOffset = data.ImageRectOffset or Vector2.zero,
			ImageRectSize = data.ImageRectSize or Vector2.zero,
			ImageColor3 = props.Color or Theme.Colors.Text,
			ImageTransparency = props.Transparency or 0,
			Size = UDim2.fromOffset(size, size),
			Position = props.Position,
			AnchorPoint = props.AnchorPoint,
			LayoutOrder = props.LayoutOrder or 0,
			Rotation = props.Rotation or 0,
			ZIndex = props.ZIndex or 1,
		})
	end

	-- Graceful fallback: a small themed dot so layouts never break
	return New("Frame")({
		Name = "IconFallback",
		BackgroundTransparency = 1,
		Size = UDim2.fromOffset(size, size),
		Position = props.Position,
		AnchorPoint = props.AnchorPoint,
		LayoutOrder = props.LayoutOrder or 0,
		[Children] = {
			New("Frame")({
				BackgroundColor3 = props.Color or Theme.Colors.TextMuted,
				BackgroundTransparency = 0.35,
				Size = UDim2.fromOffset(math.max(4, size // 3), math.max(4, size // 3)),
				Position = UDim2.fromScale(0.5, 0.5),
				AnchorPoint = Vector2.new(0.5, 0.5),
				[Children] = { New("UICorner")({ CornerRadius = UDim.new(1, 0) }) },
			}),
		},
	})
end

--[[
	Themed elevated container: Surface background + rounded corner + hairline
	stroke, with optional glassmorphism, drop shadow, and padding.
	props: { Name?, Size?, AutomaticSize?, Padding? (number|table), Glass?,
	Shadow?, LayoutOrder?, Parent?, ClipsDescendants?, [Children]? }
]]
function Primitives.Surface(props: { [any]: any }): Instance
	local inner: { any } = {}

	if props.Glass then
		for _, deco in Primitives.Glass("Lg") do
			table.insert(inner, deco)
		end
	else
		table.insert(inner, Primitives.Corner("Lg"))
		table.insert(inner, Primitives.Stroke(nil))
	end

	if props.Shadow then
		table.insert(inner, Primitives.Shadow(nil))
	end

	if props.Padding ~= nil and props.Padding ~= 0 then
		table.insert(inner, Primitives.Padding(props.Padding))
	end

	local extra = props[Children]
	if extra ~= nil then
		table.insert(inner, extra)
	end

	return New("Frame")({
		Name = props.Name or "Surface",
		Size = props.Size or UDim2.new(1, 0, 0, 0),
		AutomaticSize = props.AutomaticSize,
		BackgroundColor3 = Theme.Colors.Surface,
		BackgroundTransparency = if props.Glass then Theme.GlassTransparency else 0,
		LayoutOrder = props.LayoutOrder,
		ClipsDescendants = props.ClipsDescendants,
		Parent = props.Parent,
		[Children] = inner,
	})
end

--- Glassmorphism surface children: translucent fill + hairline stroke + top sheen.
function Primitives.Glass(radius: any?): { Instance }
	return {
		Primitives.Corner(radius or "Lg"),
		Primitives.Stroke({
			Transparency = Computed(function()
				return math.clamp(Theme.StrokeTransparency:get() - 0.1, 0, 1)
			end),
		}),
		New("UIGradient")({
			Rotation = 90,
			Transparency = NumberSequence.new({
				NumberSequenceKeypoint.new(0, 0),
				NumberSequenceKeypoint.new(0.12, 0.35),
				NumberSequenceKeypoint.new(1, 0.45),
			}),
			Color = ColorSequence.new(Color3.new(1, 1, 1)),
			Enabled = false, -- sheen kept subtle; flip Enabled for extra shine
		}),
	}
end

return Primitives

end)

__register("Components.Progress", function(require)
--!strict
--[=[
	AetherUI · Progress
	ProgressBar (determinate + indeterminate shimmer) and CircularProgress.
]=]

local Fusion = require("Core.Fusion")
local Theme = require("Core.Theme")

local New = Fusion.New
local Children = Fusion.Children
local Computed = Fusion.Computed
local Spring = Fusion.Spring

local RunService = game:GetService("RunService")

local Progress = {}

type ProgressBarProps = {
	Value: Fusion.CanBeState<number>?, -- 0..1; nil = indeterminate
	ShowLabel: boolean?,
	Color: Color3?,
	Height: number?,
	Size: UDim2?,
	LayoutOrder: number?,
	Parent: Instance?,
}

function Progress.Bar(props: ProgressBarProps): Frame
	local theme = Theme.Current
	local height = props.Height or 6
	local indeterminate = props.Value == nil

	local progress = Computed(function()
		if indeterminate then
			return 0
		end
		local v = props.Value
		if typeof(v) == "number" then
			return math.clamp(v, 0, 1)
		end
		return math.clamp(Fusion.peek(v :: any) or 0, 0, 1)
	end)

	local fillColor = Computed(function()
		return props.Color or theme:get().Primary
	end)

	local children: { Instance } = {
		New("UICorner")({ CornerRadius = UDim.new(1, 0) }),
	}

	if indeterminate then
		local shimmer = New("Frame")({
			Name = "Shimmer",
			Size = UDim2.new(0.35, 0, 1, 0),
			Position = UDim2.fromScale(-0.4, 0),
			BackgroundColor3 = fillColor,
			BorderSizePixel = 0,
			[Children] = { New("UICorner")({ CornerRadius = UDim.new(1, 0) }) },
		}) :: Frame

		local t = 0
		local conn: RBXScriptConnection
		conn = RunService.Heartbeat:Connect(function(dt)
			if not shimmer.Parent then
				conn:Disconnect()
				return
			end
			t = (t + dt * 0.7) % 1.4
			shimmer.Position = UDim2.fromScale(-0.4 + t, 0)
		end)
		table.insert(children, shimmer)
	else
		table.insert(children, New("Frame")({
			Name = "Fill",
			Size = Spring(Computed(function()
				return UDim2.new(Fusion.peek(progress), 0, 1, 0)
			end), 22, 1),
			BackgroundColor3 = fillColor,
			BorderSizePixel = 0,
			[Children] = { New("UICorner")({ CornerRadius = UDim.new(1, 0) }) },
		}))
	end

	local track = New("Frame")({
		Name = "Track",
		Size = UDim2.new(1, props.ShowLabel and -42 or 0, 0, height),
		Position = UDim2.new(0, 0, 0.5, 0),
		AnchorPoint = Vector2.new(0, 0.5),
		BackgroundColor3 = Computed(function()
			return theme:get().SurfaceHigh
		end),
		ClipsDescendants = true,
		[Children] = children,
	})

	local wrapperChildren: { Instance } = { track }

	if props.ShowLabel and not indeterminate then
		table.insert(wrapperChildren, New("TextLabel")({
			AnchorPoint = Vector2.new(1, 0.5),
			Position = UDim2.new(1, 0, 0.5, 0),
			Size = UDim2.fromOffset(36, 14),
			BackgroundTransparency = 1,
			Text = Computed(function()
				return string.format("%d%%", math.floor(Fusion.peek(progress) * 100 + 0.5))
			end),
			Font = Enum.Font.RobotoMono,
			TextSize = 11,
			TextColor3 = Computed(function()
				return theme:get().TextMuted
			end),
			TextXAlignment = Enum.TextXAlignment.Right,
		}))
	end

	return New("Frame")({
		Name = "AetherProgressBar",
		Size = props.Size or UDim2.new(1, 0, 0, math.max(height, 14)),
		BackgroundTransparency = 1,
		LayoutOrder = props.LayoutOrder,
		Parent = props.Parent,
		[Children] = wrapperChildren,
	}) :: Frame
end

type CircularProgressProps = {
	Value: Fusion.CanBeState<number>?, -- 0..1; nil = spinner
	Diameter: number?,
	Thickness: number?,
	Color: Color3?,
	ShowLabel: boolean?,
	LayoutOrder: number?,
	Parent: Instance?,
}

--[=[
	Circular progress rendered with two half-circle gradient masks — the
	standard Roblox technique for smooth radial progress without image assets.
]=]
function Progress.Circular(props: CircularProgressProps): Frame
	local theme = Theme.Current
	local d = props.Diameter or 44
	local thickness = props.Thickness or 4
	local indeterminate = props.Value == nil

	local progress = Computed(function()
		if indeterminate then
			return 0.25
		end
		local v = props.Value
		if typeof(v) == "number" then
			return math.clamp(v, 0, 1)
		end
		return math.clamp(Fusion.peek(v :: any) or 0, 0, 1)
	end)

	local fillColor = Computed(function()
		return props.Color or theme:get().Primary
	end)

	local function ring(color: Fusion.CanBeState<Color3>, transparency: number): (Frame, UIGradient, UIGradient)
		local leftGrad = New("UIGradient")({
			Transparency = NumberSequence.new(1),
			Rotation = 180,
		}) :: UIGradient
		local rightGrad = New("UIGradient")({
			Transparency = NumberSequence.new(1),
			Rotation = 0,
		}) :: UIGradient

		local function half(grad: UIGradient, isRight: boolean): Frame
			return New("Frame")({
				Size = UDim2.new(0.5, 0, 1, 0),
				Position = isRight and UDim2.fromScale(0.5, 0) or UDim2.fromScale(0, 0),
				BackgroundTransparency = 1,
				ClipsDescendants = true,
				[Children] = {
					New("Frame")({
						Size = UDim2.new(2, 0, 1, 0),
						Position = isRight and UDim2.fromScale(-1, 0) or UDim2.fromScale(0, 0),
						BackgroundTransparency = transparency,
						BackgroundColor3 = color,
						[Children] = {
							New("UICorner")({ CornerRadius = UDim.new(1, 0) }),
							New("UIStroke")({ Thickness = 0, Transparency = 1 }),
							grad,
						},
					}),
				},
			}) :: Frame
		end

		local holder = New("Frame")({
			Size = UDim2.fromScale(1, 1),
			BackgroundTransparency = 1,
			[Children] = { half(leftGrad, false), half(rightGrad, true) },
		}) :: Frame
		return holder, leftGrad, rightGrad
	end

	local _ = ring

	-- Simpler robust approach: canvas-group ring using UIStroke arc illusion
	-- Track ring + rotating fill ring clipped to progress fraction.
	local fillRotation = Computed(function()
		return 360 * Fusion.peek(progress)
	end)

	local labelText = Computed(function()
		return string.format("%d%%", math.floor(Fusion.peek(progress) * 100 + 0.5))
	end)

	local spinnerRotation = Fusion.Value(0)
	if indeterminate then
		local conn: RBXScriptConnection
		conn = RunService.Heartbeat:Connect(function(dt)
			spinnerRotation:set((Fusion.peek(spinnerRotation) + dt * 280) % 360)
		end)
		task.delay(0, function()
			-- disconnect when the frame is destroyed (handled below via Destroying)
			local _ = conn
		end)
	end

	local frame: Frame
	frame = New("Frame")({
		Name = "AetherCircularProgress",
		Size = UDim2.fromOffset(d, d),
		BackgroundTransparency = 1,
		LayoutOrder = props.LayoutOrder,
		Parent = props.Parent,
		Rotation = indeterminate and Spring(spinnerRotation, 5, 2) or 0,
		[Children] = {
			-- Track circle
			New("Frame")({
				Size = UDim2.fromScale(1, 1),
				BackgroundTransparency = 1,
				[Children] = {
					New("UICorner")({ CornerRadius = UDim.new(1, 0) }),
					New("UIStroke")({
						Color = Computed(function()
							return theme:get().SurfaceHigh
						end),
						Thickness = thickness,
					}),
				},
			}),
			-- Fill arc: two clipped halves rotated by progress
			New("Frame")({
				Name = "ArcLeft",
				Size = UDim2.new(0.5, 0, 1, 0),
				BackgroundTransparency = 1,
				ClipsDescendants = true,
				[Children] = {
					New("Frame")({
						Size = UDim2.new(2, 0, 1, 0),
						BackgroundTransparency = 1,
						Rotation = Spring(Computed(function()
							return math.clamp(Fusion.peek(fillRotation), 180, 360) - 360
						end), 25, 1),
						[Children] = {
							New("UICorner")({ CornerRadius = UDim.new(1, 0) }),
							New("UIStroke")({ Color = fillColor, Thickness = thickness }),
						},
					}),
				},
			}),
			New("Frame")({
				Name = "ArcRight",
				Position = UDim2.fromScale(0.5, 0),
				Size = UDim2.new(0.5, 0, 1, 0),
				BackgroundTransparency = 1,
				ClipsDescendants = true,
				[Children] = {
					New("Frame")({
						Position = UDim2.fromScale(-1, 0),
						Size = UDim2.new(2, 0, 1, 0),
						BackgroundTransparency = 1,
						Rotation = Spring(Computed(function()
							return math.clamp(Fusion.peek(fillRotation), 0, 180) - 180
						end), 25, 1),
						[Children] = {
							New("UICorner")({ CornerRadius = UDim.new(1, 0) }),
							New("UIStroke")({ Color = fillColor, Thickness = thickness }),
						},
					}),
				},
			}),
			(props.ShowLabel and not indeterminate) and New("TextLabel")({
				Size = UDim2.fromScale(1, 1),
				BackgroundTransparency = 1,
				Text = labelText,
				Font = Enum.Font.GothamBold,
				TextSize = math.max(10, math.floor(d * 0.24)),
				TextColor3 = Computed(function()
					return theme:get().Text
				end),
			}) or nil,
		},
	}) :: Frame

	return frame
end

return Progress

end)

__register("Components.RadioGroup", function(require)
--!strict
--[[
	AetherUI • Components/RadioGroup
	props:
		Items: { { Label: string, Value: any, Description: string? } }
		Value: Fusion.Value<any>?
		Direction: Enum.FillDirection?   OnChanged?, LayoutOrder
]]

local Fusion = require("Core.Fusion")
local Theme = require("Core.Theme")
local Animation = require("Core.Animation")
local Sound = require("Core.Sound")
local Primitives = require("Components.Primitives")

local New = Fusion.New
local Children = Fusion.Children
local OnEvent = Fusion.OnEvent
local Computed = Fusion.Computed
local Spring = Fusion.Spring
local Tween = Fusion.Tween
local Value = Fusion.Value
local ForValues = Fusion.ForValues

return function(props: { [string]: any }): Frame
	local selected = props.Value or Value(nil)

	local function makeOption(item: any): Instance
		local hovering = Value(false)
		local isSelected = Computed(function()
			return selected:get() == item.Value
		end)
		local dotScale = Spring(
			Computed(function()
				return if isSelected:get() then 1 else 0
			end),
			Animation.Springs.Wobbly.Speed,
			Animation.Springs.Wobbly.Damping
		)

		return New("TextButton")({
			Name = "Radio",
			Text = "",
			AutoButtonColor = false,
			BackgroundTransparency = 1,
			AutomaticSize = Enum.AutomaticSize.XY,
			[OnEvent("MouseEnter")] = function()
				hovering:set(true)
			end,
			[OnEvent("MouseLeave")] = function()
				hovering:set(false)
			end,
			[OnEvent("Activated")] = function()
				selected:set(item.Value)
				Sound.Play("Click")
				if props.OnChanged then
					props.OnChanged(item.Value)
				end
			end,
			[Children] = {
				Primitives.List({
					Direction = Enum.FillDirection.Horizontal,
					Gap = 10,
					VerticalAlignment = Enum.VerticalAlignment.Top,
				}),
				New("Frame")({
					Name = "Circle",
					BackgroundColor3 = Theme.Colors.Surface,
					Size = UDim2.fromOffset(18, 18),
					LayoutOrder = 0,
					[Children] = {
						New("UICorner")({ CornerRadius = UDim.new(1, 0) }),
						Primitives.Stroke({
							Color = Tween(
								Computed(function()
									if isSelected:get() then
										return Theme.Colors.Primary:get()
									end
									return if hovering:get() then Theme.Colors.BorderStrong:get() else Theme.Colors.Border:get()
								end),
								Animation.Presets.Fast
							),
							Transparency = 0,
							Thickness = Computed(function()
								return if isSelected:get() then 1.5 else 1
							end),
						}),
						New("Frame")({
							Name = "Dot",
							BackgroundColor3 = Theme.Colors.Primary,
							Size = UDim2.fromOffset(8, 8),
							Position = UDim2.fromScale(0.5, 0.5),
							AnchorPoint = Vector2.new(0.5, 0.5),
							[Children] = {
								New("UICorner")({ CornerRadius = UDim.new(1, 0) }),
								New("UIScale")({ Scale = dotScale }),
							},
						}),
					},
				}),
				New("Frame")({
					BackgroundTransparency = 1,
					AutomaticSize = Enum.AutomaticSize.XY,
					LayoutOrder = 1,
					[Children] = {
						Primitives.List({ Gap = 2 }),
						Primitives.Text({ Text = item.Label, Size = "Sm" }),
						if item.Description
							then Primitives.Text({ Text = item.Description, Size = "Xs", Muted = true, Wrapped = true })
							else nil,
					},
				}),
			},
		})
	end

	return New("Frame")({
		Name = "AetherRadioGroup",
		Parent = props.Parent,
		BackgroundTransparency = 1,
		AutomaticSize = Enum.AutomaticSize.XY,
		LayoutOrder = props.LayoutOrder or 0,
		[Children] = {
			Primitives.List({
				Direction = props.Direction or Enum.FillDirection.Vertical,
				Gap = 10,
			}),
			ForValues(props.Items or {}, function(item: any)
				return makeOption(item)
			end, Fusion.cleanup),
		},
	}) :: Frame
end

end)

__register("Components.ScrollFrame", function(require)
--!strict
--[=[
	AetherUI · ScrollFrame
	ScrollingFrame with a slim, themed, auto-hiding scrollbar and
	automatic canvas sizing.
]=]

local Fusion = require("Core.Fusion")
local Theme = require("Core.Theme")

local New = Fusion.New
local Children = Fusion.Children
local Computed = Fusion.Computed

type ScrollFrameProps = {
	Size: UDim2?,
	Position: UDim2?,
	AnchorPoint: Vector2?,
	Padding: number?,
	ListPadding: number?,
	Horizontal: boolean?,
	LayoutOrder: number?,
	ZIndex: number?,
	Parent: Instance?,
	Children: { Instance }?,
}

local function ScrollFrame(props: ScrollFrameProps): ScrollingFrame
	local theme = Theme.Current

	local inner: { Instance } = {
		New("UIListLayout")({
			FillDirection = props.Horizontal and Enum.FillDirection.Horizontal or Enum.FillDirection.Vertical,
			Padding = UDim.new(0, props.ListPadding or 8),
			SortOrder = Enum.SortOrder.LayoutOrder,
		}),
	}

	if props.Padding and props.Padding > 0 then
		table.insert(inner, New("UIPadding")({
			PaddingLeft = UDim.new(0, props.Padding),
			PaddingRight = UDim.new(0, props.Padding),
			PaddingTop = UDim.new(0, props.Padding),
			PaddingBottom = UDim.new(0, props.Padding),
		}))
	end

	if props.Children then
		for _, child in ipairs(props.Children) do
			table.insert(inner, child)
		end
	end

	return New("ScrollingFrame")({
		Name = "AetherScrollFrame",
		Size = props.Size or UDim2.fromScale(1, 1),
		Position = props.Position,
		AnchorPoint = props.AnchorPoint,
		BackgroundTransparency = 1,
		BorderSizePixel = 0,
		ScrollBarThickness = 4,
		ScrollBarImageColor3 = Computed(function()
			return theme:get().Border
		end),
		ScrollBarImageTransparency = 0.2,
		ScrollingDirection = props.Horizontal and Enum.ScrollingDirection.X or Enum.ScrollingDirection.Y,
		AutomaticCanvasSize = props.Horizontal and Enum.AutomaticSize.X or Enum.AutomaticSize.Y,
		CanvasSize = UDim2.new(),
		ElasticBehavior = Enum.ElasticBehavior.WhenScrollable,
		LayoutOrder = props.LayoutOrder,
		ZIndex = props.ZIndex,
		Parent = props.Parent,
		[Children] = inner,
	}) :: ScrollingFrame
end

return ScrollFrame

end)

__register("Components.Separator", function(require)
--!strict
--[=[
	AetherUI · Separator / Divider
	Horizontal or vertical hairline, optional centered label.
]=]

local Fusion = require("Core.Fusion")
local Theme = require("Core.Theme")

local New = Fusion.New
local Children = Fusion.Children
local Computed = Fusion.Computed

type SeparatorProps = {
