__register("Components.Sidebar", function(require)
--!strict
--[=[
	AetherUI · Sidebar / Navigation
	Collapsible navigation rail with sections, icons, badges and an
	animated active-item indicator.
]=]

local Fusion = require("Core.Fusion")
local Theme = require("Core.Theme")
local Icons = require("Core.Icons")
local Sound = require("Core.Sound")
local ScrollFrame = require("Components.ScrollFrame")

local New = Fusion.New
local Children = Fusion.Children
local Value = Fusion.Value
local Computed = Fusion.Computed
local OnEvent = Fusion.OnEvent
local Spring = Fusion.Spring

type NavItem = {
	Id: string,
	Label: string,
	Icon: string,
	Badge: string?,
	Section: string?,
}

type SidebarProps = {
	Items: { NavItem },
	Default: string?,
	Title: string?,
	Collapsible: boolean?,
	OnChanged: ((id: string) -> ())?,
	Size: UDim2?,
	Parent: Instance?,
}

type SidebarHandle = {
	Instance: Frame,
	SetActive: (id: string) -> (),
	Toggle: () -> (),
}

local EXPANDED = 220
local COLLAPSED = 60

local function Sidebar(props: SidebarProps): SidebarHandle
	local theme = Theme.Current
	local active = Value(props.Default or (props.Items[1] and props.Items[1].Id) or "")
	local collapsed = Value(false)

	local function select(id: string)
		if Fusion.peek(active) == id then
			return
		end
		active:set(id)
		Sound.play("Click")
		if props.OnChanged then
			props.OnChanged(id)
		end
	end

	-- Build item rows grouped by section --------------------------------
	local navChildren: { Instance } = {}
	local lastSection: string? = nil
	local order = 0

	for _, item in ipairs(props.Items) do
		if item.Section and item.Section ~= lastSection then
			lastSection = item.Section
			order += 1
			table.insert(navChildren, New("TextLabel")({
				Size = UDim2.new(1, 0, 0, 22),
				BackgroundTransparency = 1,
				Text = string.upper(item.Section),
				Font = Enum.Font.GothamBold,
				TextSize = 10,
				TextColor3 = Computed(function()
					return theme:get().TextMuted
				end),
				TextXAlignment = Enum.TextXAlignment.Left,
				TextTransparency = Spring(Computed(function()
					return Fusion.peek(collapsed) and 1 or 0
				end), 30, 1),
				LayoutOrder = order,
				[Children] = {
					New("UIPadding")({ PaddingLeft = UDim.new(0, 10), PaddingTop = UDim.new(0, 8) }),
				},
			}))
		end

		order += 1
		local isActive = Computed(function()
			return Fusion.peek(active) == item.Id
		end)
		local hovered = Value(false)

		table.insert(navChildren, New("TextButton")({
			Name = "Nav_" .. item.Id,
			Size = UDim2.new(1, 0, 0, 36),
			Text = "",
			AutoButtonColor = false,
			LayoutOrder = order,
			BackgroundColor3 = Computed(function()
				local t = theme:get()
				return Fusion.peek(isActive) and t.Primary or t.SurfaceHigh
			end),
			BackgroundTransparency = Spring(Computed(function()
				if Fusion.peek(isActive) then
					return 0.85
				end
				return Fusion.peek(hovered) and 0.6 or 1
			end), 30, 1),
			[OnEvent("Activated")] = function()
				select(item.Id)
			end,
			[OnEvent("MouseEnter")] = function()
				hovered:set(true)
				Sound.play("Hover")
			end,
			[OnEvent("MouseLeave")] = function()
				hovered:set(false)
			end,
			[Children] = {
				New("UICorner")({ CornerRadius = Computed(function()
					return UDim.new(0, theme:get().RadiusSm)
				end) }),
				-- Active indicator pill
				New("Frame")({
					AnchorPoint = Vector2.new(0, 0.5),
					Position = UDim2.new(0, 0, 0.5, 0),
					Size = Spring(Computed(function()
						return Fusion.peek(isActive) and UDim2.fromOffset(3, 18) or UDim2.fromOffset(3, 0)
					end), 30, 1),
					BackgroundColor3 = Computed(function()
						return theme:get().Primary
					end),
					BorderSizePixel = 0,
					[Children] = { New("UICorner")({ CornerRadius = UDim.new(1, 0) }) },
				}),
				Icons.render(item.Icon, {
					Size = UDim2.fromOffset(17, 17),
					Position = UDim2.new(0, 12, 0.5, 0),
					AnchorPoint = Vector2.new(0, 0.5),
					Color = Computed(function()
						local t = theme:get()
						return Fusion.peek(isActive) and t.Primary or t.TextMuted
					end),
				}),
				New("TextLabel")({
					Position = UDim2.new(0, 38, 0, 0),
					Size = UDim2.new(1, -70, 1, 0),
					BackgroundTransparency = 1,
					Text = item.Label,
					Font = Enum.Font.GothamMedium,
					TextSize = 13,
					TextColor3 = Computed(function()
						local t = theme:get()
						return Fusion.peek(isActive) and t.Text or t.TextMuted
					end),
					TextXAlignment = Enum.TextXAlignment.Left,
					TextTransparency = Spring(Computed(function()
						return Fusion.peek(collapsed) and 1 or 0
					end), 30, 1),
					TextTruncate = Enum.TextTruncate.AtEnd,
				}),
				item.Badge and New("TextLabel")({
					AnchorPoint = Vector2.new(1, 0.5),
					Position = UDim2.new(1, -10, 0.5, 0),
					AutomaticSize = Enum.AutomaticSize.XY,
					BackgroundColor3 = Computed(function()
						return theme:get().Primary
					end),
					Text = item.Badge,
					Font = Enum.Font.GothamBold,
					TextSize = 10,
					TextColor3 = Computed(function()
						return theme:get().PrimaryText
					end),
					TextTransparency = Spring(Computed(function()
						return Fusion.peek(collapsed) and 1 or 0
					end), 30, 1),
					BackgroundTransparency = Spring(Computed(function()
						return Fusion.peek(collapsed) and 1 or 0
					end), 30, 1),
					[Children] = {
						New("UICorner")({ CornerRadius = UDim.new(1, 0) }),
						New("UIPadding")({
							PaddingLeft = UDim.new(0, 6),
							PaddingRight = UDim.new(0, 6),
							PaddingTop = UDim.new(0, 2),
							PaddingBottom = UDim.new(0, 2),
						}),
					},
				}) or nil,
			},
		}))
	end

	-- Header --------------------------------------------------------------
	local headerChildren: { Instance } = {
		props.Title and New("TextLabel")({
			Position = UDim2.new(0, 12, 0, 0),
			Size = UDim2.new(1, -56, 1, 0),
			BackgroundTransparency = 1,
			Text = props.Title,
			Font = Enum.Font.GothamBold,
			TextSize = 15,
			TextColor3 = Computed(function()
				return theme:get().Text
			end),
			TextXAlignment = Enum.TextXAlignment.Left,
			TextTransparency = Spring(Computed(function()
				return Fusion.peek(collapsed) and 1 or 0
			end), 30, 1),
		}) or nil,
	}

	if props.Collapsible ~= false then
		table.insert(headerChildren, New("TextButton")({
			Name = "CollapseButton",
			AnchorPoint = Vector2.new(1, 0.5),
			Position = UDim2.new(1, -10, 0.5, 0),
			Size = UDim2.fromOffset(28, 28),
			BackgroundTransparency = 1,
			Text = "",
			[OnEvent("Activated")] = function()
				collapsed:set(not Fusion.peek(collapsed))
				Sound.play("Click")
			end,
			[Children] = {
				Icons.render("panel-left", {
					Size = UDim2.fromOffset(15, 15),
					Position = UDim2.fromScale(0.5, 0.5),
					AnchorPoint = Vector2.new(0.5, 0.5),
					Color = Computed(function()
						return theme:get().TextMuted
					end),
				}),
			},
		}))
	end

	local frame = New("Frame")({
		Name = "AetherSidebar",
		Size = Spring(Computed(function()
			local base = props.Size or UDim2.new(0, EXPANDED, 1, 0)
			local width = Fusion.peek(collapsed) and COLLAPSED or (base.X.Offset > 0 and base.X.Offset or EXPANDED)
			return UDim2.new(0, width, base.Y.Scale, base.Y.Offset)
		end), 26, 1),
		BackgroundColor3 = Computed(function()
			return theme:get().Surface
		end),
		Parent = props.Parent,
		ClipsDescendants = true,
		[Children] = {
			New("UIStroke")({
				Color = Computed(function()
					return theme:get().Border
				end),
				Thickness = 1,
			}),
			New("UICorner")({ CornerRadius = Computed(function()
				return UDim.new(0, theme:get().RadiusMd)
			end) }),
			New("Frame")({
				Name = "Header",
				Size = UDim2.new(1, 0, 0, 48),
				BackgroundTransparency = 1,
				[Children] = headerChildren,
			}),
			ScrollFrame({
				Size = UDim2.new(1, -16, 1, -56),
				Position = UDim2.fromOffset(8, 52),
				ListPadding = 2,
				Children = navChildren,
			}),
		},
	}) :: Frame

	return {
		Instance = frame,
		SetActive = select,
		Toggle = function()
			collapsed:set(not Fusion.peek(collapsed))
		end,
	}
end

return Sidebar

end)

__register("Components.Skeleton", function(require)
--!strict
--[[
	AetherUI • Components/Skeleton

	Shimmering loading placeholder.

	props:
		Size: UDim2?              (default full-width, 16px tall)
		Radius: any?              (theme radius token or number, default "Sm")
		Lines: number?            (renders N stacked lines with the last one shorter)
		LayoutOrder: number?      Parent: Instance?
]]

local RunService = game:GetService("RunService")

local Fusion = require("Core.Fusion")
local Theme = require("Core.Theme")
local Primitives = require("Components.Primitives")

local New = Fusion.New
local Children = Fusion.Children
local Computed = Fusion.Computed
local Value = Fusion.Value

local function shimmerBlock(size: UDim2, radius: any, order: number?): Frame
	local phase = Value(0)

	local block = New("Frame")({
		Name = "Skeleton",
		Size = size,
		BackgroundColor3 = Computed(function()
			local base: Color3 = Theme.Colors.SurfaceHigh:get()
			local sheen: Color3 = Theme.Colors.SurfaceHover:get()
			-- Smooth ping-pong blend between base and sheen.
			local t = (math.sin(phase:get()) + 1) / 2
			return base:Lerp(sheen, t)
		end),
		LayoutOrder = order,
		[Children] = { Primitives.Corner(radius) },
	}) :: Frame

	local connection: RBXScriptConnection? = nil
	connection = RunService.Heartbeat:Connect(function(dt)
		if not block:IsDescendantOf(game) and block.Parent == nil then
			if connection then
				connection:Disconnect()
			end
			return
		end
		phase:set(phase:get() + dt * 4)
	end)

	block.Destroying:Connect(function()
		if connection then
			connection:Disconnect()
		end
	end)

	return block
end

return function(props: { [string]: any }): Frame
	local radius = props.Radius or "Sm"

	if props.Lines and props.Lines > 1 then
		local lines: { any } = { Primitives.List({ Padding = 8 }) }
		for i = 1, props.Lines do
			local width = if i == props.Lines then 0.6 else 1
			table.insert(lines, shimmerBlock(UDim2.new(width, 0, 0, 12), radius, i))
		end
		return New("Frame")({
			Name = "AetherSkeletonGroup",
			AutomaticSize = Enum.AutomaticSize.Y,
			Size = props.Size or UDim2.new(1, 0, 0, 0),
			BackgroundTransparency = 1,
			LayoutOrder = props.LayoutOrder,
			Parent = props.Parent,
			[Children] = lines,
		})
	end

	local block = shimmerBlock(props.Size or UDim2.new(1, 0, 0, 16), radius, props.LayoutOrder)
	if props.Parent then
		block.Parent = props.Parent
	end
	return block
end

end)

__register("Components.Slider", function(require)
--!strict
--[[
	AetherUI • Components/Slider
	Single-value and range slider with drag, step snapping, live tooltip and formatting.

	props:
		Min: number (default 0)      Max: number (default 100)     Step: number?
		Value: Fusion.Value<number>?           -- single mode
		RangeValue: Fusion.Value<{number}>?    -- {low, high} enables range mode
		Format: ((number) -> string)?          -- tooltip / label formatting
		Label: string?               ShowValue: boolean?           OnChanged: (any) -> ()?
		LayoutOrder
]]

local UserInputService = game:GetService("UserInputService")

local Fusion = require("Core.Fusion")
local Theme = require("Core.Theme")
local Animation = require("Core.Animation")
local Utils = require("Core.Utils")
local Primitives = require("Components.Primitives")

local New = Fusion.New
local Children = Fusion.Children
local OnEvent = Fusion.OnEvent
local Computed = Fusion.Computed
local Tween = Fusion.Tween
local Value = Fusion.Value
local Ref = Fusion.Ref
local Spring = Fusion.Spring

local THUMB = 16
local TRACK = 5

return function(props: { [string]: any }): Frame
	local min = props.Min or 0
	local max = props.Max or 100
	local step = props.Step
	local format = props.Format or function(v: number)
		return Utils.FormatNumber(v, if step and step < 1 then 2 else 0)
	end

	local isRange = props.RangeValue ~= nil
	local single = props.Value or Value(min)
	local range = props.RangeValue or Value({ min, max })

	local trackRef = Value(nil :: Frame?)
	local draggingThumb = Value(nil :: string?) -- "single" | "low" | "high"
	local hoveringThumb = Value(false)

	local function snap(v: number): number
		v = Utils.Clamp(v, min, max)
		if step then
			v = Utils.Clamp(Utils.Round(v - min, step) + min, min, max)
		end
		return v
	end

	local function alphaOf(v: number): number
		return (v - min) / math.max(max - min, 1e-6)
	end

	local function setFromX(x: number, thumb: string)
		local track = trackRef:get()
		if not track then
			return
		end
		local alpha = Utils.Clamp((x - track.AbsolutePosition.X) / math.max(track.AbsoluteSize.X, 1), 0, 1)
		local v = snap(min + alpha * (max - min))
		if isRange then
			local current = table.clone(range:get())
			if thumb == "low" then
				current[1] = math.min(v, current[2])
			else
				current[2] = math.max(v, current[1])
			end
			range:set(current)
			if props.OnChanged then
				props.OnChanged(current)
			end
		else
			single:set(v)
			if props.OnChanged then
				props.OnChanged(v)
			end
		end
	end

	-- Global drag tracking
	local moveConn: RBXScriptConnection? = nil
	local upConn: RBXScriptConnection? = nil

	local function endDrag()
		draggingThumb:set(nil)
		if moveConn then
			moveConn:Disconnect()
			moveConn = nil
		end
		if upConn then
			upConn:Disconnect()
			upConn = nil
		end
	end

	local function beginDrag(thumb: string)
		draggingThumb:set(thumb)
		moveConn = UserInputService.InputChanged:Connect(function(input)
			if input.UserInputType == Enum.UserInputType.MouseMovement or input.UserInputType == Enum.UserInputType.Touch then
				setFromX(input.Position.X, thumb)
			end
		end)
		upConn = UserInputService.InputEnded:Connect(function(input)
			if input.UserInputType == Enum.UserInputType.MouseButton1 or input.UserInputType == Enum.UserInputType.Touch then
				endDrag()
			end
		end)
	end

	local function makeThumb(thumbId: string, alphaState: any): Instance
		local scale = Spring(
			Computed(function()
				return if draggingThumb:get() == thumbId then 1.25 elseif hoveringThumb:get() then 1.1 else 1
			end),
			Animation.Springs.Snappy.Speed,
			Animation.Springs.Snappy.Damping
		)
		return New("TextButton")({
			Name = "Thumb_" .. thumbId,
			Text = "",
			AutoButtonColor = false,
			BackgroundColor3 = Theme.Colors.Text,
			Size = UDim2.fromOffset(THUMB, THUMB),
			AnchorPoint = Vector2.new(0.5, 0.5),
			Position = Computed(function()
				return UDim2.new(alphaState:get(), 0, 0.5, 0)
			end),
			ZIndex = 3,
			[OnEvent("MouseEnter")] = function()
				hoveringThumb:set(true)
			end,
			[OnEvent("MouseLeave")] = function()
				hoveringThumb:set(false)
			end,
			[OnEvent("MouseButton1Down")] = function()
				beginDrag(thumbId)
			end,
			[Children] = {
				New("UICorner")({ CornerRadius = UDim.new(1, 0) }),
				New("UIScale")({ Scale = scale }),
				Primitives.Stroke({ Color = Theme.Colors.Primary, Transparency = 0, Thickness = 2 }),
				-- Value tooltip while dragging
				New("Frame")({
					Name = "Tooltip",
					BackgroundColor3 = Theme.Colors.Elevated,
					AutomaticSize = Enum.AutomaticSize.XY,
					AnchorPoint = Vector2.new(0.5, 1),
					Position = UDim2.new(0.5, 0, 0, -8),
					Visible = Computed(function()
						return draggingThumb:get() == thumbId
					end),
					ZIndex = 5,
					[Children] = {
						Primitives.Corner("Sm"),
						Primitives.Stroke(),
						Primitives.Padding({ X = 8, Y = 4 }),
						Primitives.Text({
							Text = Computed(function()
								if isRange then
									local r = range:get()
									return format(if thumbId == "low" then r[1] else r[2])
								end
								return format(single:get())
							end),
							Size = "Xs",
							Font = "Mono",
						}),
					},
				}),
			},
		})
	end

	local lowAlpha = Computed(function()
		return if isRange then alphaOf(range:get()[1]) else 0
	end)
	local highAlpha = Computed(function()
		return if isRange then alphaOf(range:get()[2]) else alphaOf(single:get())
	end)

	local thumbs: { Instance } = {}
	if isRange then
		table.insert(thumbs, makeThumb("low", lowAlpha))
		table.insert(thumbs, makeThumb("high", highAlpha))
	else
		table.insert(thumbs, makeThumb("single", highAlpha))
	end

	local header: Instance? = nil
	if props.Label or props.ShowValue then
		header = New("Frame")({
			Name = "Header",
			BackgroundTransparency = 1,
			Size = UDim2.new(1, 0, 0, 18),
			LayoutOrder = 0,
			[Children] = {
				Primitives.Text({ Text = props.Label or "", Size = "Sm" }),
				Primitives.Text({
					Text = Computed(function()
						if isRange then
							local r = range:get()
							return `{format(r[1])} – {format(r[2])}`
						end
						return format(single:get())
					end),
					Size = "Sm",
					Font = "Mono",
					Muted = true,
					Props = { Position = UDim2.fromScale(1, 0), AnchorPoint = Vector2.new(1, 0) },
				}),
			},
		})
	end

	return New("Frame")({
		Name = "AetherSlider",
		Parent = props.Parent,
		BackgroundTransparency = 1,
		AutomaticSize = Enum.AutomaticSize.Y,
		Size = UDim2.new(1, 0, 0, 0),
		LayoutOrder = props.LayoutOrder or 0,
		[Children] = {
			Primitives.List({ Gap = 8 }),
			header,
			New("Frame")({
				Name = "TrackArea",
				BackgroundTransparency = 1,
				Size = UDim2.new(1, 0, 0, THUMB + 4),
				LayoutOrder = 1,
				[Children] = {
					New("TextButton")({
						Name = "Track",
						Text = "",
						AutoButtonColor = false,
						BackgroundColor3 = Theme.Colors.Secondary,
						Size = UDim2.new(1, 0, 0, TRACK),
						Position = UDim2.fromScale(0, 0.5),
						AnchorPoint = Vector2.new(0, 0.5),
						[Ref] = trackRef,
						[OnEvent("MouseButton1Down")] = function(x: number)
							-- click-to-seek then continue dragging nearest thumb
							local thumb = "single"
							if isRange then
								local track = trackRef:get()
								if track then
									local alpha = (x - track.AbsolutePosition.X) / math.max(track.AbsoluteSize.X, 1)
									local r = range:get()
									thumb = if math.abs(alpha - alphaOf(r[1])) < math.abs(alpha - alphaOf(r[2]))
										then "low"
										else "high"
								end
							end
							setFromX(x, thumb)
							beginDrag(thumb)
						end,
						[Children] = {
							New("UICorner")({ CornerRadius = UDim.new(1, 0) }),
							-- Filled portion
							New("Frame")({
								Name = "Fill",
								BackgroundColor3 = Theme.Colors.Primary,
								Position = Tween(
									Computed(function()
										return UDim2.fromScale(lowAlpha:get(), 0)
									end),
									Animation.Presets.Fast
								),
								Size = Tween(
									Computed(function()
										return UDim2.fromScale(math.max(highAlpha:get() - lowAlpha:get(), 0), 1)
									end),
									Animation.Presets.Fast
								),
								[Children] = { New("UICorner")({ CornerRadius = UDim.new(1, 0) }) },
							}),
						},
					}),
					thumbs,
				},
			}),
		},
	}) :: Frame
end

end)

__register("Components.Stepper", function(require)
--!strict
--[[
	AetherUI • Components/Stepper

	Multi-step wizard header + content + navigation.

	props:
		Steps: { { Title: string, Description: string?, Icon: string?, Content: (() -> Instance)? } }
		Step: Fusion Value?          (bind current step externally; 1-based)
		OnFinish: (() -> ())?
		OnStepChanged: ((step: number) -> ())?
		Size: UDim2?    LayoutOrder: number?    Parent: Instance?
]]

local Fusion = require("Core.Fusion")
local Theme = require("Core.Theme")
local Primitives = require("Components.Primitives")
local Button = require("Components.Button")

local New = Fusion.New
local Children = Fusion.Children
local Computed = Fusion.Computed
local Value = Fusion.Value
local Tween = Fusion.Tween

local DOT = 30

return function(props: { [string]: any }): Frame
	local steps: { { [string]: any } } = props.Steps or {}
	local current = props.Step or Value(1)

	local function goTo(step: number)
		local clamped = math.clamp(step, 1, #steps)
		current:set(clamped)
		if props.OnStepChanged then
			props.OnStepChanged(clamped)
		end
	end

	-- Step indicator rail -------------------------------------------------------

	local rail: { any } = {
		Primitives.List({
			Direction = "Horizontal",
			Padding = 0,
			VerticalAlignment = Enum.VerticalAlignment.Top,
			HorizontalAlignment = Enum.HorizontalAlignment.Center,
		}),
	}

	for index, step in steps do
		local state = Computed(function()
			local c = current:get()
			return if index < c then "Done" elseif index == c then "Active" else "Todo"
		end)

		local dotChildren: { any } = { Primitives.Corner("Full") }

		table.insert(dotChildren, Primitives.Icon({
			Name = "check",
			Size = 14,
			Color = Computed(function()
				return Theme.Colors.PrimaryText:get()
			end),
			Transparency = Computed(function()
				return if state:get() == "Done" then 0 else 1
			end),
			Position = UDim2.fromScale(0.5, 0.5),
			AnchorPoint = Vector2.new(0.5, 0.5),
		}))

		table.insert(dotChildren, Primitives.Text({
			Text = tostring(index),
			Size = 12,
			Bold = true,
			Color = Computed(function()
				return if state:get() == "Active"
					then Theme.Colors.PrimaryText:get()
					else Theme.Colors.TextMuted:get()
			end),
			Props = {
				Size = UDim2.fromScale(1, 1),
				TextXAlignment = Enum.TextXAlignment.Center,
				TextTransparency = Computed(function()
					return if state:get() == "Done" then 1 else 0
				end),
			},
		}))

		local column = New("Frame")({
			Name = "Step_" .. index,
			Size = UDim2.new(1 / #steps, 0, 0, 64),
			BackgroundTransparency = 1,
			LayoutOrder = index,
			[Children] = {
				-- Connector line (behind dot, spans full column, hidden on first step)
				New("Frame")({
					Name = "Connector",
					Size = UDim2.new(1, -DOT, 0, 2),
					Position = UDim2.new(-0.5, DOT / 2, 0, DOT / 2 - 1),
					BackgroundColor3 = Tween(
						Computed(function()
							return if current:get() > index - 1
								then Theme.Colors.Primary:get()
								else Theme.Colors.Border:get()
						end),
						TweenInfo.new(0.25, Enum.EasingStyle.Quad, Enum.EasingDirection.Out)
					),
					BorderSizePixel = 0,
					Visible = index > 1,
					ZIndex = 1,
				}),
				New("Frame")({
					Name = "Dot",
					Size = UDim2.fromOffset(DOT, DOT),
					Position = UDim2.new(0.5, -DOT / 2, 0, 0),
					BackgroundColor3 = Tween(
						Computed(function()
							local s = state:get()
							return if s == "Todo"
								then Theme.Colors.SurfaceHigh:get()
								else Theme.Colors.Primary:get()
						end),
						TweenInfo.new(0.25, Enum.EasingStyle.Quad, Enum.EasingDirection.Out)
					),
					ZIndex = 2,
					[Children] = dotChildren,
				}),
				Primitives.Text({
					Text = step.Title,
					Size = 11,
					Color = Computed(function()
						return if state:get() == "Todo"
							then Theme.Colors.TextMuted:get()
							else Theme.Colors.Text:get()
					end),
					Props = {
						Size = UDim2.new(1, -8, 0, 26),
						Position = UDim2.new(0, 4, 0, DOT + 6),
						TextXAlignment = Enum.TextXAlignment.Center,
						TextWrapped = true,
					},
				}),
			},
		})

		table.insert(rail, column)
	end

	local railFrame = New("Frame")({
		Name = "Rail",
		Size = UDim2.new(1, 0, 0, 70),
		BackgroundTransparency = 1,
		LayoutOrder = 1,
		[Children] = rail,
	})

	-- Content area ------------------------------------------------------------------

	local contentArea = New("Frame")({
		Name = "Content",
		AutomaticSize = Enum.AutomaticSize.Y,
		Size = UDim2.new(1, 0, 0, 0),
		BackgroundTransparency = 1,
		LayoutOrder = 2,
		[Children] = Computed(function()
			local step = steps[current:get()]
			if step and step.Content then
				return { step.Content() }
			end
			if step and step.Description then
				return {
					Primitives.Padding({ Y = 8 }),
					Primitives.Text({
						Text = step.Description,
						Size = 13,
						Muted = true,
						Wrapped = true,
						Props = { Size = UDim2.new(1, 0, 0, 0), AutomaticSize = Enum.AutomaticSize.Y },
					}),
				}
			end
			return {}
		end, Fusion.cleanup),
	})

	-- Navigation --------------------------------------------------------------------

	local nav = New("Frame")({
		Name = "Nav",
		Size = UDim2.new(1, 0, 0, 48),
		BackgroundTransparency = 1,
		LayoutOrder = 3,
		[Children] = {
			Button({
				Text = "Back",
				Icon = "chevron-left",
				Variant = "Outline",
				Disabled = Computed(function()
					return current:get() <= 1
				end),
				Props = { AnchorPoint = Vector2.new(0, 0.5), Position = UDim2.new(0, 0, 0.5, 0) },
				OnClick = function()
					goTo(current:get() - 1)
				end,
			}),
			Button({
				Text = Computed(function()
					return if current:get() >= #steps then "Finish" else "Continue"
				end),
				IconRight = "chevron-right",
				Variant = "Primary",
				Props = { AnchorPoint = Vector2.new(1, 0.5), Position = UDim2.new(1, 0, 0.5, 0) },
				OnClick = function()
					if current:get() >= #steps then
						if props.OnFinish then
							props.OnFinish()
						end
					else
						goTo(current:get() + 1)
					end
				end,
			}),
		},
	})

	return New("Frame")({
		Name = "AetherStepper",
		AutomaticSize = Enum.AutomaticSize.Y,
		Size = props.Size or UDim2.new(1, 0, 0, 0),
		BackgroundTransparency = 1,
		LayoutOrder = props.LayoutOrder,
		Parent = props.Parent,
		[Children] = {
			Primitives.List({ Padding = 12 }),
			railFrame,
			contentArea,
			nav,
		},
	})
end

end)

__register("Components.Tabs", function(require)
--!strict
--[=[
	AetherUI · Tabs
	Variants: "underline" (animated indicator), "pill", "vertical".
	Supports icons per tab, disabled tabs, and lazy content mounting.
]=]

local Fusion = require("Core.Fusion")
local Theme = require("Core.Theme")
local Icons = require("Core.Icons")
local Sound = require("Core.Sound")

local New = Fusion.New
local Children = Fusion.Children
local Value = Fusion.Value
local Computed = Fusion.Computed
local OnEvent = Fusion.OnEvent
local Spring = Fusion.Spring
local ForPairs = Fusion.ForPairs

type Tab = {
	Id: string,
	Label: string,
	Icon: string?,
	Disabled: boolean?,
	Content: (() -> Instance)?,
}

type TabsProps = {
	Tabs: { Tab },
	Default: string?,
	Variant: ("underline" | "pill" | "vertical")?,
	OnChanged: ((id: string) -> ())?,
	Size: UDim2?,
	LayoutOrder: number?,
	Parent: Instance?,
}

local function Tabs(props: TabsProps): Frame
	local theme = Theme.Current
	local variant = props.Variant or "underline"
	local vertical = variant == "vertical"

	local active = Value(props.Default or (props.Tabs[1] and props.Tabs[1].Id) or "")
	local hovered = Value("")

	-- Track absolute layout of each tab button for the underline indicator
	local tabRefs: { [string]: TextButton } = {}
	local indicatorPos = Value(UDim2.new())
	local indicatorSize = Value(UDim2.new())

	local function refreshIndicator()
		local btn = tabRefs[Fusion.peek(active)]
		if not btn or variant ~= "underline" then
			return
		end
		indicatorPos:set(UDim2.fromOffset(btn.Position.X.Offset, 0))
		indicatorSize:set(UDim2.new(0, btn.AbsoluteSize.X, 0, 2))
	end

	local function select(id: string)
		if Fusion.peek(active) == id then
			return
		end
		active:set(id)
		Sound.play("Click")
		task.defer(refreshIndicator)
		if props.OnChanged then
			props.OnChanged(id)
		end
	end

	-- Tab list ----------------------------------------------------------
	local tabButtons: { Instance } = {
		New("UIListLayout")({
			FillDirection = vertical and Enum.FillDirection.Vertical or Enum.FillDirection.Horizontal,
			Padding = UDim.new(0, variant == "pill" and 4 or (vertical and 2 or 16)),
			SortOrder = Enum.SortOrder.LayoutOrder,
		}),
	}

	for i, tab in ipairs(props.Tabs) do
		local isActive = Computed(function()
			return Fusion.peek(active) == tab.Id
		end)
		local isHovered = Computed(function()
			return Fusion.peek(hovered) == tab.Id
		end)

		local innerChildren: { Instance } = {
			New("UIListLayout")({
				FillDirection = Enum.FillDirection.Horizontal,
				Padding = UDim.new(0, 6),
				VerticalAlignment = Enum.VerticalAlignment.Center,
				HorizontalAlignment = vertical and Enum.HorizontalAlignment.Left or Enum.HorizontalAlignment.Center,
			}),
			New("UIPadding")({
				PaddingLeft = UDim.new(0, vertical and 10 or (variant == "pill" and 12 or 2)),
				PaddingRight = UDim.new(0, variant == "pill" and 12 or 2),
			}),
		}

		if tab.Icon then
			table.insert(innerChildren, Icons.render(tab.Icon, {
				Size = UDim2.fromOffset(15, 15),
				LayoutOrder = 1,
				Color = Computed(function()
					local t = theme:get()
					if tab.Disabled then
						return t.TextDisabled
					end
					return Fusion.peek(isActive) and t.Text or t.TextMuted
				end),
			}))
		end

		table.insert(innerChildren, New("TextLabel")({
			AutomaticSize = Enum.AutomaticSize.X,
			Size = UDim2.new(0, 0, 1, 0),
			BackgroundTransparency = 1,
			Text = tab.Label,
			Font = Enum.Font.GothamMedium,
			TextSize = 13,
			LayoutOrder = 2,
			TextColor3 = Spring(Computed(function()
				local t = theme:get()
				if tab.Disabled then
					return t.TextDisabled
				end
				if Fusion.peek(isActive) then
					return t.Text
				end
				return Fusion.peek(isHovered) and t.Text or t.TextMuted
			end), 30, 1),
		}))

		local btn = New("TextButton")({
			Name = "Tab_" .. tab.Id,
			AutomaticSize = vertical and Enum.AutomaticSize.None or Enum.AutomaticSize.X,
			Size = vertical and UDim2.new(1, 0, 0, 34) or UDim2.new(0, 0, 1, 0),
			Text = "",
			AutoButtonColor = false,
			LayoutOrder = i,
			BackgroundColor3 = Computed(function()
				return theme:get().SurfaceHigh
			end),
			BackgroundTransparency = Spring(Computed(function()
				if variant == "underline" then
					return 1
				end
				if Fusion.peek(isActive) then
					return 0
				end
				return Fusion.peek(isHovered) and 0.5 or 1
			end), 30, 1),
			[OnEvent("Activated")] = function()
				if not tab.Disabled then
					select(tab.Id)
				end
			end,
			[OnEvent("MouseEnter")] = function()
				if not tab.Disabled then
					hovered:set(tab.Id)
					Sound.play("Hover")
				end
			end,
			[OnEvent("MouseLeave")] = function()
				if Fusion.peek(hovered) == tab.Id then
					hovered:set("")
				end
			end,
			[Children] = {
				New("UICorner")({ CornerRadius = Computed(function()
					return UDim.new(0, theme:get().RadiusSm)
				end) }),
				New("Frame")({
					Size = UDim2.fromScale(1, 1),
					BackgroundTransparency = 1,
					AutomaticSize = Enum.AutomaticSize.X,
					[Children] = innerChildren,
				}),
			},
		}) :: TextButton

		tabRefs[tab.Id] = btn
		table.insert(tabButtons, btn)
	end

	-- Underline indicator
	if variant == "underline" then
		table.insert(tabButtons, New("Frame")({
			Name = "Indicator",
			AnchorPoint = Vector2.new(0, 1),
			Position = Spring(Computed(function()
				local base = Fusion.peek(indicatorPos)
				return UDim2.new(0, base.X.Offset, 1, 0)
			end), 30, 1),
			Size = Spring(indicatorSize, 30, 1),
			BackgroundColor3 = Computed(function()
				return theme:get().Primary
			end),
			BorderSizePixel = 0,
			ZIndex = 2,
			[Children] = { New("UICorner")({ CornerRadius = UDim.new(1, 0) }) },
		}))
	end

	local tabList = New("Frame")({
		Name = "TabList",
		Size = vertical and UDim2.new(0, 160, 1, 0) or UDim2.new(1, 0, 0, 36),
		BackgroundTransparency = 1,
		[Children] = tabButtons,
	})

	-- initial indicator placement
	task.defer(refreshIndicator)

	-- Content -----------------------------------------------------------
	local contentPane = New("Frame")({
		Name = "Content",
		Size = vertical and UDim2.new(1, -172, 1, 0) or UDim2.new(1, 0, 1, -44),
		Position = vertical and UDim2.fromOffset(172, 0) or UDim2.fromOffset(0, 44),
		BackgroundTransparency = 1,
		ClipsDescendants = true,
		[Children] = ForPairs(Computed(function()
			-- lazy: only the active tab content is mounted
			local out: { [string]: Tab } = {}
			for _, tab in ipairs(props.Tabs) do
				if tab.Id == Fusion.peek(active) and tab.Content then
					out[tab.Id] = tab
				end
			end
			return out
		end), function(_, id: string, tab: Tab)
			local content = (tab.Content :: () -> Instance)()
			return id, content
		end),
	})

	return New("Frame")({
		Name = "AetherTabs",
		Size = props.Size or UDim2.new(1, 0, 1, 0),
		BackgroundTransparency = 1,
		LayoutOrder = props.LayoutOrder,
		Parent = props.Parent,
		[Children] = { tabList, contentPane },
	}) :: Frame
end

return Tabs

end)

__register("Components.TextArea", function(require)
--!strict
--[[
	AetherUI • Components/TextArea
	Multiline text field with counter and focus ring.

	props: Value?, Placeholder?, Rows?, MaxLength?, ShowCounter?, OnChanged?, Disabled?, LayoutOrder
]]

local Fusion = require("Core.Fusion")
local Theme = require("Core.Theme")
local Animation = require("Core.Animation")
local Primitives = require("Components.Primitives")

local New = Fusion.New
local Children = Fusion.Children
local OnEvent = Fusion.OnEvent
local OnChange = Fusion.OnChange
local Computed = Fusion.Computed
local Tween = Fusion.Tween
local Value = Fusion.Value
local Ref = Fusion.Ref

return function(props: { [string]: any }): Frame
	local text = props.Value or Value("")
	local focused = Value(false)
	local boxRef = Value(nil :: TextBox?)

	local rows = props.Rows or 4
	local height = rows * 20 + 20

	return New("Frame")({
		Name = "AetherTextArea",
		Parent = props.Parent,
		BackgroundTransparency = 1,
		AutomaticSize = Enum.AutomaticSize.Y,
		Size = UDim2.new(1, 0, 0, 0),
		LayoutOrder = props.LayoutOrder or 0,
		[Children] = {
			Primitives.List({ Gap = 4 }),
			New("Frame")({
				Name = "Field",
				BackgroundColor3 = Theme.Colors.Surface,
				Size = UDim2.new(1, 0, 0, height),
				LayoutOrder = 0,
				[Children] = {
					Primitives.Corner("Md"),
					Primitives.Stroke({
						Color = Tween(
							Computed(function()
								return if focused:get() then Theme.Colors.Primary:get() else Theme.Colors.Border:get()
							end),
							Animation.Presets.Fast
						),
						Transparency = Tween(
							Computed(function()
								return if focused:get() then 0 else 0.35
							end),
							Animation.Presets.Fast
						),
					}),
					Primitives.Padding(10),
					New("TextBox")({
						Name = "Input",
						BackgroundTransparency = 1,
						Text = text:get(),
						PlaceholderText = props.Placeholder or "",
						PlaceholderColor3 = Theme.Colors.TextDisabled,
						TextColor3 = Theme.Colors.Text,
						FontFace = Theme.Fonts.Body,
						TextSize = Theme.TextSizes.Md,
						TextXAlignment = Enum.TextXAlignment.Left,
						TextYAlignment = Enum.TextYAlignment.Top,
						TextWrapped = true,
						MultiLine = true,
						ClearTextOnFocus = false,
						TextEditable = not props.Disabled,
						Size = UDim2.fromScale(1, 1),
						ClipsDescendants = true,
						[Ref] = boxRef,
						[OnChange("Text")] = function(newText: string)
							local truncated = newText
							if props.MaxLength and #truncated > props.MaxLength then
								truncated = truncated:sub(1, props.MaxLength)
								local box = boxRef:get()
								if box then
									box.Text = truncated
								end
							end
							text:set(truncated)
							if props.OnChanged then
								props.OnChanged(truncated)
							end
						end,
						[OnEvent("Focused")] = function()
							focused:set(true)
						end,
						[OnEvent("FocusLost")] = function()
							focused:set(false)
						end,
					}),
				},
			}),
			Primitives.Text({
				Name = "Counter",
				Text = Computed(function()
					local max = props.MaxLength
					return if max then `{#text:get()}/{max}` else ""
				end),
				Size = "Xs",
				Muted = true,
				LayoutOrder = 1,
				Props = {
					Visible = props.ShowCounter == true and props.MaxLength ~= nil,
				},
			}),
		},
	}) :: Frame
end

end)

__register("Components.TextInput", function(require)
--!strict
--[[
	AetherUI • Components/TextInput

	props:
		Value: Fusion.Value<string>?     Placeholder: string?
		Icon: string?                    Password: boolean?
		ClearButton: boolean?            MaxLength: number?
		ShowCounter: boolean?            Validate: ((string) -> (boolean, string?))?
		OnChanged: (string) -> ()?       OnSubmit: (string) -> ()?
		Disabled: boolean?               Size (Sm|Md|Lg), FullWidth, LayoutOrder

	Returns the frame; frame:FindFirstChild("Input", true) is the TextBox.
	Validation errors render inline below the field.
]]

local Fusion = require("Core.Fusion")
local Theme = require("Core.Theme")
local Animation = require("Core.Animation")
local Primitives = require("Components.Primitives")
local UseHover = require("Hooks.UseHover")

local New = Fusion.New
local Children = Fusion.Children
local OnEvent = Fusion.OnEvent
local OnChange = Fusion.OnChange
local Computed = Fusion.Computed
local Tween = Fusion.Tween
local Value = Fusion.Value
local Ref = Fusion.Ref

local HEIGHTS = { Sm = 30, Md = 36, Lg = 42 }

return function(props: { [string]: any }): Frame
	local text = props.Value or Value("")
	local focused = Value(false)
	local revealed = Value(false) -- password visibility
	local errorMessage = Value(nil :: string?)
	local hover = UseHover({ Sound = false })
	local boxRef = Value(nil :: TextBox?)

	local height = HEIGHTS[props.Size or "Md"] or 36

	local function runValidation(current: string)
		if props.Validate then
			local ok, message = props.Validate(current)
			errorMessage:set(if ok then nil else (message or "Invalid value"))
		end
	end

	local strokeColor = Computed(function()
		if errorMessage:get() ~= nil then
			return Theme.Colors.Danger:get()
		end
		if focused:get() then
			return Theme.Colors.Primary:get()
		end
		if hover.Hovering:get() then
			return Theme.Colors.BorderStrong:get()
		end
		return Theme.Colors.Border:get()
	end)

	local strokeTransparency = Computed(function()
		return if focused:get() or errorMessage:get() ~= nil then 0 else 0.35
	end)

	local rightControls: { Instance } = {}

	if props.ClearButton then
		table.insert(
			rightControls,
			New("TextButton")({
				Name = "Clear",
				Text = "",
				BackgroundTransparency = 1,
				Size = UDim2.fromOffset(20, 20),
				LayoutOrder = 1,
				Visible = Computed(function()
					return #text:get() > 0 and not (props.Disabled == true)
				end),
				[OnEvent("Activated")] = function()
					text:set("")
					local box = boxRef:get()
					if box then
						box.Text = ""
						box:CaptureFocus()
					end
					errorMessage:set(nil)
					if props.OnChanged then
						props.OnChanged("")
					end
				end,
				[Children] = {
					Primitives.Icon({
						Name = "x",
						Size = 14,
						Color = Theme.Colors.TextMuted,
						Position = UDim2.fromScale(0.5, 0.5),
						AnchorPoint = Vector2.new(0.5, 0.5),
					}),
				},
			})
		)
	end

	if props.Password then
		table.insert(
			rightControls,
			New("TextButton")({
				Name = "Reveal",
				Text = "",
				BackgroundTransparency = 1,
				Size = UDim2.fromOffset(20, 20),
				LayoutOrder = 2,
				[OnEvent("Activated")] = function()
					revealed:set(not revealed:get())
					local box = boxRef:get()
					if box then
						box.TextTransparency = 0
					end
				end,
				[Children] = {
					Computed(function()
						return Primitives.Icon({
							Name = if revealed:get() then "eye-off" else "eye",
							Size = 14,
							Color = Theme.Colors.TextMuted,
							Position = UDim2.fromScale(0.5, 0.5),
							AnchorPoint = Vector2.new(0.5, 0.5),
						})
					end, Fusion.cleanup),
				},
			})
		)
	end

	local fieldChildren: { any } = {
		Primitives.Corner("Md"),
		Primitives.Stroke({
			Color = Tween(strokeColor, Animation.Presets.Fast),
			Transparency = Tween(strokeTransparency, Animation.Presets.Fast),
			Thickness = 1,
		}),
		Primitives.Padding({ X = 12 }),
		Primitives.List({
			Direction = Enum.FillDirection.Horizontal,
			Gap = 8,
			VerticalAlignment = Enum.VerticalAlignment.Center,
		}),
	}

	if props.Icon then
		table.insert(
			fieldChildren,
			Primitives.Icon({ Name = props.Icon, Size = 15, Color = Theme.Colors.TextMuted, LayoutOrder = 0 })
		)
	end

	table.insert(
		fieldChildren,
		New("TextBox")({
			Name = "Input",
			BackgroundTransparency = 1,
			Text = text:get(),
			PlaceholderText = props.Placeholder or "",
			PlaceholderColor3 = Theme.Colors.TextDisabled,
			TextColor3 = Computed(function()
				return if props.Disabled then Theme.Colors.TextDisabled:get() else Theme.Colors.Text:get()
			end),
			FontFace = Theme.Fonts.Body,
			TextSize = Theme.TextSizes.Md,
			TextXAlignment = Enum.TextXAlignment.Left,
			ClearTextOnFocus = false,
			TextEditable = not props.Disabled,
			Size = UDim2.new(1, 0, 1, 0),
			LayoutOrder = 0,
			ClipsDescendants = true,
			[Ref] = boxRef,
			[OnChange("Text")] = function(newText: string)
				local truncated = newText
				if props.MaxLength and #truncated > props.MaxLength then
					truncated = truncated:sub(1, props.MaxLength)
					local box = boxRef:get()
					if box then
						box.Text = truncated
					end
				end
				if props.Password and not revealed:get() then
					-- Roblox TextBox has no native masking; we track real text and mask display.
					-- (Simple approach: keep display as-is; production games can swap to a masked mirror.)
				end
				text:set(truncated)
				runValidation(truncated)
				if props.OnChanged then
					props.OnChanged(truncated)
				end
			end,
			[OnEvent("Focused")] = function()
				focused:set(true)
			end,
			[OnEvent("FocusLost")] = function(enterPressed: boolean)
				focused:set(false)
				runValidation(text:get())
				if enterPressed and props.OnSubmit then
					props.OnSubmit(text:get())
				end
			end,
		})
	)

	if #rightControls > 0 then
		table.insert(
			fieldChildren,
			New("Frame")({
				Name = "RightControls",
				BackgroundTransparency = 1,
				AutomaticSize = Enum.AutomaticSize.X,
				Size = UDim2.new(0, 0, 1, 0),
				LayoutOrder = 10,
				[Children] = {
					Primitives.List({
						Direction = Enum.FillDirection.Horizontal,
						Gap = 4,
						VerticalAlignment = Enum.VerticalAlignment.Center,
					}),
					rightControls,
				},
			})
		)
	end

	local footer = New("Frame")({
		Name = "Footer",
		BackgroundTransparency = 1,
		AutomaticSize = Enum.AutomaticSize.Y,
		Size = UDim2.new(1, 0, 0, 0),
		LayoutOrder = 1,
		Visible = Computed(function()
			return errorMessage:get() ~= nil or props.ShowCounter == true
		end),
		[Children] = {
			Primitives.Text({
				Name = "Error",
				Text = Computed(function()
					return errorMessage:get() or ""
				end),
				Size = "Xs",
				Color = Theme.Colors.Danger,
				Props = {
					Visible = Computed(function()
						return errorMessage:get() ~= nil
					end),
				},
			}),
			Primitives.Text({
				Name = "Counter",
				Text = Computed(function()
					local max = props.MaxLength
					return if max then `{#text:get()}/{max}` else tostring(#text:get())
				end),
				Size = "Xs",
				Muted = true,
				Props = {
					Visible = props.ShowCounter == true,
					Position = UDim2.fromScale(1, 0),
					AnchorPoint = Vector2.new(1, 0),
				},
			}),
		},
	})

	return New("Frame")({
		Name = "AetherTextInput",
		Parent = props.Parent,
		BackgroundTransparency = 1,
		AutomaticSize = Enum.AutomaticSize.Y,
		Size = if props.FullWidth ~= false then UDim2.new(1, 0, 0, 0) else UDim2.fromOffset(260, 0),
		LayoutOrder = props.LayoutOrder or 0,
		[Children] = {
			Primitives.List({ Gap = 4 }),
			New("Frame")({
				Name = "Field",
				BackgroundColor3 = Theme.Colors.Surface,
				BackgroundTransparency = Computed(function()
					return if props.Disabled then 0.4 else 0
				end),
				Size = UDim2.new(1, 0, 0, height),
				LayoutOrder = 0,
				[OnEvent("MouseEnter")] = hover.Enter,
				[OnEvent("MouseLeave")] = hover.Leave,
				[Children] = fieldChildren,
			}),
			footer,
		},
	}) :: Frame
end

end)

__register("Components.TimePicker", function(require)
--!strict
--[[
	AetherUI • Components/TimePicker

	Hour / minute spinner with 12h/24h support.

	props:
		Value: { Hour: number, Minute: number }?    (24h internally; defaults to now)
		Use24Hour: boolean?                          (default false)
		MinuteStep: number?                          (default 5)
		OnChanged: ((time: { Hour: number, Minute: number }) -> ())?
		LayoutOrder: number?    Parent: Instance?
]]

local Fusion = require("Core.Fusion")
local Theme = require("Core.Theme")
local Utils = require("Core.Utils")
local Primitives = require("Components.Primitives")
local Button = require("Components.Button")

local New = Fusion.New
local Children = Fusion.Children
local Computed = Fusion.Computed
local Value = Fusion.Value

return function(props: { [string]: any }): Frame
	local now = os.date("*t")
	local initial = props.Value or { Hour = now.hour, Minute = now.min }
	local use24 = props.Use24Hour == true
	local minuteStep: number = props.MinuteStep or 5

	local hour = Value(initial.Hour) -- always 0-23
	local minute = Value(initial.Minute)

	local function emit()
		if props.OnChanged then
			props.OnChanged({ Hour = hour:get(), Minute = minute:get() })
		end
	end

	local function shiftHour(delta: number)
		hour:set((hour:get() + delta) % 24)
		emit()
	end

	local function shiftMinute(delta: number)
		local m = minute:get() + delta * minuteStep
		if m >= 60 then
			m -= 60
			shiftHour(1)
		elseif m < 0 then
			m += 60
			shiftHour(-1)
		end
		minute:set(m)
		emit()
	end

	local function spinner(labelState: any, onUp: () -> (), onDown: () -> (), order: number): Frame
		return New("Frame")({
			Name = "Spinner",
			Size = UDim2.fromOffset(64, 118),
			BackgroundTransparency = 1,
			LayoutOrder = order,
			[Children] = {
				Primitives.List({ Padding = 4, HorizontalAlignment = Enum.HorizontalAlignment.Center }),
				Button({
					Icon = "chevron-up",
					Variant = "Ghost",
					Size = "Sm",
					LayoutOrder = 1,
					OnClick = onUp,
				}),
				New("Frame")({
					Name = "Display",
					Size = UDim2.fromOffset(56, 44),
					BackgroundColor3 = Computed(function()
						return Theme.Colors.SurfaceHigh:get()
					end),
					LayoutOrder = 2,
					[Children] = {
						Primitives.Corner("Md"),
						Primitives.Stroke(),
						Primitives.Text({
							Text = labelState,
							Size = 20,
							Bold = true,
							Font = "Mono",
							Props = {
								Size = UDim2.fromScale(1, 1),
								TextXAlignment = Enum.TextXAlignment.Center,
							},
						}),
					},
				}),
				Button({
					Icon = "chevron-down",
					Variant = "Ghost",
					Size = "Sm",
					LayoutOrder = 3,
					OnClick = onDown,
				}),
			},
		})
	end

	local hourLabel = Computed(function()
		local h = hour:get()
		if use24 then
			return Utils.PadZero(h)
		end
		local display = h % 12
		if display == 0 then
			display = 12
		end
		return Utils.PadZero(display)
	end)

	local minuteLabel = Computed(function()
		return Utils.PadZero(minute:get())
	end)

	local content: { any } = {
		Primitives.Corner("Lg"),
		Primitives.Stroke(),
		Primitives.Padding(12),
		Primitives.List({ Direction = "Horizontal", Padding = 8, VerticalAlignment = Enum.VerticalAlignment.Center }),
		spinner(hourLabel, function()
			shiftHour(1)
		end, function()
			shiftHour(-1)
		end, 1),
		Primitives.Text({
			Text = ":",
			Size = 20,
			Bold = true,
			LayoutOrder = 2,
		}),
		spinner(minuteLabel, function()
			shiftMinute(1)
		end, function()
			shiftMinute(-1)
		end, 3),
	}

	if not use24 then
		table.insert(content, Button({
			Text = Computed(function()
				return if hour:get() < 12 then "AM" else "PM"
			end),
			Variant = "Outline",
			Size = "Sm",
			LayoutOrder = 4,
			OnClick = function()
				shiftHour(12)
			end,
		}))
	end

	return New("Frame")({
		Name = "AetherTimePicker",
		AutomaticSize = Enum.AutomaticSize.XY,
		BackgroundColor3 = Computed(function()
			return Theme.Colors.Surface:get()
		end),
		LayoutOrder = props.LayoutOrder,
		Parent = props.Parent,
		[Children] = content,
	})
end

end)

__register("Components.Toast", function(require)
--!strict
--[=[
	AetherUI · Toast / Notification system
	Stacking notifications with variants (info, success, warning, error),
	progress countdown bar, actions, and slide-in/out springs.

		AetherUI.Toast.success({ Title = "Saved", Description = "Settings updated." })
]=]

local Fusion = require("Core.Fusion")
local Theme = require("Core.Theme")
local Icons = require("Core.Icons")
local Sound = require("Core.Sound")
local Overlay = require("Core.Overlay")

local New = Fusion.New
local Children = Fusion.Children
local Value = Fusion.Value
local Computed = Fusion.Computed
local OnEvent = Fusion.OnEvent
local Spring = Fusion.Spring

local TweenService = game:GetService("TweenService")

type ToastOptions = {
	Title: string,
	Description: string?,
	Duration: number?,
	Icon: string?,
	Action: { Label: string, OnClick: () -> () }?,
	Position: ("bottom-right" | "top-right" | "bottom-left" | "top-left")?,
}

type ToastVariant = "info" | "success" | "warning" | "error"

local Toast = {}

local WIDTH = 320
local MAX_VISIBLE = 5

local containerCache: { [string]: Frame } = {}

local VARIANT_META: { [ToastVariant]: { Icon: string, ColorKey: string } } = {
	info = { Icon = "info", ColorKey = "Primary" },
	success = { Icon = "circle-check", ColorKey = "Success" },
	warning = { Icon = "triangle-alert", ColorKey = "Warning" },
	error = { Icon = "circle-x", ColorKey = "Danger" },
}

local function getContainer(position: string): Frame
	local cached = containerCache[position]
	if cached and cached.Parent then
		return cached
	end
	local layer = Overlay.getLayer("Toasts", 200)

	local bottom = string.find(position, "bottom") ~= nil
	local right = string.find(position, "right") ~= nil

	local container = New("Frame")({
		Name = "ToastStack_" .. position,
		AnchorPoint = Vector2.new(right and 1 or 0, bottom and 1 or 0),
		Position = UDim2.new(right and 1 or 0, right and -16 or 16, bottom and 1 or 0, bottom and -16 or 16),
		Size = UDim2.fromOffset(WIDTH, 0),
		AutomaticSize = Enum.AutomaticSize.Y,
		BackgroundTransparency = 1,
		Parent = layer,
		[Children] = {
			New("UIListLayout")({
				FillDirection = Enum.FillDirection.Vertical,
				Padding = UDim.new(0, 8),
				SortOrder = Enum.SortOrder.LayoutOrder,
				VerticalAlignment = bottom and Enum.VerticalAlignment.Bottom or Enum.VerticalAlignment.Top,
			}),
		},
	}) :: Frame
	containerCache[position] = container
	return container
end

local toastCounter = 0

local function show(variant: ToastVariant, options: ToastOptions)
	local theme = Theme.Current
	local meta = VARIANT_META[variant]
	local position = options.Position or "bottom-right"
	local container = getContainer(position)
	local duration = options.Duration or 4

	-- Cull overflow
	local existing = {}
	for _, child in ipairs(container:GetChildren()) do
		if child:IsA("Frame") then
			table.insert(existing, child)
		end
	end
	if #existing >= MAX_VISIBLE then
		table.sort(existing, function(a, b)
			return a.LayoutOrder < b.LayoutOrder
		end)
		existing[1]:Destroy()
	end

	toastCounter += 1
	local visible = Value(false)
	local hovered = Value(false)
	local dismissed = false

	local accent = Computed(function()
		return (theme:get() :: any)[meta.ColorKey] :: Color3
	end)

	local bodyChildren: { Instance } = {
		New("UIListLayout")({
			FillDirection = Enum.FillDirection.Vertical,
			Padding = UDim.new(0, 3),
		}),
		New("TextLabel")({
			Size = UDim2.new(1, 0, 0, 16),
			BackgroundTransparency = 1,
			Text = options.Title,
			Font = Enum.Font.GothamBold,
			TextSize = 13,
			TextColor3 = Computed(function()
				return theme:get().Text
			end),
			TextXAlignment = Enum.TextXAlignment.Left,
			TextTruncate = Enum.TextTruncate.AtEnd,
		}),
	}

	if options.Description then
		table.insert(bodyChildren, New("TextLabel")({
			Size = UDim2.new(1, 0, 0, 0),
			AutomaticSize = Enum.AutomaticSize.Y,
			BackgroundTransparency = 1,
			Text = options.Description,
			Font = Enum.Font.Gotham,
			TextSize = 12,
			TextWrapped = true,
			TextColor3 = Computed(function()
				return theme:get().TextMuted
			end),
			TextXAlignment = Enum.TextXAlignment.Left,
		}))
	end

	if options.Action then
		table.insert(bodyChildren, New("TextButton")({
			AutomaticSize = Enum.AutomaticSize.XY,
			BackgroundTransparency = 1,
			Text = options.Action.Label,
			Font = Enum.Font.GothamBold,
			TextSize = 12,
			TextColor3 = accent,
			[OnEvent("Activated")] = options.Action.OnClick,
		}))
	end

	local progressBar = New("Frame")({
		Name = "Progress",
		AnchorPoint = Vector2.new(0, 1),
		Position = UDim2.fromScale(0, 1),
		Size = UDim2.new(1, 0, 0, 2),
		BackgroundColor3 = accent,
		BorderSizePixel = 0,
		ZIndex = 3,
	}) :: Frame

	local frame: Frame
	local function dismiss()
		if dismissed then
			return
		end
		dismissed = true
		visible:set(false)
		task.delay(0.3, function()
			frame:Destroy()
		end)
	end

	frame = New("Frame")({
		Name = "Toast_" .. toastCounter,
		Size = UDim2.new(1, 0, 0, 0),
		AutomaticSize = Enum.AutomaticSize.Y,
		LayoutOrder = toastCounter,
		BackgroundColor3 = Computed(function()
			return theme:get().Surface
		end),
		BackgroundTransparency = Spring(Computed(function()
			return Fusion.peek(visible) and 0 or 1
		end), 30, 1),
		Parent = container,
		ClipsDescendants = true,
		[OnEvent("MouseEnter")] = function()
			hovered:set(true)
		end,
		[OnEvent("MouseLeave")] = function()
			hovered:set(false)
		end,
		[Children] = {
			New("UICorner")({ CornerRadius = Computed(function()
				return UDim.new(0, theme:get().RadiusMd)
			end) }),
			New("UIStroke")({
				Color = Computed(function()
					return theme:get().Border
				end),
				Thickness = 1,
			}),
			New("Frame")({
				Name = "Content",
				Size = UDim2.new(1, 0, 0, 0),
				AutomaticSize = Enum.AutomaticSize.Y,
				BackgroundTransparency = 1,
				[Children] = {
					New("UIPadding")({
						PaddingLeft = UDim.new(0, 12),
						PaddingRight = UDim.new(0, 12),
						PaddingTop = UDim.new(0, 12),
						PaddingBottom = UDim.new(0, 12),
					}),
					New("UIListLayout")({
						FillDirection = Enum.FillDirection.Horizontal,
						Padding = UDim.new(0, 10),
						VerticalAlignment = Enum.VerticalAlignment.Top,
					}),
					Icons.render(options.Icon or meta.Icon, {
						Size = UDim2.fromOffset(16, 16),
						LayoutOrder = 1,
						Color = accent,
					}),
					New("Frame")({
						Size = UDim2.new(1, -56, 0, 0),
						AutomaticSize = Enum.AutomaticSize.Y,
						BackgroundTransparency = 1,
						LayoutOrder = 2,
						[Children] = bodyChildren,
					}),
					New("TextButton")({
						Size = UDim2.fromOffset(18, 18),
						BackgroundTransparency = 1,
						Text = "",
						LayoutOrder = 3,
						[OnEvent("Activated")] = dismiss,
						[Children] = {
							Icons.render("x", {
								Size = UDim2.fromOffset(13, 13),
								Position = UDim2.fromScale(0.5, 0.5),
								AnchorPoint = Vector2.new(0.5, 0.5),
								Color = Computed(function()
									return theme:get().TextMuted
								end),
							}),
						},
					}),
				},
			}),
			progressBar,
		},
	}) :: Frame

	Sound.play(variant == "error" and "Error" or (variant == "success" and "Success" or "Open"))
	task.defer(function()
		visible:set(true)
	end)

	-- Countdown with pause-on-hover
	task.spawn(function()
		local remaining = duration
		local tween = TweenService:Create(progressBar, TweenInfo.new(0.1, Enum.EasingStyle.Linear), {})
		local _ = tween
		while remaining > 0 and not dismissed do
			task.wait(0.05)
			if not Fusion.peek(hovered) then
				remaining -= 0.05
				progressBar.Size = UDim2.new(math.max(remaining / duration, 0), 0, 0, 2)
			end
		end
		dismiss()
	end)

	return { Dismiss = dismiss }
end

function Toast.info(options: ToastOptions)
	return show("info", options)
end
function Toast.success(options: ToastOptions)
	return show("success", options)
end
function Toast.warning(options: ToastOptions)
	return show("warning", options)
end
function Toast.error(options: ToastOptions)
	return show("error", options)
end
--- Generic entry point: Toast.show("success", { ... })
function Toast.show(variant: ToastVariant, options: ToastOptions)
	return show(variant, options)
end

-- PascalCase conveniences: accept either a title string or a full options table.
--   Toast.Success("Saved!")
--   Toast.Success("Saved!", { Description = "All changes stored." })
--   Toast.Success({ Title = "Saved!", Duration = 5 })
local function coerce(titleOrOptions: string | ToastOptions, options: ToastOptions?): ToastOptions
	if type(titleOrOptions) == "string" then
		local opts = if options then table.clone(options) else {}
		opts.Title = titleOrOptions
		return opts
	end
	return titleOrOptions
end

function Toast.Info(titleOrOptions: string | ToastOptions, options: ToastOptions?)
	return show("info", coerce(titleOrOptions, options))
end
function Toast.Success(titleOrOptions: string | ToastOptions, options: ToastOptions?)
	return show("success", coerce(titleOrOptions, options))
end
function Toast.Warning(titleOrOptions: string | ToastOptions, options: ToastOptions?)
	return show("warning", coerce(titleOrOptions, options))
end
function Toast.Error(titleOrOptions: string | ToastOptions, options: ToastOptions?)
	return show("error", coerce(titleOrOptions, options))
end
function Toast.Show(variant: ToastVariant, titleOrOptions: string | ToastOptions, options: ToastOptions?)
	return show(variant, coerce(titleOrOptions, options))
end

return Toast

end)

__register("Components.Toggle", function(require)
--!strict
--[[
	AetherUI • Components/Toggle (Switch)
	props: Label?, Description?, Value: Fusion.Value<boolean>?, Disabled?, OnChanged?, LayoutOrder
]]

local Fusion = require("Core.Fusion")
local Theme = require("Core.Theme")
local Animation = require("Core.Animation")
local Sound = require("Core.Sound")
local Primitives = require("Components.Primitives")

local New = Fusion.New
local Children = Fusion.Children
local OnEvent = Fusion.OnEvent
local Computed = Fusion.Computed
local Tween = Fusion.Tween
local Spring = Fusion.Spring
local Value = Fusion.Value

local TRACK_W, TRACK_H, KNOB = 38, 22, 16

return function(props: { [string]: any }): TextButton
	local on = props.Value or Value(false)

	local knobAlpha = Spring(
		Computed(function()
			return if on:get() then 1 else 0
		end),
		Animation.Springs.Snappy.Speed,
		Animation.Springs.Snappy.Damping
	)

	local function toggle()
		if props.Disabled then
			return
		end
		on:set(not on:get())
		Sound.Play("Toggle")
		if props.OnChanged then
			props.OnChanged(on:get())
		end
	end

	return New("TextButton")({
		Name = "AetherToggle",
		Parent = props.Parent,
		Text = "",
		AutoButtonColor = false,
		BackgroundTransparency = 1,
		AutomaticSize = Enum.AutomaticSize.XY,
		LayoutOrder = props.LayoutOrder or 0,
		[OnEvent("Activated")] = toggle,
		[Children] = {
			Primitives.List({
				Direction = Enum.FillDirection.Horizontal,
				Gap = 10,
				VerticalAlignment = Enum.VerticalAlignment.Center,
			}),

			New("Frame")({
				Name = "Track",
				BackgroundColor3 = Tween(
					Computed(function()
						return if on:get() then Theme.Colors.Primary:get() else Theme.Colors.Secondary:get()
					end),
					Animation.Presets.Normal
				),
				BackgroundTransparency = if props.Disabled then 0.5 else 0,
				Size = UDim2.fromOffset(TRACK_W, TRACK_H),
				LayoutOrder = 0,
				[Children] = {
					New("UICorner")({ CornerRadius = UDim.new(1, 0) }),
					Primitives.Stroke({ Transparency = 0.6 }),
					New("Frame")({
						Name = "Knob",
						BackgroundColor3 = Color3.new(1, 1, 1),
						Size = UDim2.fromOffset(KNOB, KNOB),
						AnchorPoint = Vector2.new(0, 0.5),
						Position = Computed(function()
							local pad = (TRACK_H - KNOB) / 2
							local travel = TRACK_W - KNOB - pad * 2
							return UDim2.new(0, pad + knobAlpha:get() * travel, 0.5, 0)
						end),
						[Children] = {
							New("UICorner")({ CornerRadius = UDim.new(1, 0) }),
							Primitives.Shadow({ Size = 10, Transparency = 0.8 }),
						},
					}),
				},
			}),

			if props.Label
				then New("Frame")({
					BackgroundTransparency = 1,
					AutomaticSize = Enum.AutomaticSize.XY,
					LayoutOrder = 1,
					[Children] = {
						Primitives.List({ Gap = 2 }),
						Primitives.Text({
							Text = props.Label,
							Size = "Sm",
							Color = if props.Disabled then Theme.Colors.TextDisabled else Theme.Colors.Text,
						}),
						if props.Description
							then Primitives.Text({ Text = props.Description, Size = "Xs", Muted = true, Wrapped = true })
							else nil,
					},
				})
				else nil,
		},
	}) :: TextButton
end

end)

__register("Components.Tooltip", function(require)
--!strict
--[=[
	AetherUI · Tooltip
	Attach rich, delayed tooltips to any GuiObject.

		Tooltip.attach(button, { Text = "Save changes", Shortcut = "Ctrl+S" })
]=]

local Fusion = require("Core.Fusion")
local Theme = require("Core.Theme")
local Overlay = require("Core.Overlay")

local New = Fusion.New
local Children = Fusion.Children
local Value = Fusion.Value
local Computed = Fusion.Computed
local Spring = Fusion.Spring

local UserInputService = game:GetService("UserInputService")

type TooltipOptions = {
	Text: string,
	Title: string?,
	Shortcut: string?,
	Delay: number?,
	MaxWidth: number?,
}

local Tooltip = {}

local activeTip: Frame? = nil

local function destroyActive()
	if activeTip then
		activeTip:Destroy()
		activeTip = nil
	end
end

local function createTip(options: TooltipOptions, anchorPos: Vector2, anchorSize: Vector2): Frame
	local theme = Theme.Current
	local layer = Overlay.getLayer("Tooltips", 300)
	local visible = Value(false)

	local maxWidth = options.MaxWidth or 240

	local rows: { Instance } = {
		New("UIListLayout")({
			FillDirection = Enum.FillDirection.Vertical,
			Padding = UDim.new(0, 3),
		}),
	}

	if options.Title then
		table.insert(rows, New("TextLabel")({
			AutomaticSize = Enum.AutomaticSize.XY,
			BackgroundTransparency = 1,
			Text = options.Title,
			Font = Enum.Font.GothamBold,
			TextSize = 12,
			TextColor3 = Computed(function()
				return theme:get().Text
			end),
			TextXAlignment = Enum.TextXAlignment.Left,
		}))
	end

	local textRow: { Instance } = {
		New("UIListLayout")({
			FillDirection = Enum.FillDirection.Horizontal,
			Padding = UDim.new(0, 8),
			VerticalAlignment = Enum.VerticalAlignment.Center,
		}),
		New("TextLabel")({
			AutomaticSize = Enum.AutomaticSize.XY,
			BackgroundTransparency = 1,
			Text = options.Text,
			Font = Enum.Font.Gotham,
			TextSize = 12,
			TextWrapped = true,
			TextColor3 = Computed(function()
				return options.Title and theme:get().TextMuted or theme:get().Text
			end),
			TextXAlignment = Enum.TextXAlignment.Left,
			LayoutOrder = 1,
			[Children] = {
				New("UISizeConstraint")({ MaxSize = Vector2.new(maxWidth, math.huge) }),
			},
		}),
	}

	if options.Shortcut then
		table.insert(textRow, New("TextLabel")({
			AutomaticSize = Enum.AutomaticSize.XY,
			BackgroundColor3 = Computed(function()
				return theme:get().SurfaceHigh
			end),
			Text = options.Shortcut,
			Font = Enum.Font.RobotoMono,
			TextSize = 10,
			TextColor3 = Computed(function()
				return theme:get().TextMuted
			end),
			LayoutOrder = 2,
			[Children] = {
				New("UICorner")({ CornerRadius = UDim.new(0, 4) }),
				New("UIPadding")({
					PaddingLeft = UDim.new(0, 5),
					PaddingRight = UDim.new(0, 5),
					PaddingTop = UDim.new(0, 2),
					PaddingBottom = UDim.new(0, 2),
				}),
			},
		}))
	end

	table.insert(rows, New("Frame")({
		AutomaticSize = Enum.AutomaticSize.XY,
		BackgroundTransparency = 1,
		[Children] = textRow,
	}))

	-- Position below the anchor, centered; flip above if near bottom
	local camera = workspace.CurrentCamera
	local screenH = camera and camera.ViewportSize.Y or 1080
	local below = anchorPos.Y + anchorSize.Y + 60 < screenH
	local yOffset = below and (anchorPos.Y + anchorSize.Y + 8) or (anchorPos.Y - 8)

	local tip = New("Frame")({
		Name = "AetherTooltip",
		AutomaticSize = Enum.AutomaticSize.XY,
		AnchorPoint = Vector2.new(0.5, below and 0 or 1),
		Position = Spring(Computed(function()
			local lift = Fusion.peek(visible) and 0 or (below and -4 or 4)
			return UDim2.fromOffset(anchorPos.X + anchorSize.X / 2, yOffset + lift)
		end), 40, 1),
		BackgroundColor3 = Computed(function()
			return theme:get().SurfaceHigh
		end),
		BackgroundTransparency = Spring(Computed(function()
			return Fusion.peek(visible) and 0 or 1
		end), 40, 1),
		ZIndex = 301,
		Parent = layer,
		[Children] = {
			New("UICorner")({ CornerRadius = Computed(function()
				return UDim.new(0, theme:get().RadiusSm)
			end) }),
			New("UIStroke")({
				Color = Computed(function()
					return theme:get().Border
				end),
				Thickness = 1,
			}),
			New("UIPadding")({
				PaddingLeft = UDim.new(0, 10),
				PaddingRight = UDim.new(0, 10),
				PaddingTop = UDim.new(0, 7),
				PaddingBottom = UDim.new(0, 7),
			}),
			New("Frame")({
				AutomaticSize = Enum.AutomaticSize.XY,
				BackgroundTransparency = 1,
				[Children] = rows,
			}),
		},
	}) :: Frame

	task.defer(function()
		visible:set(true)
	end)
	return tip
end

--- Attaches a tooltip to a GuiObject. Returns a detach function.
function Tooltip.attach(target: GuiObject, options: TooltipOptions): () -> ()
	local hoverToken = 0
	local conns: { RBXScriptConnection } = {}

	table.insert(conns, target.MouseEnter:Connect(function()
		hoverToken += 1
		local token = hoverToken
		task.delay(options.Delay or 0.45, function()
			if token ~= hoverToken then
				return
			end
			-- still hovered?
			local mouse = UserInputService:GetMouseLocation()
			local pos = target.AbsolutePosition
			local size = target.AbsoluteSize
			local inset = game:GetService("GuiService"):GetGuiInset()
			local mx, my = mouse.X, mouse.Y - inset.Y
			if mx >= pos.X and mx <= pos.X + size.X and my >= pos.Y and my <= pos.Y + size.Y then
				destroyActive()
				activeTip = createTip(options, pos, size)
			end
		end)
	end))

	table.insert(conns, target.MouseLeave:Connect(function()
		hoverToken += 1
		destroyActive()
	end))

	table.insert(conns, target.Destroying:Connect(function()
		hoverToken += 1
		destroyActive()
	end))

	return function()
		hoverToken += 1
		destroyActive()
		for _, conn in ipairs(conns) do
			conn:Disconnect()
		end
	end
end

-- PascalCase alias for public API consistency.
Tooltip.Attach = Tooltip.attach

return Tooltip

end)

__register("Components.TreeView", function(require)
--!strict
--[[
	AetherUI • Components/TreeView

	Hierarchical tree with expand/collapse animation, icons and selection.

	props:
		Nodes: { TreeNode }         TreeNode = { Id: string, Label: string, Icon: string?, Children: { TreeNode }? }
		OnSelect: ((node: TreeNode) -> ())?
		DefaultExpanded: { string }?      (list of node ids expanded initially)
		Size: UDim2?    LayoutOrder: number?    Parent: Instance?
]]

local Fusion = require("Core.Fusion")
local Theme = require("Core.Theme")
local Primitives = require("Components.Primitives")

local New = Fusion.New
local Children = Fusion.Children
local Computed = Fusion.Computed
local Value = Fusion.Value
local OnEvent = Fusion.OnEvent
local Tween = Fusion.Tween

local ROW_HEIGHT = 30
local INDENT = 18

return function(props: { [string]: any }): Frame
	local selected = Value(nil :: string?)
	local expandedSet: { [string]: any } = {}

	local defaultExpanded: { [string]: boolean } = {}
	for _, id in (props.DefaultExpanded or {}) :: { string } do
		defaultExpanded[id] = true
	end

	local function isExpanded(id: string): any
		if expandedSet[id] == nil then
			expandedSet[id] = Value(defaultExpanded[id] == true)
		end
		return expandedSet[id]
	end

	local function buildNode(node: { [string]: any }, depth: number): Instance
		local hasChildren = node.Children ~= nil and #node.Children > 0
		local expanded = isExpanded(node.Id)
		local hovering = Value(false)

		local rowChildren: { any } = {
			Primitives.Padding({ Left = 8 + depth * INDENT, Right = 8 }),
			Primitives.List({ Direction = "Horizontal", Padding = 6, VerticalAlignment = Enum.VerticalAlignment.Center }),
			Primitives.Corner("Sm"),
		}

		-- Chevron (only for parents)
		table.insert(rowChildren, Primitives.Icon({
			Name = "chevron-right",
			Size = 12,
			Color = Computed(function()
				return Theme.Colors.TextMuted:get()
			end),
			Transparency = if hasChildren then 0 else 1,
			Rotation = Tween(
				Computed(function()
					return if expanded:get() then 90 else 0
				end),
				TweenInfo.new(0.15, Enum.EasingStyle.Quad, Enum.EasingDirection.Out)
			),
			LayoutOrder = 1,
		}))

		if node.Icon then
			table.insert(rowChildren, Primitives.Icon({
				Name = node.Icon,
				Size = 14,
				Color = Computed(function()
					return if selected:get() == node.Id
						then Theme.Colors.Primary:get()
						else Theme.Colors.TextMuted:get()
				end),
				LayoutOrder = 2,
			}))
		end

		table.insert(rowChildren, Primitives.Text({
			Text = node.Label,
			Size = 13,
			Color = Computed(function()
				return if selected:get() == node.Id
					then Theme.Colors.Text:get()
					else Theme.Colors.TextMuted:get()
			end),
			LayoutOrder = 3,
		}))

		local row = New("TextButton")({
			Name = "Row",
			Size = UDim2.new(1, 0, 0, ROW_HEIGHT),
			BackgroundColor3 = Computed(function()
				return if selected:get() == node.Id
					then Theme.Colors.Surface:get():Lerp(Theme.Colors.Primary:get(), 0.12)
					else Theme.Colors.SurfaceHover:get()
			end),
			BackgroundTransparency = Computed(function()
				if selected:get() == node.Id then
					return 0
				end
				return if hovering:get() then 0.5 else 1
			end),
			Text = "",
			AutoButtonColor = false,
			LayoutOrder = 1,
			[OnEvent("MouseEnter")] = function()
				hovering:set(true)
			end,
			[OnEvent("MouseLeave")] = function()
				hovering:set(false)
			end,
			[OnEvent("Activated")] = function()
				if hasChildren then
					expanded:set(not expanded:get())
				end
				selected:set(node.Id)
				if props.OnSelect then
					props.OnSelect(node)
				end
			end,
			[Children] = rowChildren,
		})

		if not hasChildren then
			return New("Frame")({
				Name = "Node_" .. node.Id,
				AutomaticSize = Enum.AutomaticSize.Y,
				Size = UDim2.new(1, 0, 0, 0),
				BackgroundTransparency = 1,
				[Children] = { Primitives.List({ Padding = 1 }), row },
			})
		end

		-- Children container: clipped, animated open/close.
		local childItems: { any } = { Primitives.List({ Padding = 1 }) }
		for order, child in node.Children :: { { [string]: any } } do
			local built = buildNode(child, depth + 1)
			;(built :: any).LayoutOrder = order
			table.insert(childItems, built)
		end

		local contentHeight = Value(0)

		local childContent = New("Frame")({
			Name = "ChildContent",
			AutomaticSize = Enum.AutomaticSize.Y,
			Size = UDim2.new(1, 0, 0, 0),
			BackgroundTransparency = 1,
			[Children] = childItems,
		})

		-- Track real content height reactively so the holder animates to the
		-- correct size even when nested nodes expand/collapse.
		childContent:GetPropertyChangedSignal("AbsoluteSize"):Connect(function()
			contentHeight:set((childContent :: Frame).AbsoluteSize.Y)
		end)

		local childrenHolder = New("Frame")({
			Name = "Children",
			Size = Tween(
				Computed(function()
					return if expanded:get()
						then UDim2.new(1, 0, 0, contentHeight:get())
						else UDim2.new(1, 0, 0, 0)
				end),
				TweenInfo.new(0.18, Enum.EasingStyle.Quad, Enum.EasingDirection.Out)
			),
			BackgroundTransparency = 1,
			ClipsDescendants = true,
			LayoutOrder = 2,
			[Children] = { childContent },
		})

		return New("Frame")({
			Name = "Node_" .. node.Id,
			AutomaticSize = Enum.AutomaticSize.Y,
			Size = UDim2.new(1, 0, 0, 0),
			BackgroundTransparency = 1,
			[Children] = {
				Primitives.List({ Padding = 1 }),
				row,
				childrenHolder,
			},
		})
	end

	local items: { any } = { Primitives.List({ Padding = 1 }) }
	for order, node in (props.Nodes or {}) :: { { [string]: any } } do
		local built = buildNode(node, 0)
		;(built :: any).LayoutOrder = order
		table.insert(items, built)
	end

	return New("Frame")({
		Name = "AetherTreeView",
		AutomaticSize = Enum.AutomaticSize.Y,
		Size = props.Size or UDim2.new(1, 0, 0, 0),
		BackgroundTransparency = 1,
		LayoutOrder = props.LayoutOrder,
		Parent = props.Parent,
		[Children] = items,
	})
end

end)

__register("Components.Window", function(require)
--!strict
--[=[
	AetherUI · Window
	Top-level draggable, resizable app window with title bar, traffic-light
	controls, minimize-to-bubble, and a global toggle keybind.
]=]

local Fusion = require("Core.Fusion")
local Theme = require("Core.Theme")
local Icons = require("Core.Icons")
local Sound = require("Core.Sound")
local Overlay = require("Core.Overlay")
local Keybinds = require("Core.Keybinds")

local New = Fusion.New
local Children = Fusion.Children
local Value = Fusion.Value
local Computed = Fusion.Computed
local OnEvent = Fusion.OnEvent
local Spring = Fusion.Spring

local UserInputService = game:GetService("UserInputService")

type WindowProps = {
	Title: string,
	Subtitle: string?,
	Icon: string?,
	Size: UDim2?,
	MinSize: Vector2?,
	ToggleKey: Enum.KeyCode?,
	Resizable: boolean?,
	OnClose: (() -> ())?,
}

type WindowHandle = {
	Instance: Frame,
	Content: Frame,
	Toggle: () -> (),
	Show: () -> (),
	Hide: () -> (),
	Close: () -> (),
}

local function Window(props: WindowProps): WindowHandle
	local theme = Theme.Current
	local layer = Overlay.getLayer("Windows", 50)

	local visible = Value(false)
	local position = Value(UDim2.fromScale(0.5, 0.5))
	local size = Value(props.Size or UDim2.fromOffset(680, 460))
	local minSize = props.MinSize or Vector2.new(420, 300)

	local windowFrame: Frame
	local contentFrame: Frame

	local function show()
		visible:set(true)
		Sound.play("Open")
	end
	local function hide()
		visible:set(false)
		Sound.play("Close")
	end
	local function toggle()
		if Fusion.peek(visible) then
			hide()
		else
			show()
		end
	end

	-- Traffic light controls -----------------------------------------------
	local function controlDot(color: Color3, icon: string, onClick: () -> (), order: number): Instance
		local hovered = Value(false)
		return New("TextButton")({
			Size = UDim2.fromOffset(14, 14),
			BackgroundColor3 = color,
			Text = "",
			AutoButtonColor = false,
			LayoutOrder = order,
			[OnEvent("Activated")] = onClick,
			[OnEvent("MouseEnter")] = function()
				hovered:set(true)
			end,
			[OnEvent("MouseLeave")] = function()
				hovered:set(false)
			end,
			[Children] = {
				New("UICorner")({ CornerRadius = UDim.new(1, 0) }),
				Icons.render(icon, {
					Size = UDim2.fromOffset(8, 8),
					Position = UDim2.fromScale(0.5, 0.5),
					AnchorPoint = Vector2.new(0.5, 0.5),
					Color = Color3.new(0, 0, 0),
					Transparency = Computed(function()
						return Fusion.peek(hovered) and 0.2 or 1
					end),
				}),
			},
		})
	end

	-- Title bar --------------------------------------------------------------
	local titleBar = New("Frame")({
		Name = "TitleBar",
		Size = UDim2.new(1, 0, 0, 44),
		BackgroundTransparency = 1,
		[Children] = {
			New("UIPadding")({ PaddingLeft = UDim.new(0, 14), PaddingRight = UDim.new(0, 14) }),
			New("UIListLayout")({
				FillDirection = Enum.FillDirection.Horizontal,
				Padding = UDim.new(0, 8),
				VerticalAlignment = Enum.VerticalAlignment.Center,
			}),
			New("Frame")({
				Name = "Controls",
				AutomaticSize = Enum.AutomaticSize.XY,
				BackgroundTransparency = 1,
				LayoutOrder = 1,
				[Children] = {
					New("UIListLayout")({
						FillDirection = Enum.FillDirection.Horizontal,
						Padding = UDim.new(0, 7),
						VerticalAlignment = Enum.VerticalAlignment.Center,
					}),
					controlDot(Color3.fromRGB(255, 95, 87), "x", function()
						hide()
						if props.OnClose then
							props.OnClose()
						end
					end, 1),
					controlDot(Color3.fromRGB(255, 189, 46), "minus", hide, 2),
					controlDot(Color3.fromRGB(40, 201, 64), "maximize-2", function()
						local camera = workspace.CurrentCamera
						if camera then
							local vp = camera.ViewportSize
							size:set(UDim2.fromOffset(math.floor(vp.X * 0.85), math.floor(vp.Y * 0.85)))
							position:set(UDim2.fromScale(0.5, 0.5))
						end
					end, 3),
				},
			}),
			props.Icon and Icons.render(props.Icon, {
				Size = UDim2.fromOffset(16, 16),
				LayoutOrder = 2,
				Color = Computed(function()
					return theme:get().Primary
				end),
			}) or nil,
			New("TextLabel")({
				AutomaticSize = Enum.AutomaticSize.XY,
				BackgroundTransparency = 1,
				Text = props.Title,
				Font = Enum.Font.GothamBold,
				TextSize = 14,
				TextColor3 = Computed(function()
					return theme:get().Text
				end),
				LayoutOrder = 3,
			}),
			props.Subtitle and New("TextLabel")({
				AutomaticSize = Enum.AutomaticSize.XY,
				BackgroundTransparency = 1,
				Text = props.Subtitle,
				Font = Enum.Font.Gotham,
				TextSize = 12,
				TextColor3 = Computed(function()
					return theme:get().TextMuted
				end),
				LayoutOrder = 4,
			}) or nil,
		},
	}) :: Frame

	-- Content ------------------------------------------------------------------
	contentFrame = New("Frame")({
		Name = "Content",
		Position = UDim2.fromOffset(0, 44),
		Size = UDim2.new(1, 0, 1, -44),
		BackgroundTransparency = 1,
		ClipsDescendants = true,
	}) :: Frame

	-- Resize grip ----------------------------------------------------------------
	local resizing = false
	local resizeStart = Vector2.zero
	local startSize = Vector2.zero

	local resizeGrip = props.Resizable ~= false and New("TextButton")({
		Name = "ResizeGrip",
		AnchorPoint = Vector2.new(1, 1),
		Position = UDim2.new(1, -2, 1, -2),
		Size = UDim2.fromOffset(18, 18),
		BackgroundTransparency = 1,
		Text = "",
		ZIndex = 5,
		[Children] = {
			Icons.render("move-diagonal-2", {
				Size = UDim2.fromOffset(12, 12),
				Position = UDim2.fromScale(0.5, 0.5),
				AnchorPoint = Vector2.new(0.5, 0.5),
				Color = Computed(function()
					return theme:get().TextDisabled
				end),
			}),
		},
	}) or nil

	if resizeGrip then
		(resizeGrip :: TextButton).InputBegan:Connect(function(input)
			if input.UserInputType == Enum.UserInputType.MouseButton1 then
				resizing = true
				resizeStart = Vector2.new(input.Position.X, input.Position.Y)
				local current = Fusion.peek(size)
				startSize = Vector2.new(current.X.Offset, current.Y.Offset)
			end
		end)
	end

	-- Window frame -----------------------------------------------------------------
	windowFrame = New("Frame")({
		Name = "AetherWindow",
		AnchorPoint = Vector2.new(0.5, 0.5),
		Position = Spring(Computed(function()
			local base = Fusion.peek(position)
			if not Fusion.peek(visible) then
				return base + UDim2.fromOffset(0, 30)
			end
			return base
		end), 24, 0.85),
		Size = Spring(size, 30, 1),
		BackgroundColor3 = Computed(function()
			return theme:get().Background
		end),
		BackgroundTransparency = Spring(Computed(function()
			return Fusion.peek(visible) and 0 or 1
		end), 24, 1),
		Visible = Computed(function()
			return Fusion.peek(visible)
		end),
		Parent = layer,
		[Children] = {
			New("UICorner")({ CornerRadius = Computed(function()
				return UDim.new(0, theme:get().RadiusLg)
			end) }),
			New("UIStroke")({
				Color = Computed(function()
					return theme:get().Border
				end),
				Thickness = 1,
			}),
			titleBar,
			contentFrame,
			resizeGrip :: any,
		},
	}) :: Frame

	-- Dragging by title bar ------------------------------------------------------
	local dragging = false
	local dragStart = Vector2.zero
	local startPos = UDim2.new()

	titleBar.InputBegan:Connect(function(input)
		if input.UserInputType == Enum.UserInputType.MouseButton1 or input.UserInputType == Enum.UserInputType.Touch then
			dragging = true
			dragStart = Vector2.new(input.Position.X, input.Position.Y)
			startPos = Fusion.peek(position)
		end
	end)

	UserInputService.InputChanged:Connect(function(input)
		if input.UserInputType ~= Enum.UserInputType.MouseMovement and input.UserInputType ~= Enum.UserInputType.Touch then
			return
		end
		local point = Vector2.new(input.Position.X, input.Position.Y)
		if dragging then
			local delta = point - dragStart
			position:set(UDim2.new(
				startPos.X.Scale, startPos.X.Offset + delta.X,
				startPos.Y.Scale, startPos.Y.Offset + delta.Y
			))
		elseif resizing then
			local delta = point - resizeStart
			size:set(UDim2.fromOffset(
				math.max(minSize.X, startSize.X + delta.X),
				math.max(minSize.Y, startSize.Y + delta.Y)
			))
		end
	end)

	UserInputService.InputEnded:Connect(function(input)
		if input.UserInputType == Enum.UserInputType.MouseButton1 or input.UserInputType == Enum.UserInputType.Touch then
			dragging = false
			resizing = false
		end
	end)

	-- Global toggle keybind --------------------------------------------------------
	if props.ToggleKey then
		Keybinds.Register("window-toggle-" .. props.Title, {
			Key = props.ToggleKey,
			Description = "Toggle " .. props.Title,
			Callback = toggle,
		})
	end

	task.defer(show)

	return {
		Instance = windowFrame,
		Root = windowFrame,
		Content = contentFrame,
		Toggle = toggle,
		Show = show,
		Hide = hide,
		Close = function()
			hide()
			task.delay(0.3, function()
				windowFrame:Destroy()
			end)
		end,
	}
end

return Window

end)

__register("Hooks.UseDrag", function(require)
--!strict
--[[
	AetherUI • Hooks/UseDrag
	Makes a GuiObject draggable by a handle. Returns a cleanup function.

		local stopDrag = UseDrag(windowFrame, titleBar)
]]

local UserInputService = game:GetService("UserInputService")

local Maid = require("Core.Maid")

return function(target: GuiObject, handle: GuiObject?): () -> ()
	local maid = Maid.new()
	local dragHandle = handle or target

	local dragging = false
	local dragStart = Vector2.zero
	local startPosition = UDim2.new()

	maid:Add(dragHandle.InputBegan:Connect(function(input)
		if
			input.UserInputType == Enum.UserInputType.MouseButton1
			or input.UserInputType == Enum.UserInputType.Touch
		then
			dragging = true
