__register("Hooks.UseHover", function(require)
--!strict
--[[
	AetherUI • Hooks/UseHover
	Returns a reactive hover state plus enter/leave handlers to wire to OnEvent.

		local hover = UseHover()
		New "TextButton" {
			[OnEvent "MouseEnter"] = hover.Enter,
			[OnEvent "MouseLeave"] = hover.Leave,
			BackgroundColor3 = Tween(Computed(function()
				return if hover.Hovering:get() then ... else ...
			end), Animation.Presets.Fast),
		}
]]

local Fusion = require("Core.Fusion")
local Sound = require("Core.Sound")

type Hover = {
	Hovering: any,
	Enter: () -> (),
	Leave: () -> (),
}

return function(options: { Sound: boolean? }?): Hover
	local hovering = Fusion.Value(false)
	local playSound = if options then options.Sound ~= false else true

	return {
		Hovering = hovering,
		Enter = function()
			hovering:set(true)
			if playSound then
				Sound.Play("Hover")
			end
		end,
		Leave = function()
			hovering:set(false)
		end,
	}
end

end)

__register("Hooks.UsePress", function(require)
--!strict
--[[
	AetherUI • Hooks/UsePress
	Reactive pressed state + press handlers, with optional click sound.
]]

local Fusion = require("Core.Fusion")
local Sound = require("Core.Sound")

type Press = {
	Pressed: any,
	Down: () -> (),
	Up: () -> (),
	Activate: (callback: (() -> ())?) -> (),
}

return function(options: { Sound: boolean? }?): Press
	local pressed = Fusion.Value(false)
	local playSound = if options then options.Sound ~= false else true

	return {
		Pressed = pressed,
		Down = function()
			pressed:set(true)
		end,
		Up = function()
			pressed:set(false)
		end,
		Activate = function(callback)
			if playSound then
				Sound.Play("Click")
			end
			if callback then
				callback()
			end
		end,
	}
end

end)

